INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('198', '과학영농 실천을 위한 토양정보시스템 흙토람', '농사를 짓고자 할 때 토양특성에 맞는 작물을 제시해 주고, 알맞은 비료량을 추천해 주는 누구
나 쉽게 이용할 수 있는 인터넷 시스템', NULL, NULL, '{"classCode": "A010902", "className": "농업환경", "classSubCode": "A01090201", "classSubContents": "농사를 짓고자 할 때 토양특성에 맞는 작물을 제시해 주고, 알맞은 비료량을 추천해 주는 누구\n나 쉽게 이용할 수 있는 인터넷 시스템", "classSubContents2": "&#10061; 40여년간 국책사업으로 수행한 토양조사 결과를 전산화하여 정보시스템 구축\n&#10061; 농경지 토양자원을 효율적으로 이용\n&#10061; 농업인 등 다양한 수요자가 요구하는 각종 토양정보를 신속히 제공", "classSubHtml": "A01090201.html", "classSubIdx": "198", "classSubMaster": "담당자 : 농업연구사 최은영 031-290-0346", "classSubMovieUrl": null, "classSubPdf": "A01090201.pdf", "classSubTitle": "과학영농 실천을 위한 토양정보시스템 흙토람", "classSubUse": "Y", "regDate": "2009-06-12 15:01:19.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('196', '농식품 안전성 신속판정기술 개발', '기존 방법에선 수일 이상 소요되던 식중독균, 잔류농약, 중금속 등 농식품 위해물질 오염 검사
를 수 시간 이내에 신속하게 수행케 하는 기술.', NULL, NULL, '{"classCode": "A010905", "className": "농산물안전성", "classSubCode": "A01090501", "classSubContents": "기존 방법에선 수일 이상 소요되던 식중독균, 잔류농약, 중금속 등 농식품 위해물질 오염 검사\n를 수 시간 이내에 신속하게 수행케 하는 기술.", "classSubContents2": "○ 국민소득 향상과 외식산업 급신장, 온라인 거래, 단체급식의 확산 등으로 \n   신선&#8231;안전&#8231;우수 농산물에 대한 소비자의 요구가 증대하고 있으며, 최근 농산물의 \n   잔류농약, 중금속, 대장균 O-157, 항생제 등 문제발생에 따른 농산물 안전성에 대한 인식이\n   고조되고 있음.\n○ 농산물 안전성은 사고 발생 후 추적검사가 아닌 사전검사를 통한 위생사고 방지와 오염 \n   농산물의 회수에 따른 막대한 비용 절감이 바람직하므로, 소비자에게 유통되기 전에 정확한\n   오염정도와 위험도를 신속하게 모니터링 할 수 있는 현장 판정 기술 개발이 요구됨.\n○ 농산물 안전성 사고가 매년 반복되고 있지만 기존의 농산물 안전성 분석 기술은 3~5일간의 \n   장시간이 소요되고 고가의 분석기 사용 등 분석비용이 많이 소요됨.\n○ 수입이 급증하고 있는 외국 농산물과의 차별화와 국내 소비자의 건강 보호를 위해서는 \n   나노 및 바이오센서 기술, 전기화학분석기술 등 첨단 센서기술을 이용한 보다 신속하고 현장\n   중심적인 안전성 판정기술 개발이 시급함.", "classSubHtml": "A01090501.html", "classSubIdx": "196", "classSubMaster": "담당자 : 농업연구관  김기영 031-290-1899", "classSubMovieUrl": null, "classSubPdf": "A01090501.pdf", "classSubTitle": "농식품 안전성 신속판정기술 개발", "classSubUse": "Y", "regDate": "2009-06-12 14:56:55.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('144', '수경재배기술을 이용한 청정인삼 및 인삼 엽 생산방법', '“청정인삼 고속생산기술”은 수경재배기술로 재배함으로서 무농약 청정재배와 연중생산이 가능
하고 2년근 크기(8~10g)의 수삼을 4개월 만에 고속생산 할 수 있는 신기술 인삼재배 방법이다.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090901", "classSubContents": "“청정인삼 고속생산기술”은 수경재배기술로 재배함으로서 무농약 청정재배와 연중생산이 가능\n하고 2년근 크기(8~10g)의 수삼을 4개월 만에 고속생산 할 수 있는 신기술 인삼재배 방법이다.", "classSubContents2": "신품종 보급 및 기계화율의 저조로 국제경쟁력 취약 \n연작장해가 심하고 농약 과다살포로 소비자의 불신 및 수출 제약\n소비 확대를 위한 신수요 창출로 인삼산업 발전 유도\n - 약용 및 보신용에서 웰빙채소, 간식용으로의 소비영역 확대\n웰빙에 대한 관심이 높아지면서 안전한 기능성 식품 수요증가", "classSubHtml": "A01090901.htm", "classSubIdx": "144", "classSubMaster": "담당자 : (농업연구사) (김용범) (043-871-5544, 010-2621-8403)", "classSubMovieUrl": null, "classSubPdf": "A01090901.pdf", "classSubTitle": "수경재배기술을 이용한 청정인삼 및 인삼 엽 생산방법", "classSubUse": "Y", "regDate": "2009-03-19 19:05:24.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('141', '한우&#8228;수입우 판별 유전자 분석기법 - 이동형 진단장치', '젖소 및 수입 쇠고기 등이 한우고기로 둔갑되어 부정유통, 판매되는 것을 방지하기 위해 DNA 마
커를 활용하여 한우와 비한우를 판별하는 과학적인 DNA 검사기법을 농촌진흥청이 중심이 되어 
2007년 초에 개발하였으며 이 방법의 신속화 및 현장 검사가 가능하도록 이동형 진단장치를 개발
함.', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090801", "classSubContents": "젖소 및 수입 쇠고기 등이 한우고기로 둔갑되어 부정유통, 판매되는 것을 방지하기 위해 DNA 마\n커를 활용하여 한우와 비한우를 판별하는 과학적인 DNA 검사기법을 농촌진흥청이 중심이 되어 \n2007년 초에 개발하였으며 이 방법의 신속화 및 현장 검사가 가능하도록 이동형 진단장치를 개발\n함.", "classSubContents2": "○ 한우고기가 아닌 비한우 쇠고기의 부정유통 및 둔갑판매를 방지하기 위해 누구나 인정할 수 \n있는 과학적인 분석 방법의 필요성을 일반 주부 등 소비자와 한우고기를 생산하는 농가 등에서 \n그동안 제기해 왔으며, \n    ○ 대형마트, 식육거래업체, 정육점, 학교급식, 음식점 등 쇠고기가 판매 및 유통되고 있는 \n현장에서 신속하면서 간편하게 분석가능한 방법의 필요성을 지속적으로 요구하여 왔음.\n    ○ 이에 수년간의 연구노력으로 한우와 한우이외의 소품종간 구분이 가능한 다수의 DNA마커\n들을 발굴하여 부정유통을 방지하여 건전한 상거래 및 한우생산 농가의 보호를 위하고 더 나아\n가 국가 경제 건전성을 도모하기 위하여 유전자 감식기법을 개발하였음.", "classSubHtml": "A01090801.html", "classSubIdx": "141", "classSubMaster": "담당자 : 국립축산과학원 농업연구관 윤두학 (031-290-1603)", "classSubMovieUrl": null, "classSubPdf": "A01090801.pdf", "classSubTitle": "한우&#8228;수입우 판별 유전자 분석기법 - 이동형 진단장치", "classSubUse": "Y", "regDate": "2009-03-19 18:57:48.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('140', '학습&#8228;인지력 향상 “피브로인 BF-7” 개발', '대표적인 친환경 작목의 하나인, 천연 잠상산물 피브로인으로부터 기억, 학습력 및 집중력 증진
에 효과가 있는 물질을 추출하여 산업화 하였다(Brain Factor, BF-7이라 명명).  “피브로인 BF-
7”은 천연잠상산물을 특정 효소로 가수분해하여 특수가공법으로 분리 후 재가공한 물질이며, 서
울대학교와 중앙대학교 의대에서 임상실험을 통하여 효과를 입증하였고 식약청에서 기능성 원료 
효능 효과에 대한 ‘개별인정’을 받았다.  아울러 본 연구의 성과는 기억&#8228;학습력 및 집중력 증
진 효과가 인정된 연구성과로서 국가적 필요성이 인정된 100대 우수성과(2003~2005)에 선정된 과
제이기도 하다.', NULL, NULL, '{"classCode": "A010907", "className": "잠사곤충", "classSubCode": "A01090701", "classSubContents": "대표적인 친환경 작목의 하나인, 천연 잠상산물 피브로인으로부터 기억, 학습력 및 집중력 증진\n에 효과가 있는 물질을 추출하여 산업화 하였다(Brain Factor, BF-7이라 명명).  “피브로인 BF-\n7”은 천연잠상산물을 특정 효소로 가수분해하여 특수가공법으로 분리 후 재가공한 물질이며, 서\n울대학교와 중앙대학교 의대에서 임상실험을 통하여 효과를 입증하였고 식약청에서 기능성 원료 \n효능 효과에 대한 ‘개별인정’을 받았다.  아울러 본 연구의 성과는 기억&#8228;학습력 및 집중력 증\n진 효과가 인정된 연구성과로서 국가적 필요성이 인정된 100대 우수성과(2003~2005)에 선정된 과\n제이기도 하다.", "classSubContents2": "기술개발의 목적 \n천연 잠상산물로부터 학습&#8228;기억력 향상 등 두뇌개발에 도움을 주는 안전한 천연소재 개발 및 산\n업화\n필요성 \n개인의 지적능력 향상이 국가미래를 좌우하는 가장 중요한 사안이고, 두뇌 관련 퇴행성 질환(치\n매, 기억력 감퇴 등)등에 대한 예방물질 개발이 필요함\n외국의 연구개발 성과에 의존되는 식&#8228;의약품 개발에 순수 국내기술에 의한 연구개발 성과 구축\n이 절실히 필요함\n농업생물자원을 이용한 기능성 원료 및 효능효과를 가지는 소재개발로 “고부가가치 농업 생명 \n신소재 개발”의 발판이 필요함\n농업생물자원의 식약청 정식 허가는 신뢰성 제고로 이어질 수 있음", "classSubHtml": "A01090701.html", "classSubIdx": "140", "classSubMaster": "담당자 : 농업연구관 여주홍 (031-290-8507)", "classSubMovieUrl": null, "classSubPdf": "A01090701.pdf", "classSubTitle": "학습&#8228;인지력 향상 “피브로인 BF-7” 개발", "classSubUse": "Y", "regDate": "2009-03-19 18:54:12.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('121', '혈전용해제 생산 식물체 개발', '심근경색&#8231;뇌졸증&#8231;폐색전증 치료용 의약품인 인체 혈관 내피세포 유래 혈전용해제 (t-PA)를 생
산하는 참외 모상근 및 알팔파 식물시스템 개발 기술을 확립하였고 이러한 기술은 다른 의료용 
단백질을 비롯한 펩타이드를 생산하는 기술에 적용가능함. 현재 보관과 수송이 용이한 벼 종자
를 이용한 혈전용해제 개발 연구도 수행하여, 현재 자체 기술을 보유함.', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090301", "classSubContents": "심근경색&#8231;뇌졸증&#8231;폐색전증 치료용 의약품인 인체 혈관 내피세포 유래 혈전용해제 (t-PA)를 생\n산하는 참외 모상근 및 알팔파 식물시스템 개발 기술을 확립하였고 이러한 기술은 다른 의료용 \n단백질을 비롯한 펩타이드를 생산하는 기술에 적용가능함. 현재 보관과 수송이 용이한 벼 종자\n를 이용한 혈전용해제 개발 연구도 수행하여, 현재 자체 기술을 보유함.", "classSubContents2": "○ 새로운 농업소득 창출용 고부가성 의료용, 산업용 물질 소재 개발을 최종 연구 목표로 함.\n- 고부가성 의료용, 산업용 물질을 생산할 수 있는 유전자 및 작물 개발을 하고자함.\n- 식물시스템을 이용하여 의약품, 산업적 이용 물질를 생산하는 식물공장 개념의 기술개발 연구\n가 필요함.\n&#9642; 농업생명공학 연구 성과의 고부가 산업화 촉진. \n&#9642; 분자농업에 의한 새로운 농업생산 및 소득 창출. \n○ 세계적으로 식물 시스템을 이용한 인간 및 동물의약품, 사료첨가물, 식품소재, 화장품소재, \n산업용소재 개발 등 다방면에 응용이 가능한 식물공장 개념의 연구가 활발히 진행 중.\n&#9642; Plant factory기술은 식량생산기능 농업을 산업화소재 생산 기능으로 paradigm을 전환할 수 있\n는 미래형 기술로 평가.\n&#9642; 식물시스템을 이용하여 생산된 물질은 인수공통전염병 (예: 바이러스 등) 잠재적 위험성이 없\n고 생산단가 경쟁력 면에서 실용화 가능성이 높아 미국 및 캐나다는 국가적 차원에서 정책적 지\n원 중.\n○ 식물시스템을 이용한 재조합 단백질 생산기술개발 장점 및 필요성\n&#9642; 저렴한 생산비와 재조합단백질의 안전성\n식물은 지구상에서 가장 풍부한 단백질 생산원이며 단백질 생산비도 가장 낮다. 식물을 이용하\n여 생산하는 기술은 동물과 미생물을 이용하는 경우와 달리 인간에게 감염될 수도 있는 바이러\n스 등 질병과 독성 물질이 없어 매우 안전하며, 별도의 설비 투자 없이 작물재배를 통하여 생산\n이 가능함.\n&#9642; 생리활성 보유 재조합단백질의 생산\n   식물세포는 prokaryotic protein은 물론 eukaryotic protein을 전사 및 번역하여 생리활성을 \n갖도록 인산화 및 당쇄결합 및 3차 또는 4차 구조로 수식(modification)할 수 있으므로 거대분자\n인 재조합단백질의 대량생산에 적합한 담체 기능이 가능함.\n&#9642; 생산량의 조절 및 저장성\n   재조합단백질 대량생산 및 생산량 조절을 위해서는 유전자전환 식물의 재배면적을 조절함으로\n서 가능하고, 만약 생산량의 조절 또는 저장을 위해서는 저온 또는 동결설비 없이도 저렴하게 비\n축할 수 있는 장점이 있다. 식물은 영양조직(vegetative)과 종자(seed)를 동시에 가지고 있고, \n특히 건조종자는 고 함량의 재조합단백질 생산수단이면서 생산과 가공(분리정제) 과정에 단백질\n의 활성유지가 가능한 장기저장을 위해 매우 유익한 수단이 될 수 있음.", "classSubHtml": "A01090301.htm", "classSubIdx": "121", "classSubMaster": "담당자 : 농업연구사 한범수 (031-299-1693)", "classSubMovieUrl": null, "classSubPdf": "A01090301.pdf", "classSubTitle": "혈전용해제 생산 식물체 개발", "classSubUse": "Y", "regDate": "2009-03-19 17:46:40.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('114', '축열식 수평형 지열히트펌프 시스템', '땅속 3m 깊이에 수평으로 난방용 PE파이프를 설치하고 물을 순환시켜 7～15℃(3m 깊이의 땅속 온
도)의 지열을 흡수하고, 흡수한 지열을 히트펌프로 온도를 높혀 40～45℃의 온수 또는 온풍을 만
들어 온실에 공급하여 난방에 이용하는 장치', NULL, NULL, '{"classCode": "A010901", "className": "농기계", "classSubCode": "A01090101", "classSubContents": "땅속 3m 깊이에 수평으로 난방용 PE파이프를 설치하고 물을 순환시켜 7～15℃(3m 깊이의 땅속 온\n도)의 지열을 흡수하고, 흡수한 지열을 히트펌프로 온도를 높혀 40～45℃의 온수 또는 온풍을 만\n들어 온실에 공급하여 난방에 이용하는 장치", "classSubContents2": "고유가 대비 시설원예 등 농업시설의 난방비 절감 기술 확립\n신재생 에너지의 농업이용 기술 확립으로 녹색 농업 기반 구축", "classSubHtml": "A01090101.html", "classSubIdx": "114", "classSubMaster": "담당자 : 농업연구관 유 영 선 (031-290-1811)", "classSubMovieUrl": null, "classSubPdf": "A01090101.pdf", "classSubTitle": "축열식 수평형 지열히트펌프 시스템", "classSubUse": "Y", "regDate": "2009-03-19 16:51:54.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('72', '감자걀쭉바이로이드 진단기술 개발', '감자걀쭉병을 신속하고 정밀하게 진단하고자 역전사중합연쇄반응(RT-PCR)을 이용하여 판별할 수 
있는 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090601", "classSubContents": "감자걀쭉병을 신속하고 정밀하게 진단하고자 역전사중합연쇄반응(RT-PCR)을 이용하여 판별할 수 \n있는 기술임", "classSubContents2": "감자걀쭉병(PSTVd)은 식물방역법의 ‘금지병해충’으로 수입 허용지역을 제한하는 병임  \n감자걀쭉병에 감염된 감자는 모양이 기형으로 되거나 갈라지는 등 상품성이 전혀 없고 수량도 \n40% 정도 감수됨\n감자걀쭉병은 핵산(ssRNA)으로만 되어 있어 혈청진단법은 사용할 수 없어 유전자로 진단하는 방\n법을 이용하여야 함\n1977년 발생되어 씨감자를 전량 폐기하여 박멸한 후 발생보고가 없었으나, 중국 등 주변국가에 \n이병이 발생하고 있으며 민간육종가의 증가로 외국의 유전자 도입이 많아져 병 발생가능성이 매\n우 높아졌음\n이 병에 대한 진단방법이 마련되어 있지 않아 진단기술 개발이 필요하였음", "classSubHtml": "A01090601.html", "classSubIdx": "72", "classSubMaster": "담당자 : 농업연구사 이영규 033-330-1941", "classSubMovieUrl": null, "classSubPdf": "A01090601.pdf", "classSubTitle": "감자걀쭉바이로이드 진단기술 개발", "classSubUse": "Y", "regDate": "2009-03-18 09:09:29.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('65', '감귤 고부가가치 창출 기능성 제품 ‘감비슬림’ 개발', '감귤에서 기능성 성분을 효율적으로 추출하는 방법을 개발 한 후 기능성 성분이 첨가된 감귤음료
제조 방법을 개발하였고, 개발된 감귤 추출액으로 동물시험 및 사람을 대상으로 입증시험을 실시
하였다.
동물세포시험 결과 감귤 추출액을 투여한 동물(랫드)의 간세포의 지방간 손상 억제는 물론 치료
효과도 있었고, 동물(랫드)의 복부지방 및 체중도 감소되는 현상이 나타났다. 
또한 고도비만 중학생 2, 3학년 30명을 대상으로 감귤기능성 음료 100ml(감귤 과육+과피 2개 분
량)기준으로 제조하여 2달간 매일 음용시키고 운동도 병행한 결과, 감귤음료 섭취시 체지방률 
3%, 총콜레스테롤 10%, 체중량 지수 1% 정도의 감소 효과가 있었다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090401", "classSubContents": "감귤에서 기능성 성분을 효율적으로 추출하는 방법을 개발 한 후 기능성 성분이 첨가된 감귤음료\n제조 방법을 개발하였고, 개발된 감귤 추출액으로 동물시험 및 사람을 대상으로 입증시험을 실시\n하였다.\n동물세포시험 결과 감귤 추출액을 투여한 동물(랫드)의 간세포의 지방간 손상 억제는 물론 치료\n효과도 있었고, 동물(랫드)의 복부지방 및 체중도 감소되는 현상이 나타났다. \n또한 고도비만 중학생 2, 3학년 30명을 대상으로 감귤기능성 음료 100ml(감귤 과육+과피 2개 분\n량)기준으로 제조하여 2달간 매일 음용시키고 운동도 병행한 결과, 감귤음료 섭취시 체지방률 \n3%, 총콜레스테롤 10%, 체중량 지수 1% 정도의 감소 효과가 있었다.", "classSubContents2": "감귤 총생산량의 15%인 가공용 감귤의 수매가 향상으로 농가의 소득 증대\n감귤가공업체에 활력을 부여 및 감귤소비 촉진에 기여", "classSubHtml": "A01090401.htm", "classSubIdx": "65", "classSubMaster": "담당자 :농업연구관  최영훈  (전화)064-730-3107", "classSubMovieUrl": null, "classSubPdf": "A01090401.pdf", "classSubTitle": "감귤 고부가가치 창출 기능성 제품 ‘감비슬림’ 개발", "classSubUse": "Y", "regDate": "2009-03-17 18:41:58.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('212', '화학비료 대체 친환경유기농자재', '○ 유기합성 농약과 화학비료의 사용이 금지되고 있는 유기농업에서 효과가 우수한 농가주변의 
각종 유기물, 농축림수산 부산물, 미생물 및 천연자원  등을 이용하여 화학비료 대체 작물생육촉
진 친환경유기농자재 물질이용 및 활용기술을 개발', NULL, NULL, '{"classCode": "A010905", "className": "농산물안전성", "classSubCode": "A01090502", "classSubContents": "○ 유기합성 농약과 화학비료의 사용이 금지되고 있는 유기농업에서 효과가 우수한 농가주변의 \n각종 유기물, 농축림수산 부산물, 미생물 및 천연자원  등을 이용하여 화학비료 대체 작물생육촉\n진 친환경유기농자재 물질이용 및 활용기술을 개발", "classSubContents2": "○ 친환경농산물 생산시 각종 유기물, 친환경 유기퇴비, 분변토, 해양부산물 등을 이용한 \n   유기농자재를 보조적, 부수적으로 사용하여 환경부하를 최소화하면서 토양 비옥도를 \n   유지하여 작물을 튼튼하고 잘 자라게 하는 것을 기본 목적으로 화학비료 대체 \n   친환경유기농자재의 이용 기술을 개발\n○ 지렁이 분변토는 비료적 가치와 생물학적 활성이 우수하여 쿠바 등 유기농업 선도국에서 \n   지력유지를 위한 주요 자재로 사용되고 있으며, 미국과 캐나다에서는 분변토를 토양개량 \n   유기농자재로 동남아에 수출하고 있음\n   - 미  국 분변토 : 질소 0.5∼2%, 인산 0.6∼0.68%, 칼리 0.1∼0.68%\n   - 캐나다 분변토 : 질소 0.61%, 인산 0.08%, 칼리 0.16%\n○ 국내에서 발생되는 굴 패각의 발생량은 연간 23∼25만톤에 달하며, 생선 내장 등 버려지는\n   수산부산물이 약 47%에 달하고 있으나 부산물의 이용은 5%수준으로 해조류 등 풍부한 \n   해양자원을 이용한 자가제조 유기농자재 활용기술이 필요\n   - Codex 유기식품규격에서 허용되고 있는 해조류 등 해양부산물에 함유된 Auxin, Cytokinin,\n     아미노산 및 비료성분으로 인한 작물생육촉진 효과가 인정되어 독일, 캐나다, 호주 등 \n     유기농업 선도국가에서는 작물생육촉진 유기농자재로 개발&#8231;활용되고 있음", "classSubHtml": "A01090502.html", "classSubIdx": "212", "classSubMaster": "담당자 : 농업연구사  이상범 (031-290-0557)", "classSubMovieUrl": null, "classSubPdf": "A01090502.pdf", "classSubTitle": "화학비료 대체 친환경유기농자재", "classSubUse": "Y", "regDate": "2009-06-12 15:43:15.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('197', '새로운 가축항생제 봉독', '살아있는 벌로부터 벌이 죽지 않고 다량의 봉독을 채집 할 수 있는 국산봉독채집장치의 개발과 
채집 봉독의 가축적용 항생제 대체 기술', NULL, NULL, '{"classCode": "A010907", "className": "잠사곤충", "classSubCode": "A01090702", "classSubContents": "살아있는 벌로부터 벌이 죽지 않고 다량의 봉독을 채집 할 수 있는 국산봉독채집장치의 개발과 \n채집 봉독의 가축적용 항생제 대체 기술", "classSubContents2": "○ 양봉농가의 부가소득원 창출 필요성 대두\n  - 국내 양봉농가는 4만 가구, 4천억원 시장규모로서 농가 소득에 벌꿀 이외에는 크게 \n    기여하지 못하고 있음\n○ 양축농가의 가축에 대한 기존 항생제 대체 천연항생물질 개발 필요\n  - 2012년 이후 사료첨가제에 사용되는 기존항생제 전멸 금지에 따른 천연항생제 개발 시급\n  - 기존 항생제에 대한 내성 증가", "classSubHtml": "A01090702.html", "classSubIdx": "197", "classSubMaster": "담당자 : 농업연구사  한상미 (031-290-8510)", "classSubMovieUrl": null, "classSubPdf": "A01090702.pdf", "classSubTitle": "새로운 가축항생제 봉독", "classSubUse": "Y", "regDate": "2009-06-12 15:00:05.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('147', '감자 바이러스 동시진단 기술 개발', '역전사중합연쇄반응(RT-PCR)을 이용하여 바이러스 진단용 프라이머를 개발하여 감자에서 가장 많
이 발생하는 모자이크병(PVY, PVX)과 잎말림바이러스병(PLRV), 감자S바이러스(PVS) 둥 4종의 바
이러스병을 동시에 진단할 수 있는 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090602", "classSubContents": "역전사중합연쇄반응(RT-PCR)을 이용하여 바이러스 진단용 프라이머를 개발하여 감자에서 가장 많\n이 발생하는 모자이크병(PVY, PVX)과 잎말림바이러스병(PLRV), 감자S바이러스(PVS) 둥 4종의 바\n이러스병을 동시에 진단할 수 있는 기술임", "classSubContents2": "감자의 수량감소에 많은 영향을 미치는 바이러스병은 약제에 의한 방제가 불가능하여 사전에 진\n단제거가 가장 효과적임 \n지금까지 바이러스 진단은 혈청을 이용하는 방법과 유전자를 이용하는 방법이 널리 사용되고 있\n으나 각각의 바이러스에 대해서 진단하고 있음\n감자의 주요 바이러스를 동시에 진단하여 시간과 비용을 절약할 수 있는 기술개발이 필요", "classSubHtml": "A01090602.html", "classSubIdx": "147", "classSubMaster": "담당자 : 농업연구사 이영규 ☎ 033-330-1941", "classSubMovieUrl": null, "classSubPdf": "A01090602.pdf", "classSubTitle": "감자 바이러스 동시진단 기술 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:07:22.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('145', '식물의 고온장해 경감제 이소프렌 화합물', '이소프렌(Isoprene) 화합물은 고온 환경조건에서도 식물이 정상적으로 생육할 수 있도록 유도하
여 고온장해로부터 농가의 위험부담과 경제적 손실을 줄일 수 있다.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090902", "classSubContents": "이소프렌(Isoprene) 화합물은 고온 환경조건에서도 식물이 정상적으로 생육할 수 있도록 유도하\n여 고온장해로부터 농가의 위험부담과 경제적 손실을 줄일 수 있다.", "classSubContents2": "고온 환경에서는 광합성기구에 해당하는 엽록체의 발달장애, 엽록소-단백질 복합체 생성 장애를 \n일으켜 식물의 생육에 문제 발생\n따라서 최근에는 고온, 건조한 환경에서 생육하는 식물을 생리적으로 연구하여 식물의 고온장해 \n경감하려는 연구가 진행되고 있음\n그러나 지구 온난화 현상에 따른 식물재배 농가의 피해면적이 해마다 증가하고 있음에 불구하고 \n구체적인 고온장해 경감방안이 제시되고 있지 않다.", "classSubHtml": "A01090902.html", "classSubIdx": "145", "classSubMaster": "담당자 : 농업연구사 현동윤 043-871-5505", "classSubMovieUrl": null, "classSubPdf": "A01090902.pdf", "classSubTitle": "식물의 고온장해 경감제 이소프렌 화합물", "classSubUse": "Y", "regDate": "2009-03-19 19:06:12.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('142', '형질전환 동물이용 바이오신약 생산', '생명공학기술을 이용하여 인간 질병을 치료하기 위한 단백질을 유즙과 난백으로 분비하는 형질전
환 동물을 개발하여 국가의 과학적 위상과 국민의 경제적 부담을 줄여주는 기술', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090802", "classSubContents": "생명공학기술을 이용하여 인간 질병을 치료하기 위한 단백질을 유즙과 난백으로 분비하는 형질전\n환 동물을 개발하여 국가의 과학적 위상과 국민의 경제적 부담을 줄여주는 기술", "classSubContents2": "특정한 단백질을 만들어 내지 못하여 고통 받는 사람이 많음\n- 혈우병 환자, 항암치료중인 사람, 빈혈환자 등\n이용되고 있는 단백질 치료제는 장기적으로 투여 받아야 함에도 불구하고 세포 배양을 이용하여 \n생산하는 단백질이 생산비용이 높아 국민의 의료부담이 가중되고 있음\n형질전환 동물을 이용하여 단백질을 생산할 경우 단백질의 구조가 사람의 것과 유사하여 효능이 \n높고 생산비를 낮출 수 있어 보다 많은 환자가 치료받을 수 있음\n고가의 치료용 단백질을 생산하는 돼지를 수준 높은 시설에서 생산하게 되면 새로운 개념의 농업\n이 형성하여 국가 경쟁력을 높일 수 있음", "classSubHtml": "A01090802.html", "classSubIdx": "142", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090802.pdf", "classSubTitle": "형질전환 동물이용 바이오신약 생산", "classSubUse": "Y", "regDate": "2009-03-19 18:59:48.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('122', '다중유전자 동시발현 신기술로 베타카로틴 생성 황금쌀(비타민A 쌀) 개발', '국외 개발 황금쌀(golden rice)과 차별되는 다중유전자 동시발현 신기술로 질병 예방 효과를 지
닌 베타카로틴(비타민 A)을 쌀 100g당 1.27㎎ 생성하는 신기능성 황금쌀을 개발함
하루 밥 두 공기(236g) 정도로 비타민A 일일권장량(5000 IU) 섭취 가능', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090302", "classSubContents": "국외 개발 황금쌀(golden rice)과 차별되는 다중유전자 동시발현 신기술로 질병 예방 효과를 지\n닌 베타카로틴(비타민 A)을 쌀 100g당 1.27㎎ 생성하는 신기능성 황금쌀을 개발함\n하루 밥 두 공기(236g) 정도로 비타민A 일일권장량(5000 IU) 섭취 가능", "classSubContents2": "생명공학 기술에 의한 작물 개발이 몬산토, 신젠타 등 선진국의 몇몇 다국적 기업에 의해 주도되\n고 있는 현실에서 미래 종자전쟁을 대비하여 우리의 독자적인 생명공학 기술 경쟁력 확보가 절실\n생명공학이라는 유전자 도입 기술로 신기능성 작물 개발 시 다수의 유용유전자 발현을 동시에 유\n도하는 다중유전자 발현 기술 필요", "classSubHtml": "A01090302.html", "classSubIdx": "122", "classSubMaster": "담당자 : 농업연구사 하선화 (031-299-1675)", "classSubMovieUrl": null, "classSubPdf": "A01090302.pdf", "classSubTitle": "다중유전자 동시발현 신기술로 베타카로틴 생성 황금쌀(비타민A 쌀) 개발", "classSubUse": "Y", "regDate": "2009-03-19 17:49:00.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('115', '과채류 접목로봇', '수박, 오이, 고추 등 과채류를 자동으로 접목하는 로봇', NULL, NULL, '{"classCode": "A010901", "className": "농기계", "classSubCode": "A01090102", "classSubContents": "수박, 오이, 고추 등 과채류를 자동으로 접목하는 로봇", "classSubContents2": "과채류의 접목묘는 플러그 육묘시스템이 도입되면서 농가단위 생산에서 공정육묘장의 대량생산 \n체계로 전환\n수박, 오이 등 과채류는 접목묘의 생산과 재배가 분업화\n공정육묘장에서 접목묘 생산은 인력에 의존하여 가장 큰 애로점이 접목작업 숙련자 확보이므로 \n생력화를 위한 기계기술 개발 필요", "classSubHtml": "A01090102.html", "classSubIdx": "115", "classSubMaster": "담당자 : 농업연구관  강창호  (031-290-1932)", "classSubMovieUrl": null, "classSubPdf": "A01090102.pdf", "classSubTitle": "과채류 접목로봇", "classSubUse": "Y", "regDate": "2009-03-19 17:31:47.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('66', '과수 무독 우량모수 국가관리체계 연구', '사과 바이로이드(ASSVd)는 결실기가 되어서야 비로소 병 증상이 나타나 그 피해가 크므로 조기
에 무독묘를 선발하여 재식하여야만 피해를 예방할 수 있다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090402", "classSubContents": "사과 바이로이드(ASSVd)는 결실기가 되어서야 비로소 병 증상이 나타나 그 피해가 크므로 조기\n에 무독묘를 선발하여 재식하여야만 피해를 예방할 수 있다.", "classSubContents2": "1998년 경북의 한 농가에서 최초 발견된 이후 한반도 전역으로 확산\n감염과실은 크기가 작아지며 과피가 얼룩덜룩해져 상품성을 잃게 됨\n유목기에는 전혀 증상이 나타나지 않고 결실기의 과실에만 그 증상이 발현\n기존의 RT-PCR 검정법으로는 정밀한 진단이 불가능해 이에 대한 정밀 진단기술의 개발 요구 증대", "classSubHtml": "A01090402.html", "classSubIdx": "66", "classSubMaster": "담당자 : 농업연구사 강삼석 (061-330-1541)", "classSubMovieUrl": null, "classSubPdf": "A01090402.pdf", "classSubTitle": "과수 무독 우량모수 국가관리체계 연구", "classSubUse": "Y", "regDate": "2009-03-17 18:42:39.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('226', '식습관 개선을 위한 음식 짠맛센서', '간편하게 휴대하면서 국물류 음식의 짠맛을 측정할 수 있음', NULL, NULL, '{"classCode": "A010905", "className": "농산물안전성", "classSubCode": "A01090503", "classSubContents": "간편하게 휴대하면서 국물류 음식의 짠맛을 측정할 수 있음", "classSubContents2": "○ 한국인 소금 섭취량은 권장량의 3배 정도 높음\n- WHO 권장 섭취량 : 5g/일 이하(섭취량 : 13.4g/일)\n○ 소금(나트륨)의 과잉섭취는 고혈압, 위암, 뇌졸중, 심혈관질환, 골다공증 유발\n○ 짜게 먹는 습관을 개선하기 위해 짠맛을 손쉽게 인지할 수 있는 수단 필요", "classSubHtml": "A01090503.html", "classSubIdx": "226", "classSubMaster": "농업연구사 양길모 031-290-2902", "classSubMovieUrl": null, "classSubPdf": "A01090503.pdf", "classSubTitle": "식습관 개선을 위한 음식 짠맛센서", "classSubUse": "Y", "regDate": "2010-04-19 16:12:09.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('219', '수벌번데기 생산기술개발 및 영양성분 분석(2008)', '양봉농가가 수벌을 생산하기 위해서는 많은 노력과 기술이 필요한데, 이러
한 수벌생산의 어려움을 극복하기 위하여 탈착이 가능한 수벌생산 전용 벌집을
개발하여 많은 농가들이 손쉽게 수벌을 생산하도록 개발된 기술임', NULL, NULL, '{"classCode": "A010907", "className": "잠사곤충", "classSubCode": "A01090703", "classSubContents": "양봉농가가 수벌을 생산하기 위해서는 많은 노력과 기술이 필요한데, 이러\n한 수벌생산의 어려움을 극복하기 위하여 탈착이 가능한 수벌생산 전용 벌집을\n개발하여 많은 농가들이 손쉽게 수벌을 생산하도록 개발된 기술임", "classSubContents2": "○ 양봉부산물인 수벌의 가치창출을 통한 양봉농가 신소득원 확보\n○ 수벌생산전용 벌집을 이용한 수벌생산의 편의 도모\n○ 대량생산 및 가공의 편리성을 통한 수벌번데기 가공 시장 확대\n○ 고기능 식품의 개발을 위한 수벌번데기 안정생산 기반 조성", "classSubHtml": "A01090703.html", "classSubIdx": "219", "classSubMaster": "농업연구사 최용수 031-290-8528", "classSubMovieUrl": null, "classSubPdf": "A01090703.pdf", "classSubTitle": "수벌번데기 생산기술개발 및 영양성분 분석(2008)", "classSubUse": "Y", "regDate": "2010-04-19 15:18:30.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('192', '소규모 재배작물 8종의 품종 구분용 SSR 프라이머 개발', '최근 분자생물학의 급속한 발전으로 핵산(DNA) 수준에서 유전자원의 다양성 연구를 가능하게 하
는 핵산지문분석법(DNA fingerprinting)과 다양한 분자마커가 개발되고 있다. 이를 통해 유용 형
질 탐색, 생물의 종판별, 품종 구분 및 집단 개체군의 유연관계 분석 등을 외부환경 등에 대하
여 거의 영향을 받지 않고 간단하고 신속하게 수행할 수 있게 되었다. 
지금까지 개발된 PCR(Polymerase Chain Reaction, 중합효소에 의한 DNA 증폭)을 이용한 핵산지문
분석법에는 RAPD(Randomly Amplified Polymorphic DNAs) 방법, AFLP(Amplified Fragment Length 
Polymorphic DNA) 방법, SSR(Simple Sequence Repeat) 방법 등이 있다. 그 중 RAPD 방법은 비특
이적 PCR 산물이 생성되므로 재현성이 떨어지는 단점이 있고, AFLP 방법은 높은 DNA 다형성 검출
로 각광받고 있지만 재현성이 낮고 분석이 복잡하다는 단점이 있다. 이에 반해, SSR 방법은 DNA 
반복배열인 초위성체(microsatellite) 영역의 염기서열 정보를 근거로 PCR 프라이머를 제작하여 
이용하는 방법으로서, 분석이 용이하고 외부 환경의 영향을 전혀 받지 않으므로 높은 재현성을 
보인다. 벼, 콩 등 주요 재배 작물들에서는 다양한 품종구분용 SSR 마커들이 개발되어 있으나, 
마늘, 인삼과 같은 소규모 재배작물에서는 개발이 미비한 실정이다. 이에 농업유전자원센터에서
는 마늘, 매실, 인삼 등 소규모 재배작물 8종의 품종구분에 활용될 수 있는 SSR 프라이머를 개발
하였다.', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090303", "classSubContents": "최근 분자생물학의 급속한 발전으로 핵산(DNA) 수준에서 유전자원의 다양성 연구를 가능하게 하\n는 핵산지문분석법(DNA fingerprinting)과 다양한 분자마커가 개발되고 있다. 이를 통해 유용 형\n질 탐색, 생물의 종판별, 품종 구분 및 집단 개체군의 유연관계 분석 등을 외부환경 등에 대하\n여 거의 영향을 받지 않고 간단하고 신속하게 수행할 수 있게 되었다. \n지금까지 개발된 PCR(Polymerase Chain Reaction, 중합효소에 의한 DNA 증폭)을 이용한 핵산지문\n분석법에는 RAPD(Randomly Amplified Polymorphic DNAs) 방법, AFLP(Amplified Fragment Length \nPolymorphic DNA) 방법, SSR(Simple Sequence Repeat) 방법 등이 있다. 그 중 RAPD 방법은 비특\n이적 PCR 산물이 생성되므로 재현성이 떨어지는 단점이 있고, AFLP 방법은 높은 DNA 다형성 검출\n로 각광받고 있지만 재현성이 낮고 분석이 복잡하다는 단점이 있다. 이에 반해, SSR 방법은 DNA \n반복배열인 초위성체(microsatellite) 영역의 염기서열 정보를 근거로 PCR 프라이머를 제작하여 \n이용하는 방법으로서, 분석이 용이하고 외부 환경의 영향을 전혀 받지 않으므로 높은 재현성을 \n보인다. 벼, 콩 등 주요 재배 작물들에서는 다양한 품종구분용 SSR 마커들이 개발되어 있으나, \n마늘, 인삼과 같은 소규모 재배작물에서는 개발이 미비한 실정이다. 이에 농업유전자원센터에서\n는 마늘, 매실, 인삼 등 소규모 재배작물 8종의 품종구분에 활용될 수 있는 SSR 프라이머를 개발\n하였다.", "classSubContents2": "소규모 재배 작물의 다양성 분석\n소규모 재배 작물의 신속&#8228;정확한 평가를 통한 활용 증진\n소규모 재배 작물의 종 및 품종 구분용 SSR 마커 시스템 확립", "classSubHtml": "A01090303.htm", "classSubIdx": "192", "classSubMaster": "담당자 : 농업연구사 이기안 (031-299-1887)", "classSubMovieUrl": null, "classSubPdf": "A01090303.pdf", "classSubTitle": "소규모 재배작물 8종의 품종 구분용 SSR 프라이머 개발", "classSubUse": "Y", "regDate": "2009-06-12 14:19:32.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('149', '고추 탄저병균에 대한 항진균 활성을 가지는 바실러스속 균주', '본 개발은, 고추 재배시 발병하는 고추 탄저병의 포자의 발아를 억제하는 미생물을 선발하여 이
를 이용한 배양액을 고추재배지에 처리함으로써 고추탄저병의 발병율을 감소시켜 안전하고 질이 
좋은 고추를 생산하는 방법을 제공하는 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090603", "classSubContents": "본 개발은, 고추 재배시 발병하는 고추 탄저병의 포자의 발아를 억제하는 미생물을 선발하여 이\n를 이용한 배양액을 고추재배지에 처리함으로써 고추탄저병의 발병율을 감소시켜 안전하고 질이 \n좋은 고추를 생산하는 방법을 제공하는 기술임", "classSubContents2": "목    적 : 고추재배시 발생하는 주요 병해인 탄저병에 대하여 항진균 활성을 나타내는 미생물\n을 친환경 농자재로 이용함으로써 환경생태의 유지와 작물의 안정생산에 기여할 수 있음 \n필 요 성 : 고추재배에 균 배양액을 살포함으로서 자연발생적인 코레 토트리쿰(Colletotrichum \nsp.)의 발병을 억제하여 고추탄저 병의 발생을 감소시켜 궁극적으로는 환경생태의 유지와 안정농\n산물생산에 기여할 수 있음", "classSubHtml": "A01090603.html", "classSubIdx": "149", "classSubMaster": "담당자 : 농업연구사 유재홍 (031-290-0551)", "classSubMovieUrl": null, "classSubPdf": "A01090603.pdf", "classSubTitle": "고추 탄저병균에 대한 항진균 활성을 가지는 바실러스속 균주", "classSubUse": "Y", "regDate": "2009-03-19 19:09:15.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('146', '식탁을 화려하게 장식하는 칼라느타리 육성', '무지개빛 칼라느타리 육성 및 보급 사업의 일환으로 개발된 노랑, 분홍, 청, 백색 느타리의 재배
를 위한 적정배지와 그 재배법을 개발하고 국내 기후에 맞는 새로운 품종을 육성하여 보급하고
자 함', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090903", "classSubContents": "무지개빛 칼라느타리 육성 및 보급 사업의 일환으로 개발된 노랑, 분홍, 청, 백색 느타리의 재배\n를 위한 적정배지와 그 재배법을 개발하고 국내 기후에 맞는 새로운 품종을 육성하여 보급하고\n자 함", "classSubContents2": "현재 느타리시장은 흑회색의 ‘춘추’ 느타리 품종이 대부분을 차지함\n중국 등 외국은 오히려 백색느타리를 선호하나 국내는 저장 및 소비자 선호도 등 시장여건의 차\n이로 칼라느타리의 보급이 미흡함\n일반 시민을 대상으로 한 버섯전시회에서 청년층을 중심으로 한 칼라느타리버섯에 대한 호응도\n가 높음\n다양한 색깔의 느타리버섯 보급을 통한 농가의 선택 폭 확대 및 소비 촉진이 요구됨", "classSubHtml": "A01090903.htm", "classSubIdx": "146", "classSubMaster": "담당자 : 농업연구관 유영복, 연구사 장갑열 (031-290-0373)", "classSubMovieUrl": null, "classSubPdf": "A01090903.pdf", "classSubTitle": "식탁을 화려하게 장식하는 칼라느타리 육성", "classSubUse": "Y", "regDate": "2009-03-19 19:07:00.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('143', '현장형 간편 우유품질 분석기', '본 기기는 우유의 일반성분과 체세포 수 및 항생제 유무 등을 현장에서 신속하고 정확하게 정량
·정성분석을 통해 안전한 우유 생산과 분석치를 활용한 자가 사양관리가 가능하도록 개발한 장
치임', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090803", "classSubContents": "본 기기는 우유의 일반성분과 체세포 수 및 항생제 유무 등을 현장에서 신속하고 정확하게 정량\n·정성분석을 통해 안전한 우유 생산과 분석치를 활용한 자가 사양관리가 가능하도록 개발한 장\n치임", "classSubContents2": "최근 안전하고 품질이 우수한 우유에 대한 소비자의 관심이 증대되고 있음\n기존의 우유 품질분석은 분석시간 및 비용이 많이 들어 일반농가의 자가 생산 우유에 대한 품질\n을 평가는 어려운 실정임\n낙농농가에서 실용적으로 이용할 수 있도록 간편 현장형으로 제작하였음\n- 원유의 전처리 없이 튜브에 담아 버턴 하나로 우유의 일반성분, 체세포 수, MUN(우유 중 요소\n태질소화합물), 및 항생제 유무를 수초 내 판별 가능\n농가에서 개체별 및 농가별 우유 분석결과를 이용하여 사양관리 지표로 활용", "classSubHtml": "A01090803.html", "classSubIdx": "143", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090803.pdf", "classSubTitle": "현장형 간편 우유품질 분석기", "classSubUse": "Y", "regDate": "2009-03-19 19:03:57.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('116', '비파괴 과일 품질판정기술 개발', '과일을 쪼개거나 자르지 않고 당도와 산도, 크기, 무게, 색깔, 내부 이상 유무 등의 품질을 신속
하게 판정하는 기술로 시간당 3,600개에서 14,400개까지 등급별로 선별할 수 있음.', NULL, NULL, '{"classCode": "A010901", "className": "농기계", "classSubCode": "A01090103", "classSubContents": "과일을 쪼개거나 자르지 않고 당도와 산도, 크기, 무게, 색깔, 내부 이상 유무 등의 품질을 신속\n하게 판정하는 기술로 시간당 3,600개에서 14,400개까지 등급별로 선별할 수 있음.", "classSubContents2": "농업 생산 인구의 감소 및 고령화 등 농촌노동력부족에 대응하는 수확 후 농산물 선별작업의 자\n동화, 무인화 지능화 기계기술개발이 필요하며, 최근 급증하고 있는 외국 농산물과의 차별화와 \n국내 소비자의 건강 보호를 위해서는 보다 과학적이고 객관적인 품질 판정기술 개발이 시급함\n과수원에서 생산되는 과일의 품질을 나타내기 위해서는 그 중 몇 개의 과실을 따서 즙을 낸 다\n음 단맛과 신맛 등을 측정하여 평균값으로 과수원 전체의 값으로 나타냄.\n같은 나무에서 자란 과일도 생육 위치에 따라 햇빛에 노출되는 정도와 영양분의 공급 상태가 달\n라 개체간 품질 차이가 매우 크므로 표본검사가 아닌 전수검사가 요구되어 객관적인 농산물의 품\n질평가를 위해서는 각종 첨단센서 등을 응용한 비파괴&#8228;비접촉&#8228;실시간 판정 기술 개발이 필요함\n맛있고 품질 좋은 과일을 생산한 농가에서는 품질 좋은 과일 생산에 대한 대가를 받을 수 있게 \n하고 경쟁력 있는 우리 과일의 수출을 위해서는 품질별로 차별화 할 수 있는 기술의 개발이 선행\n되어야 함.", "classSubHtml": "A01090103.htm", "classSubIdx": "116", "classSubMaster": "담당자 : 농업연구관  이강진 (031-290-1898)", "classSubMovieUrl": null, "classSubPdf": "A01090103.pdf", "classSubTitle": "비파괴 과일 품질판정기술 개발", "classSubUse": "Y", "regDate": "2009-03-19 17:34:07.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('67', '과수 잎말이나방류의 성페로몬 트랩 이용 기술', '과수원에서 사과, 배, 감귤 등의 과실 껍질을 갉아먹어 상품가치를 떨어트리는 해충인 애모무늬
잎말이나방의 수컷 성충을 포획할 수 있는 최적의 성페로몬 트랩을 개발함', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090403", "classSubContents": "과수원에서 사과, 배, 감귤 등의 과실 껍질을 갉아먹어 상품가치를 떨어트리는 해충인 애모무늬\n잎말이나방의 수컷 성충을 포획할 수 있는 최적의 성페로몬 트랩을 개발함", "classSubContents2": "애모무늬잎말이나방 성충의 발생량을 조사할 수 있는 기술이 필요함\n국내 과수원에서는 애모무늬잎말이나방류 3종이 지역에 따라 발생하는 종류가 다르므로 페로몬 \n트랩의 판매와 이용 시 각별한 주의가 요구됨", "classSubHtml": "A01090403.htm", "classSubIdx": "67", "classSubMaster": "담당자 : (농업연구사) (양창열) (031-290-6229)", "classSubMovieUrl": null, "classSubPdf": "A01090403.pdf", "classSubTitle": "과수 잎말이나방류의 성페로몬 트랩 이용 기술", "classSubUse": "Y", "regDate": "2009-03-17 18:43:26.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('193', '밥 원료미의 유전자 간편 추출방법 개발', '밥에서 양질의 유전자를 재현성이 높으며 안정적으로 추출하는 방법개발로 밥 원료미의 품종 판
별에 이용할 수 있는 기술임', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090304", "classSubContents": "밥에서 양질의 유전자를 재현성이 높으며 안정적으로 추출하는 방법개발로 밥 원료미의 품종 판\n별에 이용할 수 있는 기술임", "classSubContents2": "국내 시장에 유통되는 브랜드쌀에 대한 소비자의 신뢰 확보와 품질 고급화를 위하여 2005년부터\n는 포장양곡표시기준을 준수하여야 하며, 2007년부터는 품종 표시 사항에 대한 규제가 시작됨. \n우리나라에서 쌀은 강화되는 농산물 표시 관련제도에 대응하여 품종 확인뿐만 아니라 앞으로는 \n식당 등 소비처에서도 원산지를 표시해야 됨에 따라 쌀 뿐만 아니라 가공된 식품에서의 품종판별\n이 필요\n따라서 본 기술은 호화전분 상태인 밥에서 양질의 유전자를 안정적으로 추출하는 방법을 확립하\n여 유통 및 소비단계의 밥 상태에서 원료미 품종판별에 필요한 기술임", "classSubHtml": "A01090304.html", "classSubIdx": "193", "classSubMaster": "담당자 : 농업연구사 송 진 031-299-0511", "classSubMovieUrl": null, "classSubPdf": "A01090304.pdf", "classSubTitle": "밥 원료미의 유전자 간편 추출방법 개발", "classSubUse": "Y", "regDate": "2009-06-12 14:21:50.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('153', '한국형 발효생햄 제조기술', '우리나라 4계절을 이용하여 특별한 시설투자 없이 제조하는 방법과 온도 및 습도가 조절되는 발
효실 내에서 제조하는 방법으로 돼지 뒷다리(껍질과 뼈가 포함된 상태), 천일염, 거치대(뒷다리
를 걸어두는 곳)가 필요하며, 개략적으로 원료육 다듬기 → 염지 → 수침·세척 → 모양잡기 → 
발효 → 건조단계로 간편하게 제조할 수 있는 기술', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090804", "classSubContents": "우리나라 4계절을 이용하여 특별한 시설투자 없이 제조하는 방법과 온도 및 습도가 조절되는 발\n효실 내에서 제조하는 방법으로 돼지 뒷다리(껍질과 뼈가 포함된 상태), 천일염, 거치대(뒷다리\n를 걸어두는 곳)가 필요하며, 개략적으로 원료육 다듬기 → 염지 → 수침·세척 → 모양잡기 → \n발효 → 건조단계로 간편하게 제조할 수 있는 기술", "classSubContents2": "국내 돈육의 소비 형태는 선호 및 비선호부위로 뚜렷이 구분되어 가격 차이가 심함(‘03, 육가공\n협회)\n   - 선호도(%) : 삼겹살 67, 목살 26, 등심 5, 기타 2\n   - 도매가격(&#39;08. 2) : 삼겹살 8,362원/㎏, 뒷다리 2,755\n돈육 부위별 생산량은 비선호 부위가 상대적으로 많음(‘04, 축산원)\n   - 선호부위(36.5%) : 삼겹살 18.3, 목심 9.3, 갈비 8.9\n   - 비선호부위(63.5%) : 뒷다리 30.9, 앞다리 19.7, 등심 12.9\n국내 돈육의 소비 형태에 따라 삼겹살의 수입은 증가하나 비선호 부위는 공급과잉으로 양돈산업\n의 경쟁력 저하 원인이 되고 있음\n   - 삼겹살 수입량(톤) : (‘04) 64,484 → (’05) 83,076 → (‘06) 92,638\n비선호 부위는 지방함량이 낮아 주 소비형태인 구이용으로는 부적합하여 부가가치 향상을 위해 \n다양한 제품개발 필요\n   - 등심과 안심(돈까스 제품), 앞다리(양념육), 뒷다리(육제품 원료)\n우리나라의 경우 돈육생산 대비 가공육제품 생산 비율은 15% 내외로 일본의 30%, 유럽의 70%에 \n비해 현저히 낮아 양돈산업 발달의 저해요인\n   - 국내 돈육생산량 대비 가공육제품 제조율 : (‘04) 13% → (&#39;06) 15.72\n국민식생활 패턴 변화로 발효육제품 등 고가의 육제품이 수입 판매되고 있으나 국내산 발효육제\n품 생산은 전무함\n   - 수입제품 및 가격 : 파르마햄 12,500원/100g, 하몽 11,000\n다양한 육제품 개발로 비선호부위 부가가치 향상 및 소비촉진 시급\n주산지 등 지역특성을 고려한 축산물 가공·이용 기술 개발 필요", "classSubHtml": "A01090804.html", "classSubIdx": "153", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090804.pdf", "classSubTitle": "한국형 발효생햄 제조기술", "classSubUse": "Y", "regDate": "2009-03-19 19:12:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('151', '고활성 유도저항성 근권균 EXTN-1에 의한 식물병 방제', '근권미생물로 선발된 EXTN-1균은 식물의 병에 대한 면역력을 증가시켜 식물병을 방제하는 기작으
로 국립농업과학원 연구진에 의하여 개발되었다. 이 균주는 바이러스, 세균, 곰팡이 등 모든 식
물병에 억제효과와 식물생육촉진 효과가 있으며 특히 식물바이러스 방제제가 없는 상황에서 근
권 미생물을 이용한 바이러스방제제로의 활용도 가능하다.', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090604", "classSubContents": "근권미생물로 선발된 EXTN-1균은 식물의 병에 대한 면역력을 증가시켜 식물병을 방제하는 기작으\n로 국립농업과학원 연구진에 의하여 개발되었다. 이 균주는 바이러스, 세균, 곰팡이 등 모든 식\n물병에 억제효과와 식물생육촉진 효과가 있으며 특히 식물바이러스 방제제가 없는 상황에서 근\n권 미생물을 이용한 바이러스방제제로의 활용도 가능하다.", "classSubContents2": "다목적의 실용화 가능한 생물 방제용 미생물제의 개발이 필요함.\n유기합성농약의 과다 사용에 의한 농업생태계 오염과 안전 농산물에 대한 우려 중대.", "classSubHtml": "A01090604.html", "classSubIdx": "151", "classSubMaster": "담당자 : 농업연구관 박경석 (031-290-0424)", "classSubMovieUrl": null, "classSubPdf": "A01090604.pdf", "classSubTitle": "고활성 유도저항성 근권균 EXTN-1에 의한 식물병 방제", "classSubUse": "Y", "regDate": "2009-03-19 19:10:23.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('148', '신경세포 보호활성을 갖는 아세틸시포닌을 포함하는 퇴행성 뇌질환 예방 및 치료용 약학 조성물', '지치의 주요 효능은 주로 지치 색소성분에 기인하는데, 기존에 알려진 항염증, 항암, 항산화 및 
면역증진 효과 이외에 지치 색소성분이 뇌신경세포를 보호하는 효능이 우수함을 실험적으로 입증
하였다.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090904", "classSubContents": "지치의 주요 효능은 주로 지치 색소성분에 기인하는데, 기존에 알려진 항염증, 항암, 항산화 및 \n면역증진 효과 이외에 지치 색소성분이 뇌신경세포를 보호하는 효능이 우수함을 실험적으로 입증\n하였다.", "classSubContents2": "최근 천연물 유래 건강기능식품 시장 규모가 점차 확대되고 있고, 식물자원에 함유된 기능성 물\n질을 이용하는 연구가 활발함\n합성색소가 천연색소보다 가격과 안정성 및 응용성 등에서 이용가치가 뛰어나나 발암성 등 합성\n색소의 부작용이 지적됨\n천연색소는 인체 안전성이 인정되어 식의약품 및 향장품의 소재로서 개발 가치 높고 최근 기능\n성 식품 첨가물로서 각광을 받고 있음\n지치는 기능성 적색소를 함유한 약용작물로서 지치 색소성분을 효과적으로 대량 분리정제하여 신\n규 기능성을 구명함으로써 건강기능식품의  소재화를 위한 기초자료로 활용이 가능함", "classSubHtml": "A01090904.htm", "classSubIdx": "148", "classSubMaster": "담당자 : 농업연구사 김금숙 043-871-5582", "classSubMovieUrl": null, "classSubPdf": "A01090904.pdf", "classSubTitle": "신경세포 보호활성을 갖는 아세틸시포닌을 포함하는 퇴행성 뇌질환 예방 및 치료용 약학 조성물", "classSubUse": "Y", "regDate": "2009-03-19 19:09:02.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('117', '참기름 진위 판별 기술', '식용 기름에 빛을 비춰 그 기름이 진짜 순수 참기름인지 혹은 옥수수기름이나 콩기름과 같은 이
종 식용기름이 섞인 가짜 참기름인지 여부를 판별하는 기술', NULL, NULL, '{"classCode": "A010901", "className": "농기계", "classSubCode": "A01090104", "classSubContents": "식용 기름에 빛을 비춰 그 기름이 진짜 순수 참기름인지 혹은 옥수수기름이나 콩기름과 같은 이\n종 식용기름이 섞인 가짜 참기름인지 여부를 판별하는 기술", "classSubContents2": "참기름에 이종식용유의 혼입여부를 신속하게 판단하기 어려움\n기존의 판별법은 분석에 시간이 많이 소요됨\n기존의 판별법은 시약처리를 해야 하는 등 전문가가 다뤄야 함\n참기름의 진위여부를 신속하게 판단할 수 있는 기술 개발 필요", "classSubHtml": "A01090104.htm", "classSubIdx": "117", "classSubMaster": "담당자 : 농업연구사 강석원 (031-290-1903)", "classSubMovieUrl": null, "classSubPdf": "A01090104.pdf", "classSubTitle": "참기름 진위 판별 기술", "classSubUse": "Y", "regDate": "2009-03-19 17:35:33.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('68', '국내 최초 신품종 여름딸기 ‘고하’', '당도가 높고 다수성인 ‘엘란’을 모본으로 경도가 뛰어난 ‘플라멩고&#39;을 부본
으로 2003년 인공교배, 2004년 실생개체 선발한 후 2007년 고온장일조건
하에서 개화&#8228;결실되는 사계성딸기 품종을 개발', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090404", "classSubContents": "당도가 높고 다수성인 ‘엘란’을 모본으로 경도가 뛰어난 ‘플라멩고&#39;을 부본\n으로 2003년 인공교배, 2004년 실생개체 선발한 후 2007년 고온장일조건\n하에서 개화&#8228;결실되는 사계성딸기 품종을 개발", "classSubContents2": "현재 재배되는 여름딸기는 비싼 로열티를 주는 유럽 사계성품종임\n여름딸기 수출량 및 재배면적 증가 : (’03) 3.3 → (’09) 15ha", "classSubHtml": "A01090404.htm", "classSubIdx": "68", "classSubMaster": "담당자 : 농업연구사 이종남(033-330-1651)", "classSubMovieUrl": null, "classSubPdf": "A01090404.pdf", "classSubTitle": "국내 최초 신품종 여름딸기 ‘고하’", "classSubUse": "Y", "regDate": "2009-03-17 18:44:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('194', '아토피성 피부 개선용 식물추출혼합물, AF343', '국내산 검은콩, 자두등의 식물 추출 혼합물을 제조하여 면역과민반응 억제를 통해 아토피성 피부
염 증상을 완화할 수 있는 천연소재 개발 기술임.', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090305", "classSubContents": "국내산 검은콩, 자두등의 식물 추출 혼합물을 제조하여 면역과민반응 억제를 통해 아토피성 피부\n염 증상을 완화할 수 있는 천연소재 개발 기술임.", "classSubContents2": "각종 공해물질에 대한 노출 증가, 산모의 노령화, 서구적인 식생활 등으로 인해 아토피성 피부염\n의 발생이 증가\n최근 통계청 자료에 따르면 국내 유아(0～4세) 6명중 1명이 아토피 질환에 시달리고 있고, 어린\n이 아토피성 피부염 유병율 추이는 현재에는 35% 이상에 이를 것으로 판단됨.\n아토피성 피부염 치료를 위하여 사용되는 연고 및 항히스타민제 등의 치료법은 부작용 및 재발위\n험성이 높기 때문에 일상적으로 복용하였던 국산 농산물을 이용함으로 부작용 및 재발 위험이 매\n우 낮은 식품 소재 개발이 요구됨.", "classSubHtml": "A01090305.htm", "classSubIdx": "194", "classSubMaster": "담당자 : 농업연구사 조수묵 (031-299-0532)", "classSubMovieUrl": null, "classSubPdf": "A01090305.pdf", "classSubTitle": "아토피성 피부 개선용 식물추출혼합물, AF343", "classSubUse": "Y", "regDate": "2009-06-12 14:22:55.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('155', 'SCB, 가축분뇨 자원화기술', 'SCB(Slurry Composting & Biofiltration, 퇴비단여과법)란? 고형 축분처리 용도인 퇴비화
(Composting) 시설을 탁월한 생물여과(Biofiltration) 기능을 가지게 함으로써 무취의 균질액비
를 생산하는 분뇨처리기술임', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090805", "classSubContents": "SCB(Slurry Composting & Biofiltration, 퇴비단여과법)란? 고형 축분처리 용도인 퇴비화\n(Composting) 시설을 탁월한 생물여과(Biofiltration) 기능을 가지게 함으로써 무취의 균질액비\n를 생산하는 분뇨처리기술임", "classSubContents2": "양돈분뇨는 수분함량 95%의 고농도 액상물질로서 관행의 자원화시설로는 처리가 어렵다. 즉, 퇴\n비화시설은 수분과다로 정상적 처리가 어려워 방치시설이 많고, 저장액비화시설은 악취발생에 의\n한 민원야기, 성분 불균일로 작물농가 수요도 매우 저조 → 새로운 자원화 시설이 필요.", "classSubHtml": "A01090805.html", "classSubIdx": "155", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090805.pdf", "classSubTitle": "SCB, 가축분뇨 자원화기술", "classSubUse": "Y", "regDate": "2009-03-19 19:13:26.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('154', '과일 저장병 방제용 미생물 판토에아아글로메란스', '수확 후 저장 및 유통 중에 신선과일 및 채소에 발생하는 병해를 방제할 목적으로 마늘 근권으로
부터 영양원 경합능력이 우수한 판토에아아글로메란스(Pa59-4)를 분리, 선발하였으며 이는 식물
병해에 대한 억제능력이 우수하고 정착도 잘되어 생물농약으로 개발이 가능할 것임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090605", "classSubContents": "수확 후 저장 및 유통 중에 신선과일 및 채소에 발생하는 병해를 방제할 목적으로 마늘 근권으로\n부터 영양원 경합능력이 우수한 판토에아아글로메란스(Pa59-4)를 분리, 선발하였으며 이는 식물\n병해에 대한 억제능력이 우수하고 정착도 잘되어 생물농약으로 개발이 가능할 것임", "classSubContents2": "과일 및 채소 저장 중 병원균에 의해 발생하는 부패 최소화\n신선 과일 및 채소의 안정적 생산 도모 및 고품질 안전 농산물 생산", "classSubHtml": "A01090605.htm", "classSubIdx": "154", "classSubMaster": "담당자 : 농업연구관 김용기 (031-290-0541)", "classSubMovieUrl": null, "classSubPdf": "A01090605.pdf", "classSubTitle": "과일 저장병 방제용 미생물 판토에아아글로메란스", "classSubUse": "Y", "regDate": "2009-03-19 19:13:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('150', '인삼 품질 표준화 및 기능성 소재 개발 연구', '중풍, 치매, 파킨슨병등에서 발생하는 신경세포의 사멸을 인삼이 효과적으로 억제하고  노화와 
함께 수반되는 인지능력의 감소를 막아주며 인삼을 치료약물로서 개발하는 것은 기초성과에서 제
약, 식품산업의 신제품 개발로도 높은 가치를 갖는다.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090905", "classSubContents": "중풍, 치매, 파킨슨병등에서 발생하는 신경세포의 사멸을 인삼이 효과적으로 억제하고  노화와 \n함께 수반되는 인지능력의 감소를 막아주며 인삼을 치료약물로서 개발하는 것은 기초성과에서 제\n약, 식품산업의 신제품 개발로도 높은 가치를 갖는다.", "classSubContents2": "인삼의 개별인정형 기능성 확대를 위한효능구명\n인삼의 뇌기능 개선 관련 건강기능 식품 원료성분 등록을 위한 기초자료 구축", "classSubHtml": "A01090905.htm", "classSubIdx": "150", "classSubMaster": "담당자 : 농업연구사 김영옥 043-871-5585", "classSubMovieUrl": null, "classSubPdf": "A01090905.pdf", "classSubTitle": "인삼 품질 표준화 및 기능성 소재 개발 연구", "classSubUse": "Y", "regDate": "2009-03-19 19:09:58.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('127', '껍질째 먹는 미니 참다래 ‘스키니그린’', '참다래(키위)는 세계적으로 ‘헤이워드’라는 녹색과육의 단일품종이 거의 대부분 재배, 생산되
고 있어 재배농가와 소비자의 선택의 폭이 매우 좁으며, 최근에서야 골드키위라 불리는 황색과육
의 품종이 보급 생산되고 있다. 농촌진흥청(청장 김재수)에서는 새로운 품종을 육성하기 위해 
1984년부터 육종 프로그램을 운영해 오고 있으며, 1단계 목표로 우리의 토종다래를 이용하여 껍
질째 먹을 수 있는 미니 참다래 육성의 결과로서 방울토마토처럼 한 입에 먹을 수 있는 미니 품
종 2호인「스키니그린」을 육성하였다. 「스키니그린」은 우리의 토종다래(A. arguta) 유전자원
을 소재로 육성된 품종으로 토종다래의 장점인 맛과 향을 최대한 발현시키고 크기가 작고 저장성
이 약하다는 단점을 극복한 우수한 품종으로서 소비자에게 어린시절의 향수와 함께 다양한 종류
의 참다래를 맛볼 수 있는 기회를 제공할 것으로 기대된다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090405", "classSubContents": "참다래(키위)는 세계적으로 ‘헤이워드’라는 녹색과육의 단일품종이 거의 대부분 재배, 생산되\n고 있어 재배농가와 소비자의 선택의 폭이 매우 좁으며, 최근에서야 골드키위라 불리는 황색과육\n의 품종이 보급 생산되고 있다. 농촌진흥청(청장 김재수)에서는 새로운 품종을 육성하기 위해 \n1984년부터 육종 프로그램을 운영해 오고 있으며, 1단계 목표로 우리의 토종다래를 이용하여 껍\n질째 먹을 수 있는 미니 참다래 육성의 결과로서 방울토마토처럼 한 입에 먹을 수 있는 미니 품\n종 2호인「스키니그린」을 육성하였다. 「스키니그린」은 우리의 토종다래(A. arguta) 유전자원\n을 소재로 육성된 품종으로 토종다래의 장점인 맛과 향을 최대한 발현시키고 크기가 작고 저장성\n이 약하다는 단점을 극복한 우수한 품종으로서 소비자에게 어린시절의 향수와 함께 다양한 종류\n의 참다래를 맛볼 수 있는 기회를 제공할 것으로 기대된다.", "classSubContents2": "참다래(키위)는 세계적으로 ‘헤이워드’라는 녹색과육의 단일품종이 거의 대부분 생산되고 있\n어 국내외적으로 재배농가와 소비자의 선택의 폭이 매우 좁음\n최근 뉴질랜드에서 육성된 골드키위라 불리는 황색과육의 품종이 보급, 생산되어 사과, 배, 복숭\n아, 포도와 같은 비중이 큰 과일에서처럼 품종이 다양화되기 시작함\n참다래(키위)가 맛도 좋고 몸에도 좋으나 과실 껍질의 털로 인해 성가시어 바쁜 현대인을 위해 \n우리의 토종 유전자원을 이용해 껍질째 먹을 수 있는 품종을 육성코자 하였음", "classSubHtml": "A01090405.htm", "classSubIdx": "127", "classSubMaster": "담당자 : 농업연구사 곽용범 055-864-1507", "classSubMovieUrl": null, "classSubPdf": "A01090405.pdf", "classSubTitle": "껍질째 먹는 미니 참다래 ‘스키니그린’", "classSubUse": "Y", "regDate": "2009-03-19 18:25:42.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('118', '채소정식기', '채소정식기는 육묘상자에 육묘된 채소를 한개씩 뽑아내어 밭에 일정한 간격과 깊이로 정식하는 
기계임', NULL, NULL, '{"classCode": "A010901", "className": "농기계", "classSubCode": "A01090105", "classSubContents": "채소정식기는 육묘상자에 육묘된 채소를 한개씩 뽑아내어 밭에 일정한 간격과 깊이로 정식하는 \n기계임", "classSubContents2": "농업인구의 고령화 및 부녀자화의 가속으로 노동력이 부족하고 생산비가 증가하고 있음\n농어업인구의 28.6%가 65세 이상임\n배추, 고추, 양배추, 브로콜리, 콩, 옥수수 등 밭작물의 정식작업은 대부분 인력에 의존하여 한\n개씩 정식해야 하므로 노동강도가 크기 때문에 기계화 요구도가 높음\n노동투하시간 : 배추 18.4시간/10a, 고추 24시간/10a", "classSubHtml": "A01090105.html", "classSubIdx": "118", "classSubMaster": "담당자 : 농업연구사 최덕규 (031-290-1784)", "classSubMovieUrl": null, "classSubPdf": "A01090105.pdf", "classSubTitle": "채소정식기", "classSubUse": "Y", "regDate": "2009-03-19 17:37:04.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('224', '양파정식기', '양 파정 식 기는 사람이 앉아 모를 공급하며 식부장치가 비닐 및 토양을 뚫고
8 ~ 10줄을 정식하는 반자동 양파정식기로 사람이 모를 공급하면 기계가 정식하
고 다음 심을 위치로 이동하므로 노력 및 비용을 크게 절감할 수 있는 기술임', NULL, NULL, '{"classCode": "A010901", "className": "농기계", "classSubCode": "A01090106", "classSubContents": "양 파정 식 기는 사람이 앉아 모를 공급하며 식부장치가 비닐 및 토양을 뚫고\n8 ~ 10줄을 정식하는 반자동 양파정식기로 사람이 모를 공급하면 기계가 정식하\n고 다음 심을 위치로 이동하므로 노력 및 비용을 크게 절감할 수 있는 기술임", "classSubContents2": "○ 양파의 정식작업은 전체 작업시간의 26%를 차지하여 기계화 요구도가 높\n은 작업이나 전적으로 인력에 의존하고 있는 실정임\n- 양 파 재배면적 : 15.4천ha, 인력 정식작업시간 : 50.2시간/10a\n○ 양파 정식작업은 10a당 34,000주로 밀식재배를 하기 때문에 허리를 오랫동안\n구부려 작업을 해야 하므로 노동강도가 높고, 정식시기가 마늘 파종시기와 맞물려 노\n동력 부족이 심화되고 있음\n○ 또한 농촌인력의 부족과 노령화로 인건비 상승 등의 문제가 증가하고 있어 정\n식 기계화의 개발 및 보급에 대한 필요성 증가\n○ 사람이 작업기에 탑승하여 모를 공급하고 식부장치가 비닐 및 토양을 뚫\n고 정식할 수 있는 반자동 양파정식 기계화 기술을 개발보급하여 양파정식 노\n력 및 비용을 절감하여 양파산업의 경쟁력을 확보하고자 함", "classSubHtml": "A01090106.html", "classSubIdx": "224", "classSubMaster": "농업연구사 최덕규 ☎ 031-290-1874", "classSubMovieUrl": null, "classSubPdf": "A01090106.pdf", "classSubTitle": "양파정식기", "classSubUse": "Y", "regDate": "2010-04-19 16:09:39.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('195', '유용미생물 이용 친환경 식물병 방제제', '○ 유기합성농약 과다사용에 따른 환경오염 감소 및 안전농산물 생산
○ 미생물 활용 친환경 작물보호 기술 확립 및 고부가 농산물 생산
○ 정부의 화학농약 및 비료 40% 감축계획에 대양한 미생물산업 활성화 촉진', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090306", "classSubContents": "○ 유기합성농약 과다사용에 따른 환경오염 감소 및 안전농산물 생산\n○ 미생물 활용 친환경 작물보호 기술 확립 및 고부가 농산물 생산\n○ 정부의 화학농약 및 비료 40% 감축계획에 대양한 미생물산업 활성화 촉진", "classSubContents2": "○ 최근 친환경농산물안전생산을 위하여는 고활성의 미생물자재의 개발이 필수적임\n○ 다양한 식물병에 복합적으로 작용하는 미생물제의 선발 활용이 필수적임.\n○ 복합병해 방제 등 신개념 생물방제제의 개발로 국내 관련업체의 산업화 촉진과 \n   국제생물농약시장 진출촉진\n○ 친환경 농업에서의 엽채류 균핵병 피해증가로 안정적 엽채류 생산차질", "classSubHtml": "A01090306.html", "classSubIdx": "195", "classSubMaster": "담당자 : 농업연구관  박경석  031-290-0424", "classSubMovieUrl": null, "classSubPdf": "A01090306.pdf", "classSubTitle": "유용미생물 이용 친환경 식물병 방제제", "classSubUse": "Y", "regDate": "2009-06-12 14:51:48.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('157', '필수아미노산 고함유 최고품질 벼 품종 “하이아미”', '최고품질 쌀 ‘하이아미’는 외관 품질이 매우 양호하고 부드럽고 고소한 맛이 나며 황함유 아미
노산이 다량 함유된 기능성 고품질 품종으로 쌀 품질 고급화와 식품 안전성 및 국민의 건강증진
에 도움을 줄수 있는 품종임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090606", "classSubContents": "최고품질 쌀 ‘하이아미’는 외관 품질이 매우 양호하고 부드럽고 고소한 맛이 나며 황함유 아미\n노산이 다량 함유된 기능성 고품질 품종으로 쌀 품질 고급화와 식품 안전성 및 국민의 건강증진\n에 도움을 줄수 있는 품종임", "classSubContents2": "1) 현황\n국민 식생활 행태변화로 쌀 소비의 지속적인 감소\n    - 1인당 쌀 소비량 : (‘02) 87.0 → (&#39;06) 78.8 → (&#39;07) 76.9→ (&#39;08) 75.8kg\n쌀시장 개방과 더불어 쌀의 품질경쟁력 향상을 위한 고품질 및 영양 강화 쌀에 대한 소비자 요구\n가 급증하고 있으며,또한 저투입·친환경 쌀 생산을 위한 내병충·내재해성 품종 수요도 꾸준히 \n증가하고 있는 추세임 \n2) 필요성\n우리쌀의 외관 및 밥맛의 지속적 개선으로 쌀의 국제 경쟁력 확보 필요\n국내 쌀 소비의 확대를 위한 품질 고급화 및 건강 기능성 강화 필요\n기후온난화 등 기상이변에 대비한 목적형질별 맞춤형 벼 품종개발이 절실히 요구되고 있음", "classSubHtml": "A01090606.html", "classSubIdx": "157", "classSubMaster": "담당자 : 농업연구관 최 임 수 031-290-6724", "classSubMovieUrl": null, "classSubPdf": "A01090606.pdf", "classSubTitle": "필수아미노산 고함유 최고품질 벼 품종 “하이아미”", "classSubUse": "Y", "regDate": "2009-03-19 19:15:12.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('156', '국가단위 가축 유전능력 평가와 우수 보증씨수소 선발', '국가단위 가축유전능력평가를 통한 능력이 검증된 우수 보증씨수소 선발
선발한 보증씨수소의 정액을 생산하여 냉동정액으로 농가에 공급함으로써 국가차원의 가축개량 
추진
보증씨수소 선발 및 정액공급은 작물의 신품종개발 및 종자공급과 동일', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090806", "classSubContents": "국가단위 가축유전능력평가를 통한 능력이 검증된 우수 보증씨수소 선발\n선발한 보증씨수소의 정액을 생산하여 냉동정액으로 농가에 공급함으로써 국가차원의 가축개량 \n추진\n보증씨수소 선발 및 정액공급은 작물의 신품종개발 및 종자공급과 동일", "classSubContents2": "가축의 개량은 개량의 목적에 맞는 후손을 생산하기 위하여 우수한 암, 수 개체를 선발하여 교배\n함으로써 이루어짐\n특히, 암소는 평생 10～20두의 자손을 생산할 수 있음에 반하여 수가축은 평생 6만 여 두의 자손\n을 생산할 수 있으므로 우수한 수소를 선발하는 것이 경제적 및 유전적으로 유리함\n암소는 번식에 활용해야 하므로 많은 수를 도태할 수 없지만 수소는 전국의 100만두 암소에 인공\n수정을 하더라도 50～60두가 소요되므로 암소보다 강선발을 통해 뛰어난 개체를 선발하기에 더\n욱 유리함\n국가단위 유전능력평가 기술 개발을 통해 개체별 정확한 유전능력 추정 및 보증씨수소를 선발하\n여 정액 생산공급체계 구축이 필요함", "classSubHtml": "A01090806.html", "classSubIdx": "156", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090806.pdf", "classSubTitle": "국가단위 가축 유전능력 평가와 우수 보증씨수소 선발", "classSubUse": "Y", "regDate": "2009-03-19 19:15:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('152', '종간잡종을 이용한 약용작물 삽주 초다수성 품종 ‘다출’', '삽주는 소화를 돕고 비장과 위장을 강화하여 소화를 촉진하는 용도로 많이 쓰이는 우리나라 전
통 약용작물임. 인삼특작부 약용작물과에서는 국내 최초로 종간교잡 육종(평창재래 × 중국도입)
을 통하여 기존 재래종보다 수량성이 1.6배 높고 약효성분이 우수한 신품종 ‘다출’을 개발하였
음.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090906", "classSubContents": "삽주는 소화를 돕고 비장과 위장을 강화하여 소화를 촉진하는 용도로 많이 쓰이는 우리나라 전\n통 약용작물임. 인삼특작부 약용작물과에서는 국내 최초로 종간교잡 육종(평창재래 × 중국도입)\n을 통하여 기존 재래종보다 수량성이 1.6배 높고 약효성분이 우수한 신품종 ‘다출’을 개발하였\n음.", "classSubContents2": "삽주(백출)는 대부분을 수입에 의존하고 있는 주요 약용작물이나 자생종은 뿌리 생산성이 낮고 \n도입종은 수량은 많으나 내병성이 약해 국내 도입이 어려운 실정임.\n삽주 새품종 ‘다출’은 이러한 단점을 보완하기 위해 종간교잡을 통해 육성한 다수성 품종임.", "classSubHtml": "A01090906.html", "classSubIdx": "152", "classSubMaster": "담당자 : 농업연구사 박춘근 043-871-5564", "classSubMovieUrl": null, "classSubPdf": "A01090906.pdf", "classSubTitle": "종간잡종을 이용한 약용작물 삽주 초다수성 품종 ‘다출’", "classSubUse": "Y", "regDate": "2009-03-19 19:10:54.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('128', '대일 수출용 백색 대국 ‘백마’', '국내 최초로 개발된 백색 대국 “백마”는 순백색의 대형 품종으로 꽃의 가
운데 부분에 녹색이 있고 절화수명이 길어 일본 국화시장에서 선풍적 인
기를 얻고 있는 수출유망 품종이다', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090406", "classSubContents": "국내 최초로 개발된 백색 대국 “백마”는 순백색의 대형 품종으로 꽃의 가\n운데 부분에 녹색이 있고 절화수명이 길어 일본 국화시장에서 선풍적 인\n기를 얻고 있는 수출유망 품종이다", "classSubContents2": "한국, 일본, 중국 등 아시아 지역에서는 국화가 주요 화훼품목으로 자\n리잡고 있으며 특히 일본은 세계 제1의 국화 육종, 생산, 소비 국가로\n서 세계적 국화 수출시장임\n스탠다드형 대국은 한국, 일본 등에서 전체 국화 중 50% 이상의 점유\n율을 차지하고 있으나 국내에서 자체 개발된 백색 대국 품종이 없음\n대국은 대부분 일본에서 개발된 품종을 사용하고 있으나 일본 시장에\n수출하기 위해서는 동일 품종을 사용하면서 저임금과 우수한 기후조건\n을 갖춘 중국, 베트남 등 동남아 제국과의 경쟁이 불가피함\n동남아 제국과의 경쟁을 피하고 독자적인 일본 국화시장 진출을 위해\n서는 품종보호제도를 활용할 수 있는 우수 국산품종의 개발이 절실함", "classSubHtml": "A01090406.htm", "classSubIdx": "128", "classSubMaster": "담당자 : 농업연구사, 임진희, 031-290-6144", "classSubMovieUrl": null, "classSubPdf": "A01090406.pdf", "classSubTitle": "대일 수출용 백색 대국 ‘백마’", "classSubUse": "Y", "regDate": "2009-03-19 18:27:05.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('244', '용도별 다양한 들깨 품종 개발', '2009년 용도별 들깨 신품종이 육성되었으며, 종실용으로 ‘백진’과 ‘단조’,
잎들깨용으로 ‘소망’이 개발되었음', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090907", "classSubContents": "2009년 용도별 들깨 신품종이 육성되었으며, 종실용으로 ‘백진’과 ‘단조’,\n잎들깨용으로 ‘소망’이 개발되었음", "classSubContents2": "들깨는 종실 및 엽용으로 용도에 따라서 특성 및 재배법이 달라 품종개발도\n달리하고 있음\n1) 기름 및 조미용 품종\n○ 재해에 강해 재배하기 쉽고 종자의 수량이 많으며,\n○ 종자의 껍질이 연해 먹기 좋으며, 기름이 많아 들기름용으로 적합한 품종 개발\n2) 들깻잎 전용 품종\n○ 다음 수확할 잎이 잘 자라서 수확하기 쉽고, 잎의 수량이 많으며,\n○ 항산화성분(안토시아닌)인 잎뒷면 보라색이 잘 나타나 건강에 좋은 품종 개발", "classSubHtml": "A01090907.html", "classSubIdx": "244", "classSubMaster": "농업연구사 이명희 055-350-1212", "classSubMovieUrl": null, "classSubPdf": "A01090907.pdf", "classSubTitle": "용도별 다양한 들깨 품종 개발", "classSubUse": "Y", "regDate": "2010-04-19 17:43:33.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('225', '야생동물 퇴치장치', '멧돼지, 고라니 등 야생동물에 의한 농작물 피해 방지를 위하여 전자센서로
농작물에 접근을 감지하고 야생동물이 감지된 경우에만 호랑이 소리 등 야
생동물이 싫어하는 소리와 불빛으로 퇴치하는 기술임', NULL, NULL, '{"classCode": "A010901", "className": "농기계", "classSubCode": "A01090107", "classSubContents": "멧돼지, 고라니 등 야생동물에 의한 농작물 피해 방지를 위하여 전자센서로\n농작물에 접근을 감지하고 야생동물이 감지된 경우에만 호랑이 소리 등 야\n생동물이 싫어하는 소리와 불빛으로 퇴치하는 기술임", "classSubContents2": "○ 멧 돼지 등 야생동물에 의한 농작물 피해가 심각함\n- 1 66억 원 (‘07, 환경부)\n○ 야생동물과 인간이 공존할 수 있는 친환경 야생동물 퇴치기술 개발이\n필요함\n○ 야생동물 퇴치시설로 공급 중인 철재펜스는 효과는 우수하지만 설치비\n가 고가(400만원/1ha)이고 전기울타리는 설치가 편리하지만 제초작업 등\n관리가 어려워 새로운 방식의 야생동물 퇴치기술 개발 필요", "classSubHtml": "A01090107.html", "classSubIdx": "225", "classSubMaster": "농업연구사 강태경 ☎ 031-290-1872", "classSubMovieUrl": null, "classSubPdf": "A01090107.pdf", "classSubTitle": "야생동물 퇴치장치", "classSubUse": "Y", "regDate": "2010-04-19 16:10:35.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('203', '생명공학기술 이용 콩모자이크병 저항성 신품종‘신강’개발', '신강콩은 콩모자이크바이러스병 저항성을 증진하고자 MAS(Marker Assist Selection)기법을 이용
하여 단기간에 저항성 유전자를 보유한 계통을 선발 육성한 품종으로 수량성 제고 및 농가소득
에 기여할 것임', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090307", "classSubContents": "신강콩은 콩모자이크바이러스병 저항성을 증진하고자 MAS(Marker Assist Selection)기법을 이용\n하여 단기간에 저항성 유전자를 보유한 계통을 선발 육성한 품종으로 수량성 제고 및 농가소득\n에 기여할 것임", "classSubContents2": "1) 목적\n   ○ 콩 모자이크병 저항성 품종 육성으로 친환경 콩 생산 제고\n   ○ 콩 품질 고급화 및 농약절감으로 인한 농가소득 증대\n\n2) 필요성\n   ○ 콩모자이크병은 약제 방제가 어려워 저항성 품종 육성이 최선의 방제임\n   ○ 저항성 품종 개발 시 전통적 육종방법으로 육종기간이 길고 비용이 많이 소요\n     - 병저항성유전자를 분자표지로 초기에 도입 선발하여 품종 육성을 하고 있음", "classSubHtml": "A01090307.html", "classSubIdx": "203", "classSubMaster": "담당자 : 농업연구관 윤 홍 태 031-290-6750", "classSubMovieUrl": null, "classSubPdf": "A01090307.pdf", "classSubTitle": "생명공학기술 이용 콩모자이크병 저항성 신품종‘신강’개발", "classSubUse": "Y", "regDate": "2009-06-12 15:10:52.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('159', '난황유를 이용한 병충해 방제기술', '채종유 등 식용유를 계란노른자로 유화시켜 만든 난황유의 병해충 방제효과 상승 및 효과지속을 
위한 혼합제형을 개발하고, 난황유에 유황(S)이나 쿠퍼(Cu) 250-500ppm 첨가 혼합하거나 난황유
에 님오일(Azadirachtin 20ppm) 첨가 혼합하여 사용하면 병해충을 효과적으로 관리할 수 있음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090607", "classSubContents": "채종유 등 식용유를 계란노른자로 유화시켜 만든 난황유의 병해충 방제효과 상승 및 효과지속을 \n위한 혼합제형을 개발하고, 난황유에 유황(S)이나 쿠퍼(Cu) 250-500ppm 첨가 혼합하거나 난황유\n에 님오일(Azadirachtin 20ppm) 첨가 혼합하여 사용하면 병해충을 효과적으로 관리할 수 있음", "classSubContents2": "유기농업에 활용 가능한 흰가루병 방제제 개발 및 방제효과 증진을 위한 혼합제 개발\n유기농업에 활용 가능한 총채벌레 방제제 개발 및 방제효과 증진을 위한 혼합제 개발", "classSubHtml": "A01090607.htm", "classSubIdx": "159", "classSubMaster": "담당자 : 농업연구사 박종호 031-290-0556", "classSubMovieUrl": null, "classSubPdf": "A01090607.pdf", "classSubTitle": "난황유를 이용한 병충해 방제기술", "classSubUse": "Y", "regDate": "2009-03-19 19:16:47.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('158', '폐사가축 위생처리 장치', '고온·고압의 스팀방식으로 가열 분쇄하여 폐사가축을 완전멸균처리 장비
처리부산물을 이용한 사료, 비료, 비누생산의 원료 및 퇴비화로 재활용 가능', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090807", "classSubContents": "고온·고압의 스팀방식으로 가열 분쇄하여 폐사가축을 완전멸균처리 장비\n처리부산물을 이용한 사료, 비료, 비누생산의 원료 및 퇴비화로 재활용 가능", "classSubContents2": "일반 폐사축 처리시 막대한 처리비용, 매몰 부지확보 지난, 매몰시 지하수 오염, 매연 등 환경오\n염 문제점 발생\n폐기물관리법에 저촉되는 일반 동물사체는 소각이나 관리형 매립시설에만 매몰해야 하는 관련법\n규 준수가 어려움\n폐사축의 처리시 발생되는 부산물의 재활용 가능 및 유지관리 비용이 경제적인 직접가열식 동물\n사체 처리장치 개발이 필요함", "classSubHtml": "A01090807.html", "classSubIdx": "158", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090807.pdf", "classSubTitle": "폐사가축 위생처리 장치", "classSubUse": "Y", "regDate": "2009-03-19 19:15:59.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('129', '로열티 대응 황색계 참다래 ‘한라골드’ 육성 및 보급', '1997년에 교배하여 육성된 조생종 황색과육품종으로 과실모양이 좋고, 수확기가 ‘제시골드’ 보
다 약 10일, 뉴질랜드의 ‘제스프리골드’보다 약 30일 빠른 품종임', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090407", "classSubContents": "1997년에 교배하여 육성된 조생종 황색과육품종으로 과실모양이 좋고, 수확기가 ‘제시골드’ 보\n다 약 10일, 뉴질랜드의 ‘제스프리골드’보다 약 30일 빠른 품종임", "classSubContents2": "최근 웰빙문화 확산으로 참다래 소비가 증가함에 따라 수입이 크게 증가하고 있음\n- 소비량 : (&#39;02) 21 → (&#39;04) 35 → (&#39;07) 52.3천톤\n- 수입량(자급률) : (&#39;02) 5.1 → (&#39;04) 23.1 → (&#39;07) 34.7천톤(33.6%)\n- 1인당 소비량 :  (&#39;02) 0.4 → (&#39;04)  0.7 → (&#39;07) 1.1kg(160% 증)\n 국내 참다래 생산량과 생산액은 해마다 증가하고 있음\n참다래는 동해피해 위험이 낮은 남부해안지대에 재배가 국한되며 면적은       약 1,000ha 내외\n로 유지되고 있음\n- 3대 주산지(’07성과수) : 전남(424ha), 경남(297ha), 제주(213ha)\n주요 재배품종은 ‘헤이워드’, 수분수는 ‘마츄아’와 ‘토무리’임\n최근 맛있고 먹기 좋은 품종 선호로 황색계 생산량 증가 및 고가에 거래되고       있음\n- 황색계 생산량 : (’07) 1,500 → (’12) 5,500 → (’15) 10,000톤 예상\n- 계통별 소비자가격 변화 : 생산량 증가로 현재와 유사할 것으로 예상   \n   &#8228;녹색계통 : (’08) 4,550 → (’12) 4,000 → (’15) 4,000원/kg\n   &#8228;황색계통 : (’08) 7,900 → (’12) 7,000 → (’15) 7,000원/kg\n\n\n외국품종은 재배 제한 및 로얄티 과다지출로 황색과육 우리품종 육성&#8228;보급        요구되고 있음\n       - 제스프리골드 계약재배 면적 : (&#39;04) 30 ha → (&#39;06) 100 ha\n       - 로열티 : 20년간 매출액의 15%(품종 2.5, 브랜드 12.5)", "classSubHtml": "A01090407.htm", "classSubIdx": "129", "classSubMaster": "담당자 : 국립원예특작과학원 온난화대응농업연구센터 농업연구사  김성철  064-741-2551", "classSubMovieUrl": null, "classSubPdf": "A01090407.pdf", "classSubTitle": "로열티 대응 황색계 참다래 ‘한라골드’ 육성 및 보급", "classSubUse": "Y", "regDate": "2009-03-19 18:29:41.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('245', '땅콩 싹나물의 레스베라트롤 함량을 증대시키는 방법', '땅콩 싹나물을 재배함에 있어 기능성 성분인 레스베라트롤의 함량을 효율적으
로 증가시킬 수 있는 새로운 방법', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090908", "classSubContents": "땅콩 싹나물을 재배함에 있어 기능성 성분인 레스베라트롤의 함량을 효율적으\n로 증가시킬 수 있는 새로운 방법", "classSubContents2": "○ 땅콩 싹나물에서 기능성 물질인인 레스베라트롤이 다량 함유되어 있음이\n확인됨 (종실 0.2 → 싹나물 14.2㎍/g , 종실대비 74배, 적포도주의 24배)\n○ 레스베라트롤은 우리 인체에 항암, 항산화, 피부노화 방지, 주름제거, 미\n백효과 등 여러 가지 다양한 기능성을 가지는 물질로 이 물질을 함유하\n는 식품 소재 발굴로 부가가치 창출 필요\n○ 땅콩 싹나물 재배에서 통상 보다 개선된 방법을 통하여 땅콩 싹나물의\n레스베라트롤(resveratrol)의 함량을 기존보다 효율적으로 높여 땅콩 싹나\n물을 이용한 기능성 식품의 제조를 용이하게 하는 것을 목적으로 함", "classSubHtml": "A01090908.html", "classSubIdx": "245", "classSubMaster": "농업연구관 박장환 055-350-1231", "classSubMovieUrl": null, "classSubPdf": "A01090908.pdf", "classSubTitle": "땅콩 싹나물의 레스베라트롤 함량을 증대시키는 방법", "classSubUse": "Y", "regDate": "2010-04-19 17:52:08.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('227', '트리히드록시벤즈알데히드를 유효성분 치료', '국내 자생 식물인 뱀무에서 분리한 3,4,5-트리히드록시벤즈알데히드는 세포
독성이 없으면서도 혈중 고밀도 콜레스테롤의 증가와 중성지방의 양을 감
소시키며, 동맥경화를 유발하는 동맥평활근 세포의 Matrix metalloproteinase
(MMP) 효소의 활성을 저해함으로써 지질대사의 이상으로 발생되는 고지혈
증 및 동맥경화증과 같은 MMP 과다활성으로 인한 혈관질환의 예방 및 치
료하는 효과를 갖는다. 따라서, 본 발명의 조성물은 고지혈증 및 동맥경화
와 같은 혈관질환의 예방 및 치료의 목적으로 사용할 수 있다.', NULL, NULL, '{"classCode": "A010903", "className": "생명·유전", "classSubCode": "A01090308", "classSubContents": "국내 자생 식물인 뱀무에서 분리한 3,4,5-트리히드록시벤즈알데히드는 세포\n독성이 없으면서도 혈중 고밀도 콜레스테롤의 증가와 중성지방의 양을 감\n소시키며, 동맥경화를 유발하는 동맥평활근 세포의 Matrix metalloproteinase\n(MMP) 효소의 활성을 저해함으로써 지질대사의 이상으로 발생되는 고지혈\n증 및 동맥경화증과 같은 MMP 과다활성으로 인한 혈관질환의 예방 및 치\n료하는 효과를 갖는다. 따라서, 본 발명의 조성물은 고지혈증 및 동맥경화\n와 같은 혈관질환의 예방 및 치료의 목적으로 사용할 수 있다.", "classSubContents2": "○ 현대인은 잦은 인스턴트 음식물 섭취와 육식 위주의 식생활로 혈중 콜\n레스테롤 및 중성지방의 함량이 높아 고지혈증 등 다양한 대사질환을\n가지고 있고, 이로 인해 동맥경화증 등 대사질환성 성인병이 많이 발생\n한다.\n○ 이러한 성인병의 근원인 고지혈증 및 혈관질환 예방용 천연물질의 개발\n을 통해 국민보건의 질을 향상시킬 수 있다.\n○ 본 발명의 목적은 부작용이 없으면서도 혈관내 중성지방의 양을 감소시키\n고 고밀도 콜레스테롤의 농도를 증가시키며, 동맥평활근 세포의 MMP 활\n성을 저해함으로써 고지혈증, 동맥경화증과 같은 대사성 질환의 예방 및\n치료에 유용한 유효성분을 탐색하여 의약품 또는 건강기능성 식품소재를\n개발하는 것이다.", "classSubHtml": "A01090308.html", "classSubIdx": "227", "classSubMaster": "농업연구관 조강진 (031-299-0530)", "classSubMovieUrl": null, "classSubPdf": "A01090308.pdf", "classSubTitle": "트리히드록시벤즈알데히드를 유효성분 치료", "classSubUse": "Y", "regDate": "2010-04-19 16:14:10.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('162', '농작물 바이러스 신속정밀 진단 기술', '바이러스병의 피해로부터 벗어나기 위한 최우선 과제는 바이러스 진단법의
개발이다. 아래에서는 각가지 작물로부터 극소량의 바이러스까지 검출할 수
있는 바이러스 종 특이 프라이머를 이용한 유전자 진단법을 소개하였다.', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090608", "classSubContents": "바이러스병의 피해로부터 벗어나기 위한 최우선 과제는 바이러스 진단법의\n개발이다. 아래에서는 각가지 작물로부터 극소량의 바이러스까지 검출할 수\n있는 바이러스 종 특이 프라이머를 이용한 유전자 진단법을 소개하였다.", "classSubContents2": "고품질 농산물의 안정적 생산에 있어서 바이러스병은 농업인이 해결하기\n힘든 가장 큰 애로사항임\n바이러스병은 현재까지도 치료법이 개발되지 못하고 있어 진단과 예방이\n최선의 방제대책임\n대부분의 작물에서 바이러스에 감염되지 않은 식물체(종자, 영양번식체,\n유묘 등)를 사용하여 농사를 지을 경우 바이러스병의 피해를 회피할 수\n있음\n바이러스 정밀진단법의 개발과 이용으로 농업인에게 제공되는 종자, 영\n양번식체, 유묘 등을 바이러스 무병상태로 관리한다면 고품질 농산물의\n안정적 생산과 차별화된 품질의 농산물 생산이 가능함\n농업시장의 개방과 함께 외국으로부터 다양한 식물체의 도입으로 각가지\n병원체와 해충의 유입으로 큰 사회적 문제를 야기하고 있음\n철저한 국가 검역과 무병식물체 생산을 위하여 저밀도의 바이러스까지\n검출할 수 있는 고감도의 바이러스 진단법의 개발이 필요함", "classSubHtml": "A01090608.html", "classSubIdx": "162", "classSubMaster": "담당자 : 농업연구사 이수헌 031-290-0432", "classSubMovieUrl": null, "classSubPdf": "A01090608.pdf", "classSubTitle": "농작물 바이러스 신속정밀 진단 기술", "classSubUse": "Y", "regDate": "2009-03-19 19:18:53.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('160', '한국형 부계 계통조성돈「축진듀록」개발', '우리나라의 인공수정센터에는 매년 1,000두 정도의 듀록종은 갱신하고 있으며 많은 두수를 수입
에 의존하고 있다. 농촌진흥청은 종돈 국산화에 기여하고자 10여년동안 계통조성을 실시하여 육
질이 우수한 「축진듀록」 계통돈을 개발하였다.', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090808", "classSubContents": "우리나라의 인공수정센터에는 매년 1,000두 정도의 듀록종은 갱신하고 있으며 많은 두수를 수입\n에 의존하고 있다. 농촌진흥청은 종돈 국산화에 기여하고자 10여년동안 계통조성을 실시하여 육\n질이 우수한 「축진듀록」 계통돈을 개발하였다.", "classSubContents2": "우리나라의 비육돈 생산방식은 대요크샤와 랜드레이스 사이의 교잡종 암컷에 듀록 수컷을 교배시\n켜 비육돈을 생산하는 전형적인 3품종 교배방법을 사용함\n듀록종은 수컷위주로 거래가 이루어지기 때문에 사업성이 낮아 일반적으로 육종돈군 보유를 꺼림\n   - 매년 수퇘지 수입두수의 65% 정도가 듀록종이 차지함\n듀록종은 전국 인공수정센터의 70%를 차지하고 있고 비육돈 생산에서 기여율이 50%가 될 정도로 \n중요한 품종임\n우리나라 국민의 식습관은 구이문화가 발달되어 있어 저지방 부위보다는 삼겹살 부위와 같이 지\n방함량이 많은 부위를 선호함\n성장 및 근내지방과 같은 육질이 우수한 듀록종을 개발하여 활용함으로 수입돈육과의 차별화가 \n필요함", "classSubHtml": "A01090808.html", "classSubIdx": "160", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090808.pdf", "classSubTitle": "한국형 부계 계통조성돈「축진듀록」개발", "classSubUse": "Y", "regDate": "2009-03-19 19:17:12.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('130', '무 자가불화합성 유전자형 판별 기술', '무는 자가불화합성이라는 현상이 있어서 자기 꽃가루로 교배를 하면 종자가 생기지 않는다. 이러
한 유전현상을 어린 묘 시기에 예측하여 교배육종을 효과적으로 수행할 수 있도록 유전자 분석 
기술을 개발하였다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090408", "classSubContents": "무는 자가불화합성이라는 현상이 있어서 자기 꽃가루로 교배를 하면 종자가 생기지 않는다. 이러\n한 유전현상을 어린 묘 시기에 예측하여 교배육종을 효과적으로 수행할 수 있도록 유전자 분석 \n기술을 개발하였다.", "classSubContents2": "○ 본 기술은 무 자가불화합성에 관여하는 유전자를 판별할 수 있는 DNA 표지인자를 개발하여 \n무 일대잡종 품종육성과정에 이용하기 위한 것이다.\n○ 국내의 주요채소의 품종은 대부분 우수한 양친을 육성한 후 교배하여 생산되는 일대잡종품종\n(F1품종)이며 이러한 일대잡종 종자의 생산을 위해서 인공교배, 자가불화합성, 웅성불임성 등이 \n주로 이용되고 있다. \n○ 무의 일대잡종 잡종 종자 생산을 위해서는 자가불화합성 현상에 대한 정보가 반드시 필요하\n다. 자가불화합성이란 같은 자가불화합성 유전자를 가진 개체간의 수분 및 수정이 이루어지지 않\n는 현상으로 자가수분으로 인한 후대의 약세현상을 회피하기 위한 식물체 고유의 특성이다. 그렇\n지만 이러한 자가불화합성 현상은 꽃이 핀 후 꽃가루를 암술머리에 수분하여야만 알 수 있기 때\n문에 자가불화합성의 판정은 육종과정에서 많은 어려움을 주고 있다. \n○ 무 품종육성자가 자가불화합성 유전자형을 간편하게 알 수 있다면 교배계획을 수립할 때 같\n은 유전자형간의 교배를 피하고 다른 유전자형간의 교배를 확대함으로서 육종비용을 대폭 절감\n할 수 있다\n- 민간육종가에 의하면 비공식적으로 육종비용을 최대 30%까지 절감이 가능하다고 한다\n- 또한, 일대잡종의 생산할 때에도 잡종강세현상을 일으키는 양친의 자가불화합성을 이용하여 채\n종하면 채종의 단가를 줄일 수 있다. 현재 웅성불임성에 비하여 상대적으로 줄어들고 있지만 아\n직도 F1 채종에 자가불화합성을 많이 이용하고 있다.  \n○ 최근 유전자형의 판별에 PCR 기술이 일반적으로 이용하는 추세이기 때문에 자가불화합성에 관\n련된 유전자의 염기서열 정보를 이용하여 유전자형 진단이 가능한 프라이머의 선발 및 판별방법\n을 개발하고자 하였다.  \n○ 이 유전자 분석기술을 이용하면 교배 친의 자가불화합성의 판별에 따른 교배비용 절감과 자식\n종자 채종의 효율을 증진하여 무 품종육성 비용을 낮출 수 있을 것이다.", "classSubHtml": "A01090408.htm", "classSubIdx": "130", "classSubMaster": "담당자 :(직급) 농업연구사 (성명) 김기택 (전화번호) 031-290-6194", "classSubMovieUrl": null, "classSubPdf": "A01090408.pdf", "classSubTitle": "무 자가불화합성 유전자형 판별 기술", "classSubUse": "Y", "regDate": "2009-03-19 18:31:15.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('246', '바이오디젤생산용 원료작물 품종개발', '세계기후협약 실천에 따른 온실가스 배출기준 강화와 에너지고갈 위기에
대한 대책으로 바이오디젤 원료용 조숙, 다수성 유채 품종을 개발함', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090909", "classSubContents": "세계기후협약 실천에 따른 온실가스 배출기준 강화와 에너지고갈 위기에\n대한 대책으로 바이오디젤 원료용 조숙, 다수성 유채 품종을 개발함", "classSubContents2": "○ 국내 바이오디젤 중장기 보급계획에 의거 유채 재배면적 확대\n- 바이오디젤 보급 계획(중기) : 1.0%, 18만㎘(&#39;08) → 3.0%, 54만㎘ (&#39;12)\n- 유채 재배면적 : (’08) 1.5천ha → (’11) 15천ha → (’12) 45천ha\n○ 조숙, 다수성, 올레인산 고함유 유채 1대잡종의 육성 및 보급기술 필요", "classSubHtml": "A01090909.html", "classSubIdx": "246", "classSubMaster": "농업연구관 장영석 061-450-0132", "classSubMovieUrl": null, "classSubPdf": "A01090909.pdf", "classSubTitle": "바이오디젤생산용 원료작물 품종개발", "classSubUse": "Y", "regDate": "2010-04-19 17:57:45.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('164', '당도가 높은 가공용 벼 “단미”(2008)', '우리가 일반적으로 먹는 쌀(현미 기준)은 탄수화물 78%, 단백질 6～7%, 지방 2～3%로 구성되어있
다. 주성분인 탄수화물은 대부분 전분 형태로 존재하는데, 포도당(glucose)과 자당(sucrose)을 
포함하는 유리당이 약 3～4% 수준 함유되어 있다. 개발된 ‘단미’는 일반품종과는 달리 벼의 성
숙기에 전분축적이 적은 반면 물에 쉽게 녹고 소화율이 높은 유리당의 축적이 높은(21.4%) 당질
미로서 현미의 직접 이용 및 가공이용성이 큼', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090609", "classSubContents": "우리가 일반적으로 먹는 쌀(현미 기준)은 탄수화물 78%, 단백질 6～7%, 지방 2～3%로 구성되어있\n다. 주성분인 탄수화물은 대부분 전분 형태로 존재하는데, 포도당(glucose)과 자당(sucrose)을 \n포함하는 유리당이 약 3～4% 수준 함유되어 있다. 개발된 ‘단미’는 일반품종과는 달리 벼의 성\n숙기에 전분축적이 적은 반면 물에 쉽게 녹고 소화율이 높은 유리당의 축적이 높은(21.4%) 당질\n미로서 현미의 직접 이용 및 가공이용성이 큼", "classSubContents2": "쌀의 소비확대와 부가가치를 높이고, 소비자들의 다양한 소비성향에 부응할 수 있는 특수용도 \n쌀 개발의 필요성이 증가\n쌀도 미각적 기호성 뿐만 아니라 시각 또는 영양적 품질도 함께 요구되고 있으며, 특히 물에 쉽\n게 녹고 소화율이 높은 고에너지원 및 천연 식품첨가물로도 이용가능성이 큰 품종의 개발이 필요\n함.", "classSubHtml": "A01090609.html", "classSubIdx": "164", "classSubMaster": "담당자 : 농업연구사 송유천 055-350-1165", "classSubMovieUrl": null, "classSubPdf": "A01090609.pdf", "classSubTitle": "당도가 높은 가공용 벼 “단미”(2008)", "classSubUse": "Y", "regDate": "2009-03-19 19:19:45.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('161', '지열이용 돈사 냉&#8228;난방 시스템 개발', '지하수의 신재생에너지인 지열[여름철(10～15℃), 겨울철(20～25℃)]을 이용하여 축사를 냉난방
하는 시스템임
    - 지열히트펌프를 이용하여 여름철에는 차가운 지하수 열을 응축하여 냉방에 활용하고, 겨울
철에는 따뜻한 지하수 열을 응축하여 난방에 이용', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090809", "classSubContents": "지하수의 신재생에너지인 지열[여름철(10～15℃), 겨울철(20～25℃)]을 이용하여 축사를 냉난방\n하는 시스템임\n    - 지열히트펌프를 이용하여 여름철에는 차가운 지하수 열을 응축하여 냉방에 활용하고, 겨울\n철에는 따뜻한 지하수 열을 응축하여 난방에 이용", "classSubContents2": "국내 축사형태는 주로 개방식으로 단열시설이 미비하여 에너지 다소비형으로 사육환경이 불량하\n고 연료비가 많이 소요됨\n    - 개방식돈사 연료비 소비량 : 7,750천원/년(2,000두 기준)\n      * 농업용 면세유 : 사용금액의 45% 정도 지원하고 있으나 지원량 부족\n돈사 에너지 손실 방지를 위한 밀폐로 육성돈의 만성소모성질환 다발\n    - 겨울철에는 연료비를 절감하기 위하여 최대한 밀폐하여 사육환경이 열악하고 여름철에는 \n돈사 내부온도가 27℃ 이상으로 상승하여 고온스트레스를 받아 사육환경 불량에 따른 만성소모\n성 질환 발생\n화석연료 고갈 등 국제환경규제 강화로 대체에너지 개발 필요성 증대\n발리기후변화협약으로 지구온실가스 규제가 강화될 전망이나 대체에너지는 이산화탄소 미배출로 \n온실가스 저감 및 에너지문제 동시 해결이 가능함\n정부의 저탄소 녹색성장에 대한 국가비전 제시로 축산부문에서도 지열에너지 등 대체에너지 이\n용 확대 필요\n국내 여건에서는 지열 히트펌프시스템이 축사 냉&#8228;난방용 대체에너지로 가장 적용성이 높음\n지열 이용 축사 냉난방시 여름철에 고온스트레스를 완화해주고 겨울철에 지속적인 온풍 공급으\n로 축사환경을 개선할 수 있음", "classSubHtml": "A01090809.html", "classSubIdx": "161", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090809.pdf", "classSubTitle": "지열이용 돈사 냉&#8228;난방 시스템 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:18:15.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('131', '무인 병해충 예찰 시스템', '무인 해충발생 감시 장비를 활용하여 과수원에서 발생하는 해충의 발생밀도에
따라 방제 경보를 농가에 전송, 적절한 농약 살포시기를 결정해줌으로써 친
환경 농상물 생산과 약제살포 횟수를 절감할 수 있다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090409", "classSubContents": "무인 해충발생 감시 장비를 활용하여 과수원에서 발생하는 해충의 발생밀도에\n따라 방제 경보를 농가에 전송, 적절한 농약 살포시기를 결정해줌으로써 친\n환경 농상물 생산과 약제살포 횟수를 절감할 수 있다.", "classSubContents2": "정밀하고 간편한 발생예측 및 방제경보 시스템 필요\n- u-IT 기술을 활용한 사과 해충예찰 → 맞춤형 기술제공 체계구축\n무인 해충발생 감시 장비를 활용, 방제효율 향상 및 약제 살포 횟수 절감\n- 연간 농약살포 횟수 : (’07) 10.2 → (’12) 7～9회", "classSubHtml": "A01090409.htm", "classSubIdx": "131", "classSubMaster": "담당자 : 농업연구사 이동혁(054-380-3170)", "classSubMovieUrl": null, "classSubPdf": "A01090409.pdf", "classSubTitle": "무인 병해충 예찰 시스템", "classSubUse": "Y", "regDate": "2009-03-19 18:32:23.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('274', '수출형 버섯 신품종, 팽이 ‘백아’와 만가닥버섯 ‘해미’', '팽 이 신품종 ‘백아’ 는 세계에서 두 번째로 개발된 국내순수 백색품종으
로 일본품종과 대등한 품질을 자랑하며 로얄티절감이 기대되며 만가닥버섯
신품종 ‘해미&#39;는 팽이와 새송이 일변의 수출시장에 차세대 수출 유망 품종
으로 식미감이 뛰어난 버섯임
2. 기술개발 목적 및 필요성', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090910", "classSubContents": "팽 이 신품종 ‘백아’ 는 세계에서 두 번째로 개발된 국내순수 백색품종으\n로 일본품종과 대등한 품질을 자랑하며 로얄티절감이 기대되며 만가닥버섯\n신품종 ‘해미&#39;는 팽이와 새송이 일변의 수출시장에 차세대 수출 유망 품종\n으로 식미감이 뛰어난 버섯임\n2. 기술개발 목적 및 필요성", "classSubContents2": "○ UP OV 가입과 FTA 체결에 따른 품종의 국제분쟁 가능성 증대\n- 버 섯로 열티 추정액 : (’11) 78.3 → (‘12) 90.3억원\n○ 팽 이, 느타리 등 수출 및 외국 품종 대체형 품종 육성 시급", "classSubHtml": "A01090910.html", "classSubIdx": "274", "classSubMaster": "농업연구사 장갑열 031)290-0373", "classSubMovieUrl": null, "classSubPdf": "A01090910.pdf", "classSubTitle": "수출형 버섯 신품종, 팽이 ‘백아’와 만가닥버섯 ‘해미’", "classSubUse": "Y", "regDate": "2010-04-20 09:23:29.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('166', '메주(발효콩)으로부터 항산화활성이 높은 기능성 펩타이드 분리', '전통 발효식품인 청국장에서 항산화 활성 효과가 높은 펩타이드 분리하여 건강에 유익한 기능성 
식품소재로 개발하여 국산콩 소비 촉진 및 자급률 향상을 위한 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090610", "classSubContents": "전통 발효식품인 청국장에서 항산화 활성 효과가 높은 펩타이드 분리하여 건강에 유익한 기능성 \n식품소재로 개발하여 국산콩 소비 촉진 및 자급률 향상을 위한 기술임", "classSubContents2": "한국의 전통적 식품의 기능성 구명을 위해 생리활성이 있는 펩타이드 분리\n콩 및 발효콩에 함유된 새로운 기능성 성분 동정 및 분리 \n전통 발효식품인 청국장에 존재하는 항산화 펩타이드를 다량으로 분리하는 방법을 개발하여 건\n강 기능성 식품 소재로 이용", "classSubHtml": "A01090610.html", "classSubIdx": "166", "classSubMaster": "담당자 : 농업연구사  김정태  031-290-6762", "classSubMovieUrl": null, "classSubPdf": "A01090610.pdf", "classSubTitle": "메주(발효콩)으로부터 항산화활성이 높은 기능성 펩타이드 분리", "classSubUse": "Y", "regDate": "2009-03-19 19:21:04.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('163', '국내개발 이탈리안 라이그라스 신품종 보급', '추위 및 도복에 강한 만생종 「화산101호」와 조생종 「코윈어리」등 개발 및 보급으로 호밀 대
비 산유량 13% 증가와 농가소득 32% 증가', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090810", "classSubContents": "추위 및 도복에 강한 만생종 「화산101호」와 조생종 「코윈어리」등 개발 및 보급으로 호밀 대\n비 산유량 13% 증가와 농가소득 32% 증가", "classSubContents2": "추위에 강하고 수량이 많은 이탈리안 라이그라스의 재배지역 확대\n   - 대전이남 → 한강이남 전역(1월 최저 평균기온 -5℃ → -9 이상)\n이탈리안 라이그라스 신품종 개발로 수입종자 대체\n   - 종자소요량(’12) 2천톤의 50% 자급시 연간 280만불 외화절감\n사료비 절감을 통한 양질 조사료 확대생산", "classSubHtml": "A01090810.html", "classSubIdx": "163", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090810.pdf", "classSubTitle": "국내개발 이탈리안 라이그라스 신품종 보급", "classSubUse": "Y", "regDate": "2009-03-19 19:19:25.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('132', '반도체 광원  LED의 농업적 이용기술', '반도체 광원인 LED(Light-Emitting Diodes : 빛을 내는 반도체) 광원을  이용하여 잎들깨, 국
화, 딸기의 전조재배시 현재 사용중인 백열전구를  대체하면 전기에너지를 70～80% 절감하고 생
산량과 상품성을 10～20%  높일 수 있으며, 광환경이 열악한 시설재배 작물의 보광재배에 이용하
여 다양한 시설재배 작물의 생산성 및 품질향상, 기능성 증진에 이용할 수 있음.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090410", "classSubContents": "반도체 광원인 LED(Light-Emitting Diodes : 빛을 내는 반도체) 광원을  이용하여 잎들깨, 국\n화, 딸기의 전조재배시 현재 사용중인 백열전구를  대체하면 전기에너지를 70～80% 절감하고 생\n산량과 상품성을 10～20%  높일 수 있으며, 광환경이 열악한 시설재배 작물의 보광재배에 이용하\n여 다양한 시설재배 작물의 생산성 및 품질향상, 기능성 증진에 이용할 수 있음.", "classSubContents2": "백열등 이용 전등조명재배로 농업 전기에너지 과다 소비  \n - 전등조명재배 : 2,864ha (전조 : 2,736 보광 128)\n난방을 위한 다겹피복으로 시설재배 작물의 광 부족 심화\nLED 이용 보광&#8228;전조재배 기술혁신 필요\n - 에너지절감, 농작물 생산성 및 품질향상 신기술 개발 시급", "classSubHtml": "A01090410.htm", "classSubIdx": "132", "classSubMaster": "담당자 : 농업연구사 홍성창 (031-290-0224)", "classSubMovieUrl": null, "classSubPdf": "A01090410.pdf", "classSubTitle": "반도체 광원  LED의 농업적 이용기술", "classSubUse": "Y", "regDate": "2009-03-19 18:33:35.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('275', '약용식물자원 기원정립 및 품종 판별기술 개발', '효능 및 안전성이 중요시되는 한약재의 특성상 오&#8228;남용을 방지하고 정확한
기원의 약용식물을 사용하기 위하여 기원정립 및 판별 기술 개발을 통하여
한약재 유통질서를 확립하고 국민 보건 향상에 기여.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090911", "classSubContents": "효능 및 안전성이 중요시되는 한약재의 특성상 오&#8228;남용을 방지하고 정확한\n기원의 약용식물을 사용하기 위하여 기원정립 및 판별 기술 개발을 통하여\n한약재 유통질서를 확립하고 국민 보건 향상에 기여.", "classSubContents2": "○ 수 입된 한약재의 용도가 불법적으로 식용에서 약용으로 전용되고 기원\n식물 차이에 의한 상이한 한약재 사용 문제가 대두.\n- 식품 으 로 수입하여 한약재로 불법 유통되는 문제가 심각함\n- 식품 으 로 수입하여 한약재로 전용 가능한 수입 약용작물 : 당귀, 구기자, 산\n수유, 천궁 등\n○ 약 용작물의 기원이 한국, 중국, 일본 등 국가간에 상이하여 기원식물 판\n별시스템의 체계적인 정립이 절실함.\n- 당 귀의 경우 Angelica gigas(한국), Angelica acutiloba(일본), Angelica\nsinensis(중국)로 국가간에 기원식물이 다름.\n- 구기 자는 Lycium chinensis(한국), Lycium barbarum(중국)로 기원의 차이", "classSubHtml": "A01090911.html", "classSubIdx": "275", "classSubMaster": "농업연구사 한신희 043)871-5545", "classSubMovieUrl": null, "classSubPdf": "A01090911.pdf", "classSubTitle": "약용식물자원 기원정립 및 품종 판별기술 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:26:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('168', '못자리 없는 벼농사를 실현하는 벼 무논점파 직파재배 기술', '무논(湛水) 직파재배기술은 생산비가 적게 들고 초기생육이 우수하고, 잡초성벼 발생을 방지할 
수 있으며, 수량과 품질에서도 중모기계이앙에 비해서 떨어지지 않아 안정적인 식량공급 기반유
지 및 쌀 산업 경쟁력 향상에 기대됨', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090611", "classSubContents": "무논(湛水) 직파재배기술은 생산비가 적게 들고 초기생육이 우수하고, 잡초성벼 발생을 방지할 \n수 있으며, 수량과 품질에서도 중모기계이앙에 비해서 떨어지지 않아 안정적인 식량공급 기반유\n지 및 쌀 산업 경쟁력 향상에 기대됨", "classSubContents2": "1) 현황\n    직파재배는 ‘06년 5%정도, 기존 보급된 산파 및 줄뿌림 재배기술은 정체\n   ‘07년 FTA대책회의에서 이앙재배 60%, 직파재배 40% 정책전환 필요\n   ‘09년 농가현장 전국시범사업 추진 및 기술지원 컨설팅(54개소)\n  2) 필요성\n    현장 농민의 요구가 이앙모습처럼 작업과정 및 직파재배기술 개발요구\n    벼 생력재배 신기술 개발보급을 농가에서 절실히 요구\n    직파재배시 입모향상 및 도복경감, 강우영향 최소화된 기술 필요", "classSubHtml": "A01090611.html", "classSubIdx": "168", "classSubMaster": "담당자 : 농업연구사 한희석 ☎ 031-290-6825", "classSubMovieUrl": null, "classSubPdf": "A01090611.pdf", "classSubTitle": "못자리 없는 벼농사를 실현하는 벼 무논점파 직파재배 기술", "classSubUse": "Y", "regDate": "2009-03-19 19:22:16.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('165', '한우 및 젖소 교배계획지원 기술 개발', '한우·젖소의 근친교배로 인한 근교퇴화를 방지하고 자손의 능력예측값을 이용하여 개량목표에 
알맞은 씨수소를 선택하여 농가에서 활용하고, 젖소의 경우 근친에 따른 손실액을 표시하여 근친
피해 정도를 제시하였음', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090811", "classSubContents": "한우·젖소의 근친교배로 인한 근교퇴화를 방지하고 자손의 능력예측값을 이용하여 개량목표에 \n알맞은 씨수소를 선택하여 농가에서 활용하고, 젖소의 경우 근친에 따른 손실액을 표시하여 근친\n피해 정도를 제시하였음", "classSubContents2": "농가의 암소개량에 대한 관심 증가와 원하는 송아지 생산을 위한 정액선택의 정보제공 요구가 증\n가하고 있음\n정액추천 및 교배조합별 근친도에 대한 농가민원이 증가함에도 불구하고 이의 계산이 복잡하여 \n단시간 내 민원대응이 어려워 사전에 다양한 교배조합에 따른 근친도 및 자손의 능력 등을 예측\n하여 농가에 제공할 필요성 대두\n특정 씨수소의 정액을 모든 암소에 교배하거나 우수한 정액만 사용할 경우 딸소에 다시 그 정액\n을 수정하여 고도의 근친 유발로 파생되는 경제적 손실 등 문제발생을 제거하기 위함", "classSubHtml": "A01090811.html", "classSubIdx": "165", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090811.pdf", "classSubTitle": "한우 및 젖소 교배계획지원 기술 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:20:50.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('133', '배 장기저장 수출용 ‘만황’ 육성', '가을에 수확한 과실을 오래도록 보관한 후에도 처음 수확한 과실처럼 맛이 좋은 배를 만들어 장
거리 수출 및 초봄에 소비자에게 공급하기 위해 장기 저장이 가능하면서 단맛과 신맛이 조화되
고, 육질이 부드러워 식미가 우수한 황갈색 배 ‘만황’을 육성하게 됨.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090411", "classSubContents": "가을에 수확한 과실을 오래도록 보관한 후에도 처음 수확한 과실처럼 맛이 좋은 배를 만들어 장\n거리 수출 및 초봄에 소비자에게 공급하기 위해 장기 저장이 가능하면서 단맛과 신맛이 조화되\n고, 육질이 부드러워 식미가 우수한 황갈색 배 ‘만황’을 육성하게 됨.", "classSubContents2": "10월 상순에 수확되는 ‘신고’ 배의 재배면적이 전체 배의 81.5%(’07, 과수실태조사)를 차지하\n여 맛좋은 배 과실의 연중 공급에 어려움이 많음\n     - 배 과실의 시장 공급 시기를 확대하기 위해 적정 수확기보다 일찍 수확하거나, 지나친 장\n기 저장에 따른 품질 저하로 배에 대한 소비자들의 부정적 이미지가 점차 커지고 있음\n특히 ‘신고’ 품종은 맛이 단순하여 설 명절 이후에는 식미가 떨어짐\n     - ‘신고’ 품종은 단맛은 있으나 신맛이 적어 장기 저장된 과실은 수확 시기에 느낄 수 있\n는 신선미가 떨어지고, 경우에 따라 이취가 느껴짐\n장기 저장용으로 보급되어 생산중인 ‘추황배’는 저장 후에도 단맛과 신맛이 잘 조화되어 수확\n시의 맛을 잘 간직하고 있는 맛좋은 품종이나 과실 크기가 작아 배 생산자들이 재배를 기피하여 \n생산량이 적음\n장기 저장된 ‘신고’와 ‘추황배’의 단점을 보완하고, 미국이나 유럽 등 원거리에 수출할 수 \n있는 품종에 대한 요구가 증대되어 새로운 저장용 품종을 육성하게 됨", "classSubHtml": "A01090411.html", "classSubIdx": "133", "classSubMaster": "담당자 : 농업연구사 강삼석 (061-330-1541)", "classSubMovieUrl": null, "classSubPdf": "A01090411.pdf", "classSubTitle": "배 장기저장 수출용 ‘만황’ 육성", "classSubUse": "Y", "regDate": "2009-03-19 18:35:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('276', '인삼 유통질서 확립을 위한 판별기술 개발', 'DN A 증폭기(PCR)를 이용하여 인삼 품종들의 DNA, 유전자 증폭에 필요
한 시약들을 반응시켜 인삼이 지닌 고유의 DNA를 증폭시킨 후 품종 간
의 차이를 나타내는 DNA 단편들을 찾아 품종들을 판별하는 기술임.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090912", "classSubContents": "DN A 증폭기(PCR)를 이용하여 인삼 품종들의 DNA, 유전자 증폭에 필요\n한 시약들을 반응시켜 인삼이 지닌 고유의 DNA를 증폭시킨 후 품종 간\n의 차이를 나타내는 DNA 단편들을 찾아 품종들을 판별하는 기술임.", "classSubContents2": "○ 시장 개방으로 인한 외국산의 국내산, 재래종의 품종, 저년근의 고년근 둔갑 우려\n○ 외 국산 불법 유통 및 연근 둔갑 방지 등의 판별기술 개발에 의한 인\n삼의 소비자 신뢰도 향상 필요", "classSubHtml": "A01090912.html", "classSubIdx": "276", "classSubMaster": "농업연구사 방경환 043)871-5534", "classSubMovieUrl": null, "classSubPdf": "A01090912.pdf", "classSubTitle": "인삼 유통질서 확립을 위한 판별기술 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:27:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('170', '분자표지를 이용한 벼 품종 판별', '모든 동식물은 자기 고유의 핵산(DNA)으로 구성된 유전자를 가지며 이 핵산(DNA)으로부터 증폭기
(PCR)를 이용하여 많은 양의 DNA로 증폭시켜 품종 고유의 유전자형을 동정할 수 있는 마커
(marker)조합을 찾아 국내에서 유통되는 벼 품종을 구별하고자 함.', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090612", "classSubContents": "모든 동식물은 자기 고유의 핵산(DNA)으로 구성된 유전자를 가지며 이 핵산(DNA)으로부터 증폭기\n(PCR)를 이용하여 많은 양의 DNA로 증폭시켜 품종 고유의 유전자형을 동정할 수 있는 마커\n(marker)조합을 찾아 국내에서 유통되는 벼 품종을 구별하고자 함.", "classSubContents2": "국내 브랜드쌀은 품종에 관계 없이 혼입 유통됨으로써 상품성 저하\n브랜드쌀의 품질 고급화, 상품성 향상 및 소비자에 대한 신뢰성 구축 긴요\n쌀시장 개방화에 대비하여 국내외 벼품종판별 체계 구축 및 분석방법 개선이 필요", "classSubHtml": "A01090612.html", "classSubIdx": "170", "classSubMaster": "담당자 : 농업연구사 조영찬 031-290-6708", "classSubMovieUrl": null, "classSubPdf": "A01090612.pdf", "classSubTitle": "분자표지를 이용한 벼 품종 판별", "classSubUse": "Y", "regDate": "2009-03-19 19:23:16.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('167', '기능성 우유생산 기술', '웰빙 식생활 및 노령화에 따른 천연 기능강화 우유에 대한 소비자의 관심 급증으로 천연 생리활
성물질 강화 반추가축용 사료 첨가제를 개발하여  젖소에 급여함으로써 소비자 지향 기능성 우
유 생산기술을 개발함', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090812", "classSubContents": "웰빙 식생활 및 노령화에 따른 천연 기능강화 우유에 대한 소비자의 관심 급증으로 천연 생리활\n성물질 강화 반추가축용 사료 첨가제를 개발하여  젖소에 급여함으로써 소비자 지향 기능성 우\n유 생산기술을 개발함", "classSubContents2": "건강기능성 강화 축산물에 대한 관심 증대와 소비자의 요구 증가 추세\n식품의 품질을 개선하기 위하여 천연물 추출물, 지방 및 단백질, 미네랄, 비타민 등 각종 기능\n성 물질들이 이용되고 있으나, 그 효능, 경제성 및 안정성에 대한 검정이 필요함\n현재 출시되는 기능성 우유 중 천연 유래 기능성 우유는 2종(DHA, 콜린 강화)으로 미약한 실정임\n반추가축의 특성상 대부분의 생리활성물질은 미생물에 의해 분해되므로 미생물에 의해 분해되지 \n않고 반추위를 통과할 수 있는 기술이 절실함\n영양적 및 기능적으로 우수한 생리활성물질이 함유된 우유를 생산하여 농가소득 향상 및 소비자 \n건강증진에 기어코자 함", "classSubHtml": "A01090812.html", "classSubIdx": "167", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090812.pdf", "classSubTitle": "기능성 우유생산 기술", "classSubUse": "Y", "regDate": "2009-03-19 19:21:46.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('134', '순환식 수막보온재배 시스템', '순환식 수막시스템은 비닐하우스 지붕면에 뿌린 지하수를 다시 회수하여 차가워진 만큼 원수와 
섞거나 가열한 다음 재활용함으로써 81% 정도의 지하수를 절약할 수 있고 온풍기에 비해 67% 정
도 난방연료를 절감할 수 있는 시스템임', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090412", "classSubContents": "순환식 수막시스템은 비닐하우스 지붕면에 뿌린 지하수를 다시 회수하여 차가워진 만큼 원수와 \n섞거나 가열한 다음 재활용함으로써 81% 정도의 지하수를 절약할 수 있고 온풍기에 비해 67% 정\n도 난방연료를 절감할 수 있는 시스템임", "classSubContents2": "지하수의 열에너지를 활용하여 보온하는 수막재배가 최근 지하수 부족에 의해 더 이상 재배가 곤\n란함에 따라 지하수를 재활용하는 시스템 개발이 필요함\n딸기, 상추, 감자 등의 저온성 작물의 겨울철 무가온재배를 위해서는   수막보온재배 시스템이 \n필수적으로 요구됨", "classSubHtml": "A01090412.html", "classSubIdx": "134", "classSubMaster": "담당자 : 농업연구사 이시영 051-602-2152", "classSubMovieUrl": null, "classSubPdf": "A01090412.pdf", "classSubTitle": "순환식 수막보온재배 시스템", "classSubUse": "Y", "regDate": "2009-03-19 18:36:16.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('277', '토종 약초자원을 이용한 기능성 샐러드 개발', '약 초 고유의 특성과 기능성을 갖는 샐러드를 개발하고자 샐러드에 적합
한 약초를 선발하고, 쓴맛이 강한 약초의 기호성을 높이도록 약초와 잘
어울리는 샐러드용 부재료 선발 및 약초샐러드 레시피 개발', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090913", "classSubContents": "약 초 고유의 특성과 기능성을 갖는 샐러드를 개발하고자 샐러드에 적합\n한 약초를 선발하고, 쓴맛이 강한 약초의 기호성을 높이도록 약초와 잘\n어울리는 샐러드용 부재료 선발 및 약초샐러드 레시피 개발", "classSubContents2": "○ 건 강 추구에 따른 약초자원의 식품 소재화 요구가 증가하고 있음\n○ 신 선편이 농산물 품목이 채소류위주에서 점차 다양화되고 있음\n- 약 용작 물을 이용한 새로운 신선편이 상품 개발 필요", "classSubHtml": "A01090913.html", "classSubIdx": "277", "classSubMaster": "농업연구관 김지강 031) 240-3649", "classSubMovieUrl": null, "classSubPdf": "A01090913.pdf", "classSubTitle": "토종 약초자원을 이용한 기능성 샐러드 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:28:01.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('171', '분자표지를 활용한 모자이크바이러스 저항성 콩 품종 개발', '콩모자이크바이러스(SMV)에 의한 콩의 심각한 수량감소를 방지하기 위해  콩 유전자원에 들어있
는 내병성 유전자를 인공교배를 통해 도입하고 이를 분자표지의 도움을 받아 목표유전자가 도입
된 개체만 선발(MAS)하여 SMV에 강한 신품종(신화, 신강)을 육성함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090613", "classSubContents": "콩모자이크바이러스(SMV)에 의한 콩의 심각한 수량감소를 방지하기 위해  콩 유전자원에 들어있\n는 내병성 유전자를 인공교배를 통해 도입하고 이를 분자표지의 도움을 받아 목표유전자가 도입\n된 개체만 선발(MAS)하여 SMV에 강한 신품종(신화, 신강)을 육성함", "classSubContents2": "콩모자이크바이러스는 콩의 주요 문제 병해중 하나로서 약제 방제의 효과가 크지 않으므로 저항\n성 품종 육성의 필요성이 높음\n유전자에 근접한 분자표지는 특정 형질을 도입하는데 이용할 경우 목표 유전자가 도입된 계통의 \n조기 선발이 가능하여 신품종 육성의 효율을 높일 수 있음", "classSubHtml": "A01090613.html", "classSubIdx": "171", "classSubMaster": "담당자 : 농업연구관 윤홍태 031-290-6750", "classSubMovieUrl": null, "classSubPdf": "A01090613.pdf", "classSubTitle": "분자표지를 활용한 모자이크바이러스 저항성 콩 품종 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:24:17.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('169', '사료용 옥수수 검은줄오갈병 종합방제기술', '사료용 옥수수 검은줄오갈병 지역별 발병실태, 매개체인 벼 애멸구 발생 양상 조사, 내병성 옥수
수 품종 선발 및 파종시기 조절 등 종합적인 방제기술', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090813", "classSubContents": "사료용 옥수수 검은줄오갈병 지역별 발병실태, 매개체인 벼 애멸구 발생 양상 조사, 내병성 옥수\n수 품종 선발 및 파종시기 조절 등 종합적인 방제기술", "classSubContents2": "최근 사료용 옥수수 검은줄오갈병 발생이 심하여 이에 대한 방제기술 확립이 시급히 요구됨\n검은줄오갈병 저항성 품종 선발, 파종시기 조절 등 종합적인 방제기술 개발 필요", "classSubHtml": "A01090813.html", "classSubIdx": "169", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090813.pdf", "classSubTitle": "사료용 옥수수 검은줄오갈병 종합방제기술", "classSubUse": "Y", "regDate": "2009-03-19 19:23:06.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('135', '식물의 환경 정화 기능성 구명', '화훼식물의 새집증후군의 원인물질인 포름알데히드, 톨루엔 등의 VOC(휘발성유기화합물)의 흡수
에 의한 제거와 음이온 등의 방출 효과를 구명하였으며, 이러한 환경정화 기능에 따라 실내 생활
공간별로 배치하였다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090413", "classSubContents": "화훼식물의 새집증후군의 원인물질인 포름알데히드, 톨루엔 등의 VOC(휘발성유기화합물)의 흡수\n에 의한 제거와 음이온 등의 방출 효과를 구명하였으며, 이러한 환경정화 기능에 따라 실내 생활\n공간별로 배치하였다.", "classSubContents2": "공기정화식물은 포름알데히드를 제거하여 새집증후군을 완화함 \n실내식물의 효과적인 기능성 활용에 따른 신수요 창출 \n실내식물의 공기정화 효율 극대화\n새집증후군은 새집에 사는 사람의 94.1%가 증상을 느꼈으며, 대처방법으로 공기정화식물을 들여\n놓는 경우가 43.1%임(&#39;01, 연세대)", "classSubHtml": "A01090413.html", "classSubIdx": "135", "classSubMaster": "담당자 : 연구사, 김광진, 031-290-6162", "classSubMovieUrl": null, "classSubPdf": "A01090413.pdf", "classSubTitle": "식물의 환경 정화 기능성 구명", "classSubUse": "Y", "regDate": "2009-03-19 18:38:08.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('278', '지치로부터 관절건강 개선 소재 개발', '붉은 색소성분이 많이 함유된 지치 추출물이 류마티스 관절염이 있는 실험
쥐의 염증으로 인한 부종을 64% 경감시켰다. 또, 지치 추출물은 관절염으로
인한 뼈 조직의 파괴를 막아주는 효과가 있음을 동물실험으로 확인하였음.', NULL, NULL, '{"classCode": "A010909", "className": "특용작물", "classSubCode": "A01090914", "classSubContents": "붉은 색소성분이 많이 함유된 지치 추출물이 류마티스 관절염이 있는 실험\n쥐의 염증으로 인한 부종을 64% 경감시켰다. 또, 지치 추출물은 관절염으로\n인한 뼈 조직의 파괴를 막아주는 효과가 있음을 동물실험으로 확인하였음.", "classSubContents2": "○ 류 마티스 관절염 전세계 시장규모 5조원, 국내 시장 4000억원(‘05) 형성\n○ 류 마티스 관절은 20-30대 연령에서도 발생, 심각한 질환임\n○ 기 존의 항염증 등의 치료제는 위장장애 등의 부작용 사례 많음\n○ 국 내기술로 부작용이 경감된 천연물 유래 항관절염 소재 개발 중요", "classSubHtml": "A01090914.html", "classSubIdx": "278", "classSubMaster": "농업연구사 김금숙 043)871-5582", "classSubMovieUrl": null, "classSubPdf": "A01090914.pdf", "classSubTitle": "지치로부터 관절건강 개선 소재 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:28:48.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('173', '산물벼 이용 현미 및 백미 단백질함량 측정 방법 개발', '산물벼의 현미 및 백미 단백질함량을 간편하고 신속하게 평가하고자 근적외선 분광분석법을 이용
하여 객관적인 측정방법 개발로 생산자 및 소비자간의 신뢰도을 제고하고자 하는 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090614", "classSubContents": "산물벼의 현미 및 백미 단백질함량을 간편하고 신속하게 평가하고자 근적외선 분광분석법을 이용\n하여 객관적인 측정방법 개발로 생산자 및 소비자간의 신뢰도을 제고하고자 하는 기술임", "classSubContents2": "기존의 화학분석방법은 고가의 장비와 숙련된 인력 및 소요 경비, 시간의 부담이 심각하고 시료\n의 손실이 있다는 점에서 실용화 가능성이 낮고, 또한 기존의 근적외 분광분석기를 이용한 백미 \n검량식의 경우 건조와 도정을 거쳐 한정된 수분범위의 백미 상태로 시료를 가공한 후에만 성분 \n분석이 가능하다는 한계가 있음\n이를 극복하기 위해 다양한 수분함량과 품종의 산물벼를 수집, 조제하여 근적외선 스펙트럼을 획\n득하고 해당 시료의 현미 및 백미 단백질 함량을 습식으로 분석하여 이를 계량분석화학\n(Chemometrics)을 통해 산물벼를 바로 이용할 수 있는 방법 필요", "classSubHtml": "A01090614.html", "classSubIdx": "173", "classSubMaster": "담당자 : 농업연구사 천아름 031-290-6720", "classSubMovieUrl": null, "classSubPdf": "A01090614.pdf", "classSubTitle": "산물벼 이용 현미 및 백미 단백질함량 측정 방법 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:25:18.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('172', '이동식 액비성분 분석기', '가축분뇨 액비의 성분분석은 실험실에서 화학적 분석법에 의해서 이루어지고 있으며, 많은 시간
(1～2일)과 노동력이 소요된다. 따라서 액비의 비료성분을 단시간 내에 신속하고 정확하게 분석
할 수 있는 방법이 요구되고 있으며, 그 중 한가지 방법이 비파괴분석법인 근적외선(NIR) 분광분
석법이라 할 수 있음. 근적외선은 가시광선과 중적외선 사이에 존재하는 빛으로 700～2,500nm 사
이에 존재함
근적외선분광법은 정량 및 정성분석에 모두 사용할 수 있는데, 측정시료의 투과도 및 반사도를 
가지고 시료에 조사된 빛의 산란효과를 보정한 후 회귀분석을 실시하여 검량선을 유도해 내고 이
를 검증하여 적용하는 방식임
근적외선을 이용한 시료분석 장점은 비파괴분석, 신속한 분석(45초이내), 실시간 분석, 다성분 
동시분석, 고도의 정확도 및 기체나 액체, 고체 상태로 분석할 수 있음', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090814", "classSubContents": "가축분뇨 액비의 성분분석은 실험실에서 화학적 분석법에 의해서 이루어지고 있으며, 많은 시간\n(1～2일)과 노동력이 소요된다. 따라서 액비의 비료성분을 단시간 내에 신속하고 정확하게 분석\n할 수 있는 방법이 요구되고 있으며, 그 중 한가지 방법이 비파괴분석법인 근적외선(NIR) 분광분\n석법이라 할 수 있음. 근적외선은 가시광선과 중적외선 사이에 존재하는 빛으로 700～2,500nm 사\n이에 존재함\n근적외선분광법은 정량 및 정성분석에 모두 사용할 수 있는데, 측정시료의 투과도 및 반사도를 \n가지고 시료에 조사된 빛의 산란효과를 보정한 후 회귀분석을 실시하여 검량선을 유도해 내고 이\n를 검증하여 적용하는 방식임\n근적외선을 이용한 시료분석 장점은 비파괴분석, 신속한 분석(45초이내), 실시간 분석, 다성분 \n동시분석, 고도의 정확도 및 기체나 액체, 고체 상태로 분석할 수 있음", "classSubContents2": "가축분뇨 액비를 농경지에 이용하려고 할 경우 비료성분 분석이 필수적임\n현재 가축분뇨 액비의 비료성분 분석은 실험실에서 화학적 분석법에 의해서 이루어지고 있어 많\n은 시간(1～2일)과 노동력이 소요될 뿐만 아니라 동시에 여러 성분의 분석이 불가능함\n액비 내 비료성분을 신속하고 정확하게 분석할 수 있는 기기 개발 필요", "classSubHtml": "A01090814.html", "classSubIdx": "172", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090814.pdf", "classSubTitle": "이동식 액비성분 분석기", "classSubUse": "Y", "regDate": "2009-03-19 19:24:30.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('136', '신수요 창출이 가능한 녹황색 사과 품종 ‘그린볼’', '농촌진흥청(RDA)에서는 기존의 붉은색 사과와 차별화된 색깔의 녹황색
신품종 ‘그린볼’을 육성하였다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090414", "classSubContents": "농촌진흥청(RDA)에서는 기존의 붉은색 사과와 차별화된 색깔의 녹황색\n신품종 ‘그린볼’을 육성하였다.", "classSubContents2": "우리나라에서 생산되는 사과는 대부분 붉은색임\n붉은색 일변도의 과피색에서 다양한 과피색의 사과 품종개발이 필요함", "classSubHtml": "A01090414.htm", "classSubIdx": "136", "classSubMaster": "담당자 : 농업연구사 권순일(054-380-3135)", "classSubMovieUrl": null, "classSubPdf": "A01090414.pdf", "classSubTitle": "신수요 창출이 가능한 녹황색 사과 품종 ‘그린볼’", "classSubUse": "Y", "regDate": "2009-03-19 18:39:29.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('176', '신개념 새로운 형태의 식물바이러스 유전자 분리키트 개발', '기존 식물바이러스 진단기술 개발에 비해 역전사중합연쇄반응(RT-PCR)을 이용하여 식물바이러
스 진단에 특이적으로 반응하는 유전자만을 선택적으로 분리할 수 있어 진단에 활용할 경우 효율
성과 정확성이 높은 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090615", "classSubContents": "기존 식물바이러스 진단기술 개발에 비해 역전사중합연쇄반응(RT-PCR)을 이용하여 식물바이러\n스 진단에 특이적으로 반응하는 유전자만을 선택적으로 분리할 수 있어 진단에 활용할 경우 효율\n성과 정확성이 높은 기술임", "classSubContents2": "식물바이러스 관련 유전자를 진단하고자 많은 방법이 개발되고 있으나 개발시간과 노력이 많이 \n필요함\n기존의 방법으로 진단할 경우 진단에 필요한 유전자 이외의 많은 양의 식물체 유전자로 인해 거\n짓반응이 나타나거나 감염주에서 음성반응이 나타나는 경우가 발생하여 재현성이 떨어졌음\n식물바이러스 진단에 특이하게 반응하는 유전자만을 분리 이용하여  정밀성과 효율성 향상 필요", "classSubHtml": "A01090615.html", "classSubIdx": "176", "classSubMaster": "담당자 : 농업연구사 이영규 ☎ 033-330-1941", "classSubMovieUrl": null, "classSubPdf": "A01090615.pdf", "classSubTitle": "신개념 새로운 형태의 식물바이러스 유전자 분리키트 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:26:32.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('174', '목장형 자연치즈 제조기술', '국내 자연치즈 산업 활성화로 잉여원유의 효율적 이용과 농가의 새로운 소득원 개발을 위해 목장
형 자연치즈(곰팡이 숙성치즈류와 신선카테지치즈) 제조기술을 개발 보급하고자 함', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090815", "classSubContents": "국내 자연치즈 산업 활성화로 잉여원유의 효율적 이용과 농가의 새로운 소득원 개발을 위해 목장\n형 자연치즈(곰팡이 숙성치즈류와 신선카테지치즈) 제조기술을 개발 보급하고자 함", "classSubContents2": "국내 자연치즈류 연간 소비량은 4만여톤으로 이중 27천여톤이 수입에 의존하고 있으나 이를 국내\n치즈로 대체시 수입 대체효과\n    - 연간 자연치즈 소비량 : 40,570톤(국내생산 12,959톤, 수입 27,611톤)\n소비자의 기호에 맞는 다양한 치즈 개발보급으로 우유 소비촉진 및 소비로 국민건강 증진에 기여\n곰팡이 숙성치즈류 및 신선카테지 치즈제조 기술개발 보급으로 수입산 치즈를 이용한 가공치즈 \n위주에서 자연치즈 생산소비로 활성화", "classSubHtml": "A01090815.html", "classSubIdx": "174", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090815.pdf", "classSubTitle": "목장형 자연치즈 제조기술", "classSubUse": "Y", "regDate": "2009-03-19 19:25:25.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('137', '염색체 상호전좌를 이용한 씨적은 수박품종 육성', '수박은 300～500립 정도의 씨가 있어 먹을 때 불편하다. 우장춘 박사의 3배체 씨없는 수박 등이 
개발되었으나, 국내 재배환경에 불안정한 단점이 있다. 농촌진흥청(RDA)에서는 비상동 염색체간
에 부분 교환되는 상호전좌기술을 이용하여 일반 수박의 1/4수준으로 씨가 적으며 안정적인 재배
가 가능한 품종을 개발하였다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090415", "classSubContents": "수박은 300～500립 정도의 씨가 있어 먹을 때 불편하다. 우장춘 박사의 3배체 씨없는 수박 등이 \n개발되었으나, 국내 재배환경에 불안정한 단점이 있다. 농촌진흥청(RDA)에서는 비상동 염색체간\n에 부분 교환되는 상호전좌기술을 이용하여 일반 수박의 1/4수준으로 씨가 적으며 안정적인 재배\n가 가능한 품종을 개발하였다.", "classSubContents2": "수박은 과당 종자수가 너무 많아(300～500립) 멱을 때 불편함\n씨 없는 3배체 수박은 우리나라의 재배환경에 불안정하여 공동과 등 각종 생리장해 발생 가능성\n이 높음\n염색체 상호전좌를 이용한 씨 적은 수박은 우리나라의 재배환경에 안정적이며 품질이 우수함", "classSubHtml": "A01090415.htm", "classSubIdx": "137", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090415.pdf", "classSubTitle": "염색체 상호전좌를 이용한 씨적은 수박품종 육성", "classSubUse": "Y", "regDate": "2009-03-19 18:41:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('177', '밥 원료미의 유전자 간편 추출방법 개발', '밥에서 양질의 유전자를 재현성이 높으며 안정적으로 추출하는 방법개발로 밥 원료미의 품종 판
별에 이용할 수 있는 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090616", "classSubContents": "밥에서 양질의 유전자를 재현성이 높으며 안정적으로 추출하는 방법개발로 밥 원료미의 품종 판\n별에 이용할 수 있는 기술임", "classSubContents2": "국내 시장에 유통되는 브랜드쌀에 대한 소비자의 신뢰 확보와 품질 고급화를 위하여 2005년부터\n는 포장양곡표시기준을 준수하여야 하며, 2007년부터는 품종 표시 사항에 대한 규제가 시작됨. \n우리나라에서 쌀은 강화되는 농산물 표시 관련제도에 대응하여 품종 확인뿐만 아니라 앞으로는 \n식당 등 소비처에서도 원산지를 표시해야 됨에 따라 쌀 뿐만 아니라 가공된 식품에서의 품종판별\n이 필요\n따라서 본 기술은 호화전분 상태인 밥에서 양질의 유전자를 안정적으로 추출하는 방법을 확립하\n여 유통 및 소비단계의 밥 상태에서 원료미 품종판별에 필요한 기술임", "classSubHtml": "A01090616.html", "classSubIdx": "177", "classSubMaster": "담당자 : 농업연구사 송 진 031-299-0511", "classSubMovieUrl": null, "classSubPdf": "A01090616.pdf", "classSubTitle": "밥 원료미의 유전자 간편 추출방법 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:27:43.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('175', '닭종자 순수화 복원 및 실용화 기술', '국립축산과학원은 1967년도 이후 여러 경로를 통해 국&#8228;내외 닭종자를 수집하고 품종을 보존하
는 동시에 계통교배로 품종복원 및 토착화 완료(5품종 9계통)
품종 보존된 닭종자를 모본으로 3～4원 교배법을 이용하여 신품종   종계를 작출하고 기술이전
을 통하여 종계농가에 보급
기술이전을 받은 종계농가에서 토종닭 실용계를 생산하여 일반 토종닭사육농가에 보급
일반농가는 종계 농가로부터 토종닭 실용계를 분양받아 10～12주 사육 시장에 출하
우리맛닭”은 품종복원 및 토착화된 종자를 이용해 3원교배 방식으로 개발된 성장이 빠르고 육질
이 우수한 고품질 토종닭임', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090816", "classSubContents": "국립축산과학원은 1967년도 이후 여러 경로를 통해 국&#8228;내외 닭종자를 수집하고 품종을 보존하\n는 동시에 계통교배로 품종복원 및 토착화 완료(5품종 9계통)\n품종 보존된 닭종자를 모본으로 3～4원 교배법을 이용하여 신품종   종계를 작출하고 기술이전\n을 통하여 종계농가에 보급\n기술이전을 받은 종계농가에서 토종닭 실용계를 생산하여 일반 토종닭사육농가에 보급\n일반농가는 종계 농가로부터 토종닭 실용계를 분양받아 10～12주 사육 시장에 출하\n우리맛닭”은 품종복원 및 토착화된 종자를 이용해 3원교배 방식으로 개발된 성장이 빠르고 육질\n이 우수한 고품질 토종닭임", "classSubContents2": "품종복원 및 토착화된 순계의 능력개량과 순수도 제고\n순계를 모본으로 차별화된 맞춤형 산업용 토종닭 작출(우리맛닭)\n토종닭과 지역부존자원을 활용을 연계하는 사육모델 개발", "classSubHtml": "A01090816.html", "classSubIdx": "175", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090816.pdf", "classSubTitle": "닭종자 순수화 복원 및 실용화 기술", "classSubUse": "Y", "regDate": "2009-03-19 19:26:25.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('138', '원예작물 저온 저장중 선도예측 시스템', '저온저장고의 온도, 습도, 특정 가스축적에 의한 원예작물의 장해발생 예
측 및 중량감소율 예측을 통한 유&#8228;무선 재해경보시스템을 개발하여 저장
시 원예작물 손실률 경감을 최소화 함으로써 소비자가 원하는 질 좋은 원
예산물 공급을 위한 기반을 조성한다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090416", "classSubContents": "저온저장고의 온도, 습도, 특정 가스축적에 의한 원예작물의 장해발생 예\n측 및 중량감소율 예측을 통한 유&#8228;무선 재해경보시스템을 개발하여 저장\n시 원예작물 손실률 경감을 최소화 함으로써 소비자가 원하는 질 좋은 원\n예산물 공급을 위한 기반을 조성한다.", "classSubContents2": "종래의 재배시설이나 저온저장고의 온도, 습도변화에 따르는 경보발생\n장치 및 온, 습도 조절장치가 설치되어 활용되고 있으나, 이는 단순한\n온도, 습도 설정치에 대한 경보나 조절기능이 있을 뿐이다.\n따라서 단순한 경보장치 및 온, 습도 조절장치가 아닌 원예작물의 저\n온 저장시에 온도, 습도 및 특정 가스농도 축적에 의해 발생하는 내부\n갈변, 과심갈변, 탈피과 등의 생리장해 발생 및 저장작물의 중량감소율\n을 예측하고 이를 제어할 수 있는 시스템으로 원예작물의 엄격한 품질\n관리 및 저온저장고의 시설관리를 보다 효과적으로 하고자 함.", "classSubHtml": "A01090416.html", "classSubIdx": "138", "classSubMaster": "담당자 : 농업연구사 홍윤표 (031-240-3688)", "classSubMovieUrl": null, "classSubPdf": "A01090416.pdf", "classSubTitle": "원예작물 저온 저장중 선도예측 시스템", "classSubUse": "Y", "regDate": "2009-03-19 18:42:22.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('204', '거봉보다 달콤한 명품포도 흑구슬', '국립원예특작과학원에서 육성한 ‘흑구슬’ 품종은 1988년 골든마스캇(Golden Muscat) 품종에 피
오네(Pione) 품종을 교배하여 2000년에 최종 선발한 우리나라 기후 풍토에 알맞고 양질 다수성
인 대립 포도 품종이다', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090417", "classSubContents": "국립원예특작과학원에서 육성한 ‘흑구슬’ 품종은 1988년 골든마스캇(Golden Muscat) 품종에 피\n오네(Pione) 품종을 교배하여 2000년에 최종 선발한 우리나라 기후 풍토에 알맞고 양질 다수성\n인 대립 포도 품종이다", "classSubContents2": "○ 포도는 지구상에서 가장 많이 재배되는 낙엽과수 중의 하나로서 생식용, 건포도용, \n   양조용 및 주스용 등으로 이용하고 있다\n○ 국내의 포도 산업은 17,660ha에서 연간 33만톤(5,254억원)의 과실을 생산하고 있다. \n   (과수실태조사, 2007)\n○ 농가재배 품종구성이 ‘캠벨얼리(Campbell Early)’ 73.0%, ‘거봉(Kyoho)’ 12.1%로서 \n   이 두 품종이 전체의 약 84%를 차지하고 있어 여름과 가을에 편중되는 홍수출하로 인하여 \n   포도 과실의 가격의 하락으로 농가의 수입이 향상되지 못함과 동시에 소비자의 다양한 \n   기호에 부응하지 못하는 문제점을 야기하고 있다.\n○ 따라서 이러한 문제점을 보완하여 출하기를 연장하고 소비기간을 확대할 수 있는 숙기 및 \n   특성이 다양한 포도 품종 육성이 필요하며, 특히 품질이 우수하고 거봉에 비하여 송이 \n   형성이 양호한 대립계 품종 육성이 필요하다.", "classSubHtml": "A01090417.html", "classSubIdx": "204", "classSubMaster": "담당자: 농업연구사 노정호 031-240-3696", "classSubMovieUrl": null, "classSubPdf": "A01090417.pdf", "classSubTitle": "거봉보다 달콤한 명품포도 흑구슬", "classSubUse": "Y", "regDate": "2009-06-12 15:13:10.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('180', '옥수수수염 수율 및 메이신 함량 증대기술 개발', '옥수수이삭에 실크백(silk bag)을 씌워 수정을 지연시키면 수염이 20cm이상 자라서 옥수수수염 
수확량이 3배 이상 되고, 메이신 함량이 13배 이상 증가하는 기술로 국내에서 최근 옥수수수염차
가 웰빙 건강음료로 각광을 받고 있어 식품 산업에 응용 가능성이 높음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090617", "classSubContents": "옥수수이삭에 실크백(silk bag)을 씌워 수정을 지연시키면 수염이 20cm이상 자라서 옥수수수염 \n수확량이 3배 이상 되고, 메이신 함량이 13배 이상 증가하는 기술로 국내에서 최근 옥수수수염차\n가 웰빙 건강음료로 각광을 받고 있어 식품 산업에 응용 가능성이 높음", "classSubContents2": "옥수수 재배시 부산물로 얻어지는 옥수수수염에는 항산화, 항암활성이 높은 후라보노이드 물질\n인 메이신 다량함유 \n최근 웰빙 건강음료로 옥수수 수염차가 국내에서 각광을 받고 있으며 옥수수 수염에 대한 이용관\n련 시장 규모가 커질 것으로 예상", "classSubHtml": "A01090617.html", "classSubIdx": "180", "classSubMaster": "담당자 : 농업연구사  김정태 031-290-6762", "classSubMovieUrl": null, "classSubPdf": "A01090617.pdf", "classSubTitle": "옥수수수염 수율 및 메이신 함량 증대기술 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:29:20.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('178', '사료비 절감 청보리 사일리지 이용기술', '청보리 사료는 잎과 대는 조사료, 알곡은 배합사료를 대체할 수 있는 사료이며, 단위중량당 사료
가치가 높고 종자를 자급할 수 있음
   - 청보리 재배면적 : (&#39;08) 24.8천ha → (&#39;10) 50 → (&#39;12) 100
적기에 파종하고 호숙초기에서 황숙기에 원형곤포로 조제하여 한우와 젖소에 급여
청보리는 우리 종자로 우리 땅에서 재배 및 가축에 이용하는 자연순환형 모델을 구축할 있음', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090817", "classSubContents": "청보리 사료는 잎과 대는 조사료, 알곡은 배합사료를 대체할 수 있는 사료이며, 단위중량당 사료\n가치가 높고 종자를 자급할 수 있음\n   - 청보리 재배면적 : (&#39;08) 24.8천ha → (&#39;10) 50 → (&#39;12) 100\n적기에 파종하고 호숙초기에서 황숙기에 원형곤포로 조제하여 한우와 젖소에 급여\n청보리는 우리 종자로 우리 땅에서 재배 및 가축에 이용하는 자연순환형 모델을 구축할 있음", "classSubContents2": "식생활문화의 변화로 곡실용 보리의 소비량이 감소(37㎏→1kg내외) 되면서 제고문제(224천톤)가 \n심각함\n겨울철 유휴농경지를 활용하여 보리를 재배하는 재배농가의 대체소득원 개발과 보리의 수요확대\n를 위한 신용도 개발이 시급해 가축사료로 전환됨\n수입에 의한 국내 곡실 사료량은 511만톤, 조사료는 77만톤으로 늘어나고  곡물(43%) 및 조사료\n(51%) 가격 폭등으로 국내 자급조사료 생산이 필요함\n   - 수입조사료 평균 가격 : (‘07) 313원/㎏ → (’08. 6) 476\n   - 배합사료 가격 : (‘07) 215원/㎏ → (’08. 6) 359\n조사료와 농후사료의 적정 급여비율(60:40)을 개선하여 균형있는 사료급여 체계를 통해 고급 축\n산물 생산을 위한 기반조성 확대 필요\n   - 양질조사료 생산, 이용 활성화 대책 발표(‘08, 농식품부)\n    · 조사료 자급률 향상 : (‘07) 78 → (’12) 90%(국내산 5,335천톤 생산)\n    · 사료비 34% 절감 : 배합사료 230만톤 대체(5,800억)", "classSubHtml": "A01090817.html", "classSubIdx": "178", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090817.pdf", "classSubTitle": "사료비 절감 청보리 사일리지 이용기술", "classSubUse": "Y", "regDate": "2009-03-19 19:27:59.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('205', '껍질째 먹는 배 ‘스위트스킨’', '농촌진흥청(RDA)에서는 기존의 깍아 먹는 배를 대신할 껍질째 먹는 외관과 식미가 우수한 조생
종 중소과 ‘스위트스킨’을 육성하였음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090418", "classSubContents": "농촌진흥청(RDA)에서는 기존의 깍아 먹는 배를 대신할 껍질째 먹는 외관과 식미가 우수한 조생\n종 중소과 ‘스위트스킨’을 육성하였음", "classSubContents2": "○ 배의 기호도를 결정하는 가장 큰 요인은 기존 당도와 가격이었으나 점차 기능성과 안정성을\n   선호하는 추세로 변화하고 있음\n○ 배의 페놀성화합물 등 기능성분과 항산화능은 과육보다는 과피에 많이 포함되어 있으나, \n   기존의 배는 과피가 딱딱하여 깍아 먹어야 함\n○ 배의 수출국 다변화를 위하여 북미인의 기호에 맞는 껍질째 먹을 수 있으며, 중소과인 배를\n   육성할 필요가 있음", "classSubHtml": "A01090418.html", "classSubIdx": "205", "classSubMaster": "담당자 : 농업연구사 신일섭(031-240-3676)", "classSubMovieUrl": null, "classSubPdf": "A01090418.pdf", "classSubTitle": "껍질째 먹는 배 ‘스위트스킨’", "classSubUse": "Y", "regDate": "2009-06-12 15:14:35.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('181', '원격탐사기술이용 쌀알의 단백질 함량 예측', '벼가 누렇게 되는 시기에 쌀알의 단백질 함량을 빛이 직진, 반사, 굴절하는 성질을 이용하여 예
측함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090618", "classSubContents": "벼가 누렇게 되는 시기에 쌀알의 단백질 함량을 빛이 직진, 반사, 굴절하는 성질을 이용하여 예\n측함", "classSubContents2": "쌀알 중 단백질 함량이 높으면 품질이 저하되므로 벼 수확기에 질소 비료를 알맞게 시비해야 함\n단백질 함량을 측정하는 전통적인 방법은 시간이 오래 걸리고 복잡하므로 지상광학센서 이용하\n여 신속한 측정 필요.\n단백질 함량을 적정 수준으로 유지하여 쌀 품질을 높이기 위한 벼 재배기술 개발에 활용", "classSubHtml": "A01090618.html", "classSubIdx": "181", "classSubMaster": "담당자 : 농업연구사 김이현 (031-290-0345)", "classSubMovieUrl": null, "classSubPdf": "A01090618.pdf", "classSubTitle": "원격탐사기술이용 쌀알의 단백질 함량 예측", "classSubUse": "Y", "regDate": "2009-03-19 19:30:33.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('179', '한우고기 품질고급화 기술', '한우 일관사육형 고급육 생산 사료급여 프로그램, 반추위 보호 영양물질 강화, 초음파를 이용한 
사료급여 조절 및 출하시기 조정으로 위생적이고 안전한 고품질 한우고기의 경제적 생산 기술', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090818", "classSubContents": "한우 일관사육형 고급육 생산 사료급여 프로그램, 반추위 보호 영양물질 강화, 초음파를 이용한 \n사료급여 조절 및 출하시기 조정으로 위생적이고 안전한 고품질 한우고기의 경제적 생산 기술", "classSubContents2": "한우 전업농가, 브랜드경영체 등에서 우량 비육밑소를 농가에서 직접 생산하여 고급육을 생산하\n는 일관사육 비율이 40～50% 이상 꾸준히 증가하고 있어, 고품질 한우고기 생산을 위한 일관사육\n형 프로그램 개발이 요구됨\n수입 쇠고기와 품질차별화를 위해 거세한우의 비육기간이 연장됨에 따라 사료이용성과 육량등급\n이 저하되는데 도체등급 향상을 위한 아미노산 강화 반추위 보호사료 이용 기술이 필요함\n거세한우 후기개시전 초음파 생체 정보를 이용하여 육질 및 육량 능력을 조기에 예측하여 사료급\n여 조절을 통한 비육기간을 조정하고 출하시기를 결정함으로써 농가소득을 향상시킬 수 있는 기\n술의 활용이 필요함", "classSubHtml": "A01090818.htm", "classSubIdx": "179", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090818.pdf", "classSubTitle": "한우고기 품질고급화 기술", "classSubUse": "Y", "regDate": "2009-03-19 19:29:04.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('218', '봉독 주입용 유두침', '봉독 을 주사액 또는 연고로 하여 주입하는 데 있어 치료하고자 하는 소의 분방
유두에 상처 없이 원하는 양을 손실 없이 간편하게 주입하여 유방염에 감염된
젖소 원유중의 체세포수를 저하시켜 유방염을 효과적으로 치료하는데 있음', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090819", "classSubContents": "봉독 을 주사액 또는 연고로 하여 주입하는 데 있어 치료하고자 하는 소의 분방\n유두에 상처 없이 원하는 양을 손실 없이 간편하게 주입하여 유방염에 감염된\n젖소 원유중의 체세포수를 저하시켜 유방염을 효과적으로 치료하는데 있음", "classSubContents2": "○ 2006년 국산봉독채집장치 개발 및 산업화로 국내 양봉농가에서도 봉독\n생산이 본격적으로 시작됨\n○ 따라서 다양한 봉독의 수요처 창출이 필요함\n○ 젖소 유방염은 축산농가에서 경제적으로 가장 피해가 큰 질환이나 효과\n적인 치료제가 없는 현실임\n- 경제 적 손 실 ; 1800억 추정 (연간)\n○ 젖소 유방염 치료에 봉독이 효과적임이 임상적으로 증명된 상태임\n○ 간편하고 효율적인 봉독 주입 방법이 절실히 요구됨", "classSubHtml": "A01090819.html", "classSubIdx": "218", "classSubMaster": "농업연구사 한상미 031-290-8510", "classSubMovieUrl": null, "classSubPdf": "A01090819.pdf", "classSubTitle": "봉독 주입용 유두침", "classSubUse": "Y", "regDate": "2010-04-19 14:56:37.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('206', '국산 국화 ‘백마’타고 세계시장으로 진출', '국내 최초로 개발된 백색 대국 “백마”는 순백색의 대형 품종으로 꽃의 가운데 부분에 녹색이 
있고 절화수명이 길어 일본 국화시장에서 선풍적 인기를 얻고 있는 수출유망 품종이다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090419", "classSubContents": "국내 최초로 개발된 백색 대국 “백마”는 순백색의 대형 품종으로 꽃의 가운데 부분에 녹색이 \n있고 절화수명이 길어 일본 국화시장에서 선풍적 인기를 얻고 있는 수출유망 품종이다.", "classSubContents2": "○ 한국, 일본, 중국 등 아시아 지역에서는 국화가 주요 화훼품목으로 자리잡고 있으며 특히 \n   일본은 세계 제1의 국화 육종, 생산, 소비 국가로서 세계적 국화 수출시장임\n○ 스탠다드형 대국은 한국, 일본 등에서 전체 국화 중 50% 이상의 점유율을 차지하고 있으나 \n   국내에서 자체 개발된 백색 대국 품종이 없음\n○ 대국은 대부분 일본에서 개발된 품종을 사용하고 있으나 일본 시장에 수출하기 위해서는 \n   동일 품종을 사용하면서 저임금과 우수한 기후조건을 갖춘 중국, 베트남 등 동남아 제국과의\n   경쟁이 불가피함\n○ 동남아 제국과의 경쟁을 피하고 독자적인 일본 국화시장 진출을 위해서는 품종보호제도를 \n   활용할 수 있는 우수 국산품종의 개발이 절실함", "classSubHtml": "A01090419.html", "classSubIdx": "206", "classSubMaster": "담당자 : 농업연구사 임진희 031-290-6144", "classSubMovieUrl": null, "classSubPdf": "A01090419.pdf", "classSubTitle": "국산 국화 ‘백마’타고 세계시장으로 진출", "classSubUse": "Y", "regDate": "2009-06-12 15:16:23.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('182', '유색보리 식초의 제조방법 및 이를 이용한 음료 개발', '육성된 기능성 유색보리에 누룩 및 알코올 발효균을 접종하여 식초를 제조하고 이를 음료화 함으
로써 일반 양조 식초보다 생리활성 효능이 뛰어나고 음용하기 편리한 유색보리 식초 음료를 개발
함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090619", "classSubContents": "육성된 기능성 유색보리에 누룩 및 알코올 발효균을 접종하여 식초를 제조하고 이를 음료화 함으\n로써 일반 양조 식초보다 생리활성 효능이 뛰어나고 음용하기 편리한 유색보리 식초 음료를 개발\n함", "classSubContents2": "보리는 알코올 발효 및 초산발효가 어렵다는 기술적 편견 극복 \n유색보리는 안토시아닌 색소 및 총 페놀함량 등이 높아 항산화 효과 우수\n유색보리의 항산화 성분 분리 및 대량 추출 기법 개발\n고 항산화 기능성 유색보리 식초 음료의 산업화", "classSubHtml": "A01090619.html", "classSubIdx": "182", "classSubMaster": "담당자 : 국립식량과학원 벼맥류부 농업연구관 최재성(063-840-2244)", "classSubMovieUrl": null, "classSubPdf": "A01090619.pdf", "classSubTitle": "유색보리 식초의 제조방법 및 이를 이용한 음료 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:31:38.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('279', '개방식돈사 무창식 돈사화 리모델링', '개방식으로 환기조절시 부적절한 환경관리로 호흡기질환 등이 다발할 뿐만
아니라, 겨울철 돈사내 온도유지를 위하여 에너지가 과다하게 투입되는데
따른 환경개선 방법으로 개방식 돈사를 무창식 환기시스템으로 개조', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090820", "classSubContents": "개방식으로 환기조절시 부적절한 환경관리로 호흡기질환 등이 다발할 뿐만\n아니라, 겨울철 돈사내 온도유지를 위하여 에너지가 과다하게 투입되는데\n따른 환경개선 방법으로 개방식 돈사를 무창식 환기시스템으로 개조", "classSubContents2": "○ 돈사에 일일 온도 변화 차이가 적은 환경(개방식 →무창식)을 제공\n○ 우리나라 기후조건에 적합한 개방식 돈사의 환경 리모델링 환기시스템\n개발 필요", "classSubHtml": "A01090820.html", "classSubIdx": "279", "classSubMaster": "농업연구사 송준익(031-290-1713)", "classSubMovieUrl": null, "classSubPdf": "A01090820.pdf", "classSubTitle": "개방식돈사 무창식 돈사화 리모델링", "classSubUse": "Y", "regDate": "2010-04-20 09:42:38.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('207', '바캉스용 여름사과 품종 ‘섬머드림’', '농촌진흥청(RDA)에서는 기존의 녹색 여름사과를 대체할 붉게 착색되는 여름사과 ‘섬머드림’을 
육성하였다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090420", "classSubContents": "농촌진흥청(RDA)에서는 기존의 녹색 여름사과를 대체할 붉게 착색되는 여름사과 ‘섬머드림’을 \n육성하였다.", "classSubContents2": "○ 우리나라에서 유통되는 여름사과는 대부분 녹색의 미숙 쓰가루임\n○ 조생종은 그해 첫 사과를 구매하는 소비자들에게 첫 인상을 결정하므로 식미가 \n   우수한 사과 품종개발이 필요함", "classSubHtml": "A01090420.html", "classSubIdx": "207", "classSubMaster": "담당자 : 농업연구사 권순일(054-380-3135)", "classSubMovieUrl": null, "classSubPdf": "A01090420.pdf", "classSubTitle": "바캉스용 여름사과 품종 ‘섬머드림’", "classSubUse": "Y", "regDate": "2009-06-12 15:17:42.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('183', '거대배 이유식용 찰쌀보리 ‘배아찰’', '배아 크기가 일반보리에 비하여 월등히 커서 라이신등 필수아미노산 함량이 높고 당과 비타민 함
량이 많아 선식 및 이유식용으로 적합한 고영양성 찰쌀 보리인 ‘배아찰쌀보리’ 육성', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090620", "classSubContents": "배아 크기가 일반보리에 비하여 월등히 커서 라이신등 필수아미노산 함량이 높고 당과 비타민 함\n량이 많아 선식 및 이유식용으로 적합한 고영양성 찰쌀 보리인 ‘배아찰쌀보리’ 육성", "classSubContents2": "모든 곡실에서 많은 영양소를 함유하고 있는 배부분의 함량 증가\n일반 보리보다 영양소 함량이 증가된 고영양성 보리 품종 개발\n보리의 영양학적 우수성 배가에 따른 소비 확대", "classSubHtml": "A01090620.html", "classSubIdx": "183", "classSubMaster": "담당자 : 국립식량과학원 벼맥류부 농업연구사, 이미자, 063-840-2257", "classSubMovieUrl": null, "classSubPdf": "A01090620.pdf", "classSubTitle": "거대배 이유식용 찰쌀보리 ‘배아찰’", "classSubUse": "Y", "regDate": "2009-03-19 19:32:31.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('280', '분만틀 대체 분만돈 사육시설', '현재 한국을 포함한 세계 각국에서 사용되는 분만돈 사육시설은 여러 가
지가 있으나, 동물복지적인 문제, 제공되는 사육면적의 한계 및 환경여건 등 많
은 문제로 인하여 우리나라의 여건에 적합한 사육시설이 없는 실정이다. 종래
의 분만틀은 포유자돈의 압사를 막기 위하여 설치되었으며, 모돈의 움직임을
극히 제약함으로써 동물복지적인 측면에서 시급하게 해결해야할 문제 중 하나
로 대두되고 있다. 국내에서 생산되는 분만틀의 경우, 외국의 유사제품을 생산
하는 수준으로 제작하는 회사마다 틀의 높이와 간격 등 규격이 달라 사육관리
의 표준화가 어려운 단점이 있다. 또한, 그 용도와 기능에 대하여 명확한 설명
과 실증된 바도 없기 때문에 이에 대한 기준의 설정이 절실한 실정이며, 분만
틀을 대체할 수 있는 동물복지적인 사육시설 개발', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090821", "classSubContents": "현재 한국을 포함한 세계 각국에서 사용되는 분만돈 사육시설은 여러 가\n지가 있으나, 동물복지적인 문제, 제공되는 사육면적의 한계 및 환경여건 등 많\n은 문제로 인하여 우리나라의 여건에 적합한 사육시설이 없는 실정이다. 종래\n의 분만틀은 포유자돈의 압사를 막기 위하여 설치되었으며, 모돈의 움직임을\n극히 제약함으로써 동물복지적인 측면에서 시급하게 해결해야할 문제 중 하나\n로 대두되고 있다. 국내에서 생산되는 분만틀의 경우, 외국의 유사제품을 생산\n하는 수준으로 제작하는 회사마다 틀의 높이와 간격 등 규격이 달라 사육관리\n의 표준화가 어려운 단점이 있다. 또한, 그 용도와 기능에 대하여 명확한 설명\n과 실증된 바도 없기 때문에 이에 대한 기준의 설정이 절실한 실정이며, 분만\n틀을 대체할 수 있는 동물복지적인 사육시설 개발", "classSubContents2": "○ 동물복지를 고려한 가축사육시설 개발을 통한 동물복지 증진\n○ 국내 사육여건을 고려한 한국형 사육시설로 농가보급 확대\n○ 유기축산에 기초한 동물복지형 고품질 축산물 생산기반 구축", "classSubHtml": "A01090821.html", "classSubIdx": "280", "classSubMaster": "농업연구사 전중환 (031-290-1720)", "classSubMovieUrl": null, "classSubPdf": "A01090821.pdf", "classSubTitle": "분만틀 대체 분만돈 사육시설", "classSubUse": "Y", "regDate": "2010-04-20 09:47:41.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('208', '장미 ‘핑키’로 사랑하는 마음을 두배로', '○ 해외품종 식재로 인한 로열티 부담 증가로 국내품종의 필요성 증가. 
○ 2005년에 국립원예특작과학원에 ‘핑키’품종을 육성함. 
○‘핑키’는 진분홍색의 스프레이형으로 꽃이 크고 소화수가 많으며 화형이 우수하고, 생육이
   왕성하며 다수성으로 대일 수출에 알맞음.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090421", "classSubContents": "○ 해외품종 식재로 인한 로열티 부담 증가로 국내품종의 필요성 증가. \n○ 2005년에 국립원예특작과학원에 ‘핑키’품종을 육성함. \n○‘핑키’는 진분홍색의 스프레이형으로 꽃이 크고 소화수가 많으며 화형이 우수하고, 생육이\n   왕성하며 다수성으로 대일 수출에 알맞음.", "classSubContents2": "○ 장미는 우리나라 화훼류중 가장 비중이 큰 작목임\n  - 장미의 비중(전체절화대비):면적 28%(658ha), 생산액 36%(1,353억원)\n○ 국내장미 육성기반 취약, 해외도입품종 의존재배로 농가의 로열티부담 가중\n  - 해외도입품종의 재배비율: 약 91%정도 \n  - 로열티 지불에 따른 농가경영악화:경영비 증가 22%, 소득감소 30%정도\n○ 국제식물 신품종보호동맹(UPOV) 가입과 육성자 권리보호 강화에 따른 로열티 지불부담 \n   가중으로 수출 유망작물의 국내 품종육성 필요성 증가", "classSubHtml": "A01090421.html", "classSubIdx": "208", "classSubMaster": "담당자 : 농업연구관 김원희 031-290-6151", "classSubMovieUrl": null, "classSubPdf": "A01090421.pdf", "classSubTitle": "장미 ‘핑키’로 사랑하는 마음을 두배로", "classSubUse": "Y", "regDate": "2009-06-12 15:19:22.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('184', '고구마 유통기한 연장 및 선도 유지를 위한 표면처리제 개발', '세척한 고구마에 자색고구마 추출물을 이용한 표면처리제를 처리함으로써 고구마의 상품성을 향
상시키고 유통기한 연장하여 생산 농가소득 증진 및 소비자 기호도에 맞춤형 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090621", "classSubContents": "세척한 고구마에 자색고구마 추출물을 이용한 표면처리제를 처리함으로써 고구마의 상품성을 향\n상시키고 유통기한 연장하여 생산 농가소득 증진 및 소비자 기호도에 맞춤형 기술임", "classSubContents2": "최근 소비자 기호도 변화에 따라 세척 고구마의 판매량이 늘고 있음\n고구마는 표피가 엷은 코르크층으로 이루어져 있어 세척할 경우 호흡증가 및 수분증발로 상품성\n이 저하되고 쉽게 썩어 유통기간을 단축시키는 원인이 되고 있음\n세척으로 인한 고구마 유통기간 단축 해결 및 상품성 향상 필요", "classSubHtml": "A01090621.html", "classSubIdx": "184", "classSubMaster": "담당자 : 농업연구관 이준설 061-450-0143", "classSubMovieUrl": null, "classSubPdf": "A01090621.pdf", "classSubTitle": "고구마 유통기한 연장 및 선도 유지를 위한 표면처리제 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:33:57.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('281', '가축 스트레스 저감물질의 대량생산 및 저감사료', '○ 가축 은 사육되어지는 물리적 환경이나 가축간의 생물적 환경에 의한 스트
레스로 생산성과 번식률이 저하되며, 수송이나 온도와 같은 환경 스트레스
를 받음으로서 면역 능력이 저하되어 감염성 질병이나 설사 유발 등으로
생산성이 저하됨
○ 이와 같이 가축 사육시 발생하는 다양한 스트레스는 가축의 생산성에 많은
영향을 미치고 있는데 이를 최소화하기위해 일부분 사양시설 개선에 의해
의존할 수 있지만 이를 개선하기 위해서는 많은 비용이 소요됨
○ 스트 레스를 저감할 수 있는 물질을 개발하여 가축사양에 이용함으로서 다
양한 스트레스 요인에 의한 가축 생산성 저하에 효율적으로 대처할 수
있음
○ 전 통주 발효 미생물을 이용 항스트레스 물질인 글루타치온 고발현 균주의
선발 및 특성 구명
○ 축 종별 글루타치온 첨가 효과 구명 : 젖소, 사슴, 돼지, 닭', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090822", "classSubContents": "○ 가축 은 사육되어지는 물리적 환경이나 가축간의 생물적 환경에 의한 스트\n레스로 생산성과 번식률이 저하되며, 수송이나 온도와 같은 환경 스트레스\n를 받음으로서 면역 능력이 저하되어 감염성 질병이나 설사 유발 등으로\n생산성이 저하됨\n○ 이와 같이 가축 사육시 발생하는 다양한 스트레스는 가축의 생산성에 많은\n영향을 미치고 있는데 이를 최소화하기위해 일부분 사양시설 개선에 의해\n의존할 수 있지만 이를 개선하기 위해서는 많은 비용이 소요됨\n○ 스트 레스를 저감할 수 있는 물질을 개발하여 가축사양에 이용함으로서 다\n양한 스트레스 요인에 의한 가축 생산성 저하에 효율적으로 대처할 수\n있음\n○ 전 통주 발효 미생물을 이용 항스트레스 물질인 글루타치온 고발현 균주의\n선발 및 특성 구명\n○ 축 종별 글루타치온 첨가 효과 구명 : 젖소, 사슴, 돼지, 닭", "classSubContents2": "○ 가축 은 사육중 스트레스로 생산성과 번식률 및 면역 능력의 저하로 감염성\n질병이나 설사가 발생되고 생산성이 저하\n○ 따 라서, 가축의 스트레스를 저감할 수 있는 물질을 개발하여 가축사양에\n이용함으로서 다양한 스트레스 요인에 의한 가축 생산성 저하에 효율적\n으로 대처할 수 있음", "classSubHtml": "A01090822.html", "classSubIdx": "281", "classSubMaster": "농업연구사 이왕식 (031-290-1698)", "classSubMovieUrl": null, "classSubPdf": "A01090822.pdf", "classSubTitle": "가축 스트레스 저감물질의 대량생산 및 저감사료", "classSubUse": "Y", "regDate": "2010-04-20 09:49:00.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('209', '참다래 신품종 ‘제시골드’ 저온 저장 특성', '참다래 신품종 ‘제시골드’의 저온(1±0.5℃) 저장 시 저장 2개월 이내를 "안정저장기간"으로 
설정하고, 저장 2개월 이후를 "저장한계기간"으로 설정하여 수확 후 저장 지침으로 활용한다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090422", "classSubContents": "참다래 신품종 ‘제시골드’의 저온(1±0.5℃) 저장 시 저장 2개월 이내를 \"안정저장기간\"으로 \n설정하고, 저장 2개월 이후를 \"저장한계기간\"으로 설정하여 수확 후 저장 지침으로 활용한다.", "classSubContents2": "○ 참다래 황색과육 품종 소비기호도 증가에 따른 ‘제시골드’ 재배면적 증가\n - 재배면적 : (’06) 0 → (’08) 10ha → (’12) 100ha 예정\n○ 재배면적 급증에 따른 농업인의 저장 및 후숙특성연구 수요 증가\n○ ‘제시골드’ 고품질 안정 유통을 위한 저온 저장 특성 구명 필요", "classSubHtml": "A01090422.html", "classSubIdx": "209", "classSubMaster": "담당자 : 농업연구사 이진수 064-741-2562", "classSubMovieUrl": null, "classSubPdf": "A01090422.pdf", "classSubTitle": "참다래 신품종 ‘제시골드’ 저온 저장 특성", "classSubUse": "Y", "regDate": "2009-06-12 15:37:19.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('185', '작물생장촉진 미생물 ‘KR083’ 및 ‘RRj228’ 산업화', '작물 뿌리가 잘 자라게 하여 양분흡수를 많게 하고 토양내 식물병원균의 자람을 억제시켜 병 발
생을 줄여주는 바실러스 속 미생물 ‘KR083’ 및 슈도모나스 속 미생물 ‘RRj228’의 제제 산업
화 기술', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090622", "classSubContents": "작물 뿌리가 잘 자라게 하여 양분흡수를 많게 하고 토양내 식물병원균의 자람을 억제시켜 병 발\n생을 줄여주는 바실러스 속 미생물 ‘KR083’ 및 슈도모나스 속 미생물 ‘RRj228’의 제제 산업\n화 기술", "classSubContents2": "친환경농업을 위한 화학비료ㆍ농약 부분대체용 미생물제제 개발 필요\n - 친환경농업 현황(2007) : 75,000농가, 123천ha 농경지, 1,786천톤 생산\n - 미생물 기능 : 질소고정, 양분가용화, 식물호르몬 분비, 토양병 억제 등\n토양생산성 및 농산물품질의 유지ㆍ향상을 위한 친환경농자재 개발 필요 \n - 화학비료 의존농법 폐해 : 지력 불균형, 작물병해 증가, 관개수 오염\n - 소비자의 식품구매 고려요소 : 안전성(56%) > 가격 (19%) > 맛(13%)", "classSubHtml": "A01090622.htm", "classSubIdx": "185", "classSubMaster": "담당자 : 농업연구관 강위금 031-290-6770", "classSubMovieUrl": null, "classSubPdf": "A01090622.pdf", "classSubTitle": "작물생장촉진 미생물 ‘KR083’ 및 ‘RRj228’ 산업화", "classSubUse": "Y", "regDate": "2009-03-19 19:35:23.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('282', '돼지 생산성 향상을 위한 미생물 이용 기술', '○ 최근 돼지 생산성향상, 항생제대체, 친환경축산을 위하여 미생물이용
기술에 대한 수요가 증가되고 있음
○ 유익한 미생물을 이용하여 농가형 발효생균제를 제조&#8228;급여하여 돼
지의 면역력 강화 및 생산성 향상기술을 보급코자 함', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090823", "classSubContents": "○ 최근 돼지 생산성향상, 항생제대체, 친환경축산을 위하여 미생물이용\n기술에 대한 수요가 증가되고 있음\n○ 유익한 미생물을 이용하여 농가형 발효생균제를 제조&#8228;급여하여 돼\n지의 면역력 강화 및 생산성 향상기술을 보급코자 함", "classSubContents2": "○ 고품질 안전축산물에 대한 소비자 관심 증가\n- 무 항생 제 및 친환경축산물 구매 선호\n- 항 생제 허용품목 감축(안) : (&#39;08) 25종 &#10141; (&#39;09) 18 &#10141; (&#39;10) 9 &#10141; (&#39;12) 0\n- 사 료용 항생제 사용금지(‘12년)에 따른 생산성 저하 예상\n- 돼 지 면역력 향상을 위한 기술 개발 필요\n○ 돼 지 생산성 향상을 위한 유익 미생물에 대한 수요 증가\n- 사 료공 정서 생균제 종류 확대 : 14 → 29종(‘07)\n- 유 익 미생물의 효과 : 장의 안정성, 사료이용성 증진, 면역력 향상\n- 돼 지 생산성 향상을 위한 유익 미생물이용 기술 개발 필요", "classSubHtml": "A01090823.html", "classSubIdx": "282", "classSubMaster": "축산연구사 김동운 (041-580-3449)", "classSubMovieUrl": null, "classSubPdf": "A01090823.pdf", "classSubTitle": "돼지 생산성 향상을 위한 미생물 이용 기술", "classSubUse": "Y", "regDate": "2010-04-20 09:51:23.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('210', '회색빛 도시에 녹색 희망을 전하는 ‘생활원예’', '&#10061; 공기정화 식물 및 실내정원의 정착으로 실내 그린 어메니티 증진
&#10061; 옥상, 벽면 등 인공지반의 원예적 이용 확대', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090423", "classSubContents": "&#10061; 공기정화 식물 및 실내정원의 정착으로 실내 그린 어메니티 증진\n&#10061; 옥상, 벽면 등 인공지반의 원예적 이용 확대", "classSubContents2": "&#10061; 국가 5대 비전 중 “저탄소 녹색 성장산업 지원방안” 발표 (’08. 8. 15.)\n&#10061; 아토피 및 새집증후군 등 생활원예에 대한 국민의 관심 증가\n  - 포름알데히드 등 10종의 유해물질 허용기준 설정(2005년 12월 시행)\n&#10061; 공기정화 식물 및 실내정원의 정착을 통한 쾌적한 실내환경 유지\n  - 우수한 공기정화 식물의 선발 및 실생활 공간 내 적용 방법 \n  - 기능성 실내정원 모델 개발 및 보급\n&#10061; 옥상, 벽면 등 인공지반의 녹지 공간 증대 및 원예적 활용 모델 개발\n  - 옥상 및 인공지반 녹화로 인한 에너지 절감 효과\n  - 도시 경관 향상 및 다양한 원예 활용 모델 제시", "classSubHtml": "A01090423.html", "classSubIdx": "210", "classSubMaster": "담당자 : 농업연구관 정명일 031-290-6164", "classSubMovieUrl": null, "classSubPdf": "A01090423.pdf", "classSubTitle": "회색빛 도시에 녹색 희망을 전하는 ‘생활원예’", "classSubUse": "Y", "regDate": "2009-06-12 15:39:01.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('186', '정량 유전자 증폭 방법을 이용한 벼 흰잎마름병 발생예찰', '정량 유전자 증폭(Real Time PCR)을 이용한 벼 흰잎마름병 발생예찰방법은 박테리오파지를 이용
하는 것보다 1개월 이상 빠르고, 균주의 특이성이 없어 효율적이며, 5시간 이내로 병원균의 밀도
를 측정 및 분석이 가능함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090623", "classSubContents": "정량 유전자 증폭(Real Time PCR)을 이용한 벼 흰잎마름병 발생예찰방법은 박테리오파지를 이용\n하는 것보다 1개월 이상 빠르고, 균주의 특이성이 없어 효율적이며, 5시간 이내로 병원균의 밀도\n를 측정 및 분석이 가능함", "classSubContents2": "벼 흰잎마름병 발생이 급속히 확산되고 있으며 발병이 빨라지고 있음\n병원세균은 관개수를 통하여 전염이 되고 있으나, 이에 대한 정확한 예찰방법이 없음", "classSubHtml": "A01090623.html", "classSubIdx": "186", "classSubMaster": "담당자 : 국립식량과학원 벼맥류부 농업연구사, 노태환, 063-840-2179", "classSubMovieUrl": null, "classSubPdf": "A01090623.pdf", "classSubTitle": "정량 유전자 증폭 방법을 이용한 벼 흰잎마름병 발생예찰", "classSubUse": "Y", "regDate": "2009-03-19 19:36:40.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('283', '임신돈용 완전혼합발효(TMF)사료', '○ 임 신돈용 TMF사료를 제조하기 위해서는 발효가 잘 되는 원료사료를
이용하고, TMF사료 제조 후 1주일이 지난 다음에 급여한다.
○ TM F사료에 대하여 45일까지 사료의 미생물 변화를 조사한 결과 보존
상에 큰 문제가 없었다.', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090824", "classSubContents": "○ 임 신돈용 TMF사료를 제조하기 위해서는 발효가 잘 되는 원료사료를\n이용하고, TMF사료 제조 후 1주일이 지난 다음에 급여한다.\n○ TM F사료에 대하여 45일까지 사료의 미생물 변화를 조사한 결과 보존\n상에 큰 문제가 없었다.", "classSubContents2": "○ 양 돈사료의 주된 원료인 곡물이 폭등함에 따라 식품 부산물이나 농산부\n산물을 발효시켜 돼지에 급여함으로써 사료비 절감효과를 기대하고 있다.\n○ 청 보리와 같은 사료의 섬유소 성분은 대장에서 미생물 발효 기질로 이용\n되며, 발효산물로 저급휘발성지방산(VFA)이 생성되어 대장내 발효조건이\n개선된다.\n○ 생 균제, 식이섬유소, 발효사료 등을 활용하여 대장환경을 개선함으로써\n돼지의 생산성이 증대될 것이라는 기대가 많다.", "classSubHtml": "A01090824.html", "classSubIdx": "283", "classSubMaster": "농업연구사 조성백 (041-580-3446)", "classSubMovieUrl": null, "classSubPdf": "A01090824.pdf", "classSubTitle": "임신돈용 완전혼합발효(TMF)사료", "classSubUse": "Y", "regDate": "2010-04-20 09:52:12.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('211', '중생종 고당도 수출용 단감 “로망”육성', '우리나라 기후 풍토에 적응력이 강한 고품질 조중생 완전단감 품종을 육성하기 위하여 
1997년 로-19에 만어소를 교배하여 2006년에 97-23-29계통을 1차 선발하여, 제반 특성을 
정밀 검토한바 년차간 변이가 적고 특성이 우수하여 2008년 최종 선발 로망으로 명명하였다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090424", "classSubContents": "우리나라 기후 풍토에 적응력이 강한 고품질 조중생 완전단감 품종을 육성하기 위하여 \n1997년 로-19에 만어소를 교배하여 2006년에 97-23-29계통을 1차 선발하여, 제반 특성을 \n정밀 검토한바 년차간 변이가 적고 특성이 우수하여 2008년 최종 선발 로망으로 명명하였다.", "classSubContents2": "○ 우리나라는 세계 1위의 단감 생산국이나 완전단감 육성 품종 없음\n○ 부유 단일 품종 편중재배로는 다양한 소비 기호 충족 미흡\n○ 단감 수출시장 다변화 및 확대를 위해서는 국제 기호성 품종육성 시급\n○ 단감은 2008년 품종보호대상 작물로 지정됨에 따라 외국 도입품종 재배에 따른 로열티 \n   문제가 제기 우려", "classSubHtml": "A01090424.html", "classSubIdx": "211", "classSubMaster": "담당자 : 농업연구관 조광식 (061-330-1590)", "classSubMovieUrl": null, "classSubPdf": "A01090424.pdf", "classSubTitle": "중생종 고당도 수출용 단감 “로망”육성", "classSubUse": "Y", "regDate": "2009-06-12 15:40:59.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('187', '친환경 최고품질 벼 품종 “진수미” 육성', '진수미는 우리나라 남부지역재배에 적합한 밥맛이 좋은 품종으로 2008년에 육성되었으며 영남평
야지에서 재배하였을때 쌀알이 깨끗하고 내병성을 갖추었으며 최고 수준의 밥맛을 보여 농가소
득 증대에 기여할 것으로 평가됨', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090624", "classSubContents": "진수미는 우리나라 남부지역재배에 적합한 밥맛이 좋은 품종으로 2008년에 육성되었으며 영남평\n야지에서 재배하였을때 쌀알이 깨끗하고 내병성을 갖추었으며 최고 수준의 밥맛을 보여 농가소\n득 증대에 기여할 것으로 평가됨", "classSubContents2": "쌀 시장의 개방에 따른 국제경쟁력을 갖추기 위하여 최고품질 벼 품종의 개발이 필요함\n우리나라 남부지역은 여러가지 기상재해와 병해충의 피해가 많아 안정적인 벼농사를 위해서는 이\n러한 피해에 대한 저항성이 필요함", "classSubHtml": "A01090624.html", "classSubIdx": "187", "classSubMaster": "담당자 : 농업연구관 여운상 018-207-6587", "classSubMovieUrl": null, "classSubPdf": "A01090624.pdf", "classSubTitle": "친환경 최고품질 벼 품종 “진수미” 육성", "classSubUse": "Y", "regDate": "2009-03-19 19:37:47.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('284', '안전돈육 생산을 위한 항생제 대체제 활용기술', '&#10061; 축 산업에서 항생제는 질병예방, 성장촉진 및 치료의 목적으로 사용
&#10061; 항 생제 내성균에 대한 위험성 제기와 소비자의 안전성 요구 증대
&#10061; 유 럽연합은 2006년부터 전면금지, 우리나라는 2012년부터 금지 예정', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090825", "classSubContents": "&#10061; 축 산업에서 항생제는 질병예방, 성장촉진 및 치료의 목적으로 사용\n&#10061; 항 생제 내성균에 대한 위험성 제기와 소비자의 안전성 요구 증대\n&#10061; 유 럽연합은 2006년부터 전면금지, 우리나라는 2012년부터 금지 예정", "classSubContents2": "&#10061; 항생 제 사용금지 시 질병발생, 폐사율 등 해결할 수 있는 사양기술 필요\n&#10061; 소 비자 요구하는 고품질의 안전돈육 생산 기술 개발", "classSubHtml": "A01090825.html", "classSubIdx": "284", "classSubMaster": "농업연구사 정현정 (041-580-3453)", "classSubMovieUrl": null, "classSubPdf": "A01090825.pdf", "classSubTitle": "안전돈육 생산을 위한 항생제 대체제 활용기술", "classSubUse": "Y", "regDate": "2010-04-20 09:53:39.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('220', '인체에 무해한 채소 무름병 방제제 카로신 D', '○ 인 체에 무해하며 무름병균만 특이적으로 제거 할 수 있는 새로운 박테
리오신 카로신 디의 생성 균주 탐색
○ 탐 색한 균주의 박테리오신 생성 유전자 개발 및 이를 이용한 무름병 방
제제 개발', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090425", "classSubContents": "○ 인 체에 무해하며 무름병균만 특이적으로 제거 할 수 있는 새로운 박테\n리오신 카로신 디의 생성 균주 탐색\n○ 탐 색한 균주의 박테리오신 생성 유전자 개발 및 이를 이용한 무름병 방\n제제 개발", "classSubContents2": "○ 국 민 소득의 증가로 샐러드 등의 엽채류 섭취가 증가하며 30%정도의\n엽채류는 유통 중 부패균에 의하여 손실\n○ 지 구 온난화에 따른 기온 상승 등으로 신선채소의 수확 후 유통 및 저\n장 중 부패에 의한 손실 급증\n○ 가 열없이 섭취되는 제품의 특성 상 인체에 무해한 부패균 저감화 방법\n이 절실히 요구됨", "classSubHtml": "A01090425.html", "classSubIdx": "220", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090425.pdf", "classSubTitle": "인체에 무해한 채소 무름병 방제제 카로신 D", "classSubUse": "Y", "regDate": "2010-04-19 16:04:17.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('188', '컬러감자 자영, 홍영 개발', '항산화 기능성 물질인 안토시아닌이 풍부하게 함유되어있어 고혈압, 심장질환개선 등 성인병과 
아토피 등에 효과가 있고 겉과 속이 모두 자주색 또는 홍색인 컬러감자 ‘자영’, ‘홍영’ 신품
종을 육성 및 보급함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090625", "classSubContents": "항산화 기능성 물질인 안토시아닌이 풍부하게 함유되어있어 고혈압, 심장질환개선 등 성인병과 \n아토피 등에 효과가 있고 겉과 속이 모두 자주색 또는 홍색인 컬러감자 ‘자영’, ‘홍영’ 신품\n종을 육성 및 보급함", "classSubContents2": "감자는 알칼리성 다이어트 식품으로 선진국에서는 소비량이 많은 작물임\n컬러작물에 포함되어있는 안토시아닌의 항산화기능성에 대한 연구결과가 많이 발표되고 있으며, \n천연색소에 대한 관심도가 증가하고 있음\n안토시아닌 함량이 높은 컬러감자를 개발 보급으로 감자소비촉진 및 농가소득 향상", "classSubHtml": "A01090625.html", "classSubIdx": "188", "classSubMaster": "담당자 : 농업연구사 조지홍☎ 033-330-1610", "classSubMovieUrl": null, "classSubPdf": "A01090625.pdf", "classSubTitle": "컬러감자 자영, 홍영 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:38:47.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('285', '축진참돈을 활용한 재래돼지 산업화', '우리나라 재래돼지는 일제강점기에 외래종과의 교잡으로 멸실 위기에
있으나 국제적인 고유 유전자원 확보의 전략화 추세에서 중요성이 인정
되고 있어 20년에 걸쳐 순수화 복원을 하여 고급육 생산에 활용하고 있음', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090826", "classSubContents": "우리나라 재래돼지는 일제강점기에 외래종과의 교잡으로 멸실 위기에\n있으나 국제적인 고유 유전자원 확보의 전략화 추세에서 중요성이 인정\n되고 있어 20년에 걸쳐 순수화 복원을 하여 고급육 생산에 활용하고 있음", "classSubContents2": "○ 1992년 유엔환경계획에서 미래의 유전자원으로서 재래가축의 보존에 대\n한 필요성을 인식하고 생물다양성의 멸종우려와 보존에 대한 인식이 고\n조되면서 1993년 생물다양성협약이 발효되어, 멸종위기에 처한 재래종의\n가치를 구명하고 고유 유전자원을 보존하려는 노력이 국제적인 추세로\n자리 잡고 있어 이에 따른 유전자원의 확보 경쟁으로 재래돼지의 순수\n화 복원과 보존 필요성이 대두되고 있음\n○ 복원된 재래돼지는 미래의 유전자원으로서 보존가치가 크며, 일반 개량\n돼지에 비해 만숙종으로 잘 크지는 않지만 육질이 대단히 우수한 것으\n로 조사되고 있어 육질과 맛이 좋은 고기를 만드는 유전자원으로서 수\n입육과 차별화된 고품질 돈육의 생산에 활용할 필요가 있음", "classSubHtml": "A01090826.html", "classSubIdx": "285", "classSubMaster": "농업연구관 김명직 (041-580-3445)", "classSubMovieUrl": null, "classSubPdf": "A01090826.pdf", "classSubTitle": "축진참돈을 활용한 재래돼지 산업화", "classSubUse": "Y", "regDate": "2010-04-20 09:54:31.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('221', '포도 비파괴 당도 선별장치', '근적 외선을 발생시켜 포도에 반사한 후 스펙트럼을 생성시키는 근적외선 장
치와 이를 분석하여 내부품질을 판정하는 부분과 포도의 이송 및 배출시 손상
이 없도록 고안된 자유이송접시와 이를 안정적으로 이송시키는 컨베이어 등으
로 구성된 포도 비파괴 당도선별장치로 구성되어 있음
이송 컨베이어에 놓이는 포도가 차례로 이동되면서 근적외선 발생부와 스펙
트럼 분석기를 거치면서 내부품질 정보가 컴퓨터 시스템으로 전송되어 당도에
따른 품질 등급이 자동으로 분리됨으로서 포도의 등급별 선별작업 효율이 높아
져 선별 신뢰도를 높일 수 있음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090426", "classSubContents": "근적 외선을 발생시켜 포도에 반사한 후 스펙트럼을 생성시키는 근적외선 장\n치와 이를 분석하여 내부품질을 판정하는 부분과 포도의 이송 및 배출시 손상\n이 없도록 고안된 자유이송접시와 이를 안정적으로 이송시키는 컨베이어 등으\n로 구성된 포도 비파괴 당도선별장치로 구성되어 있음\n이송 컨베이어에 놓이는 포도가 차례로 이동되면서 근적외선 발생부와 스펙\n트럼 분석기를 거치면서 내부품질 정보가 컴퓨터 시스템으로 전송되어 당도에\n따른 품질 등급이 자동으로 분리됨으로서 포도의 등급별 선별작업 효율이 높아\n져 선별 신뢰도를 높일 수 있음", "classSubContents2": "○ 믿고 살 수 있는 고품질 농산물에 대한 소비자의 요구도 증대로 품질의\n등급화 및 균일화 선별기술이 필요함\n○ 농산물의 품질은 개체간 차이가 크므로 전수조사를 위한 비파괴 신속&#8228;\n정밀 선별시스템이 요구됨\n○ 근적외선 반사스펙트럼에 의한 포도의 내부품질을 비파괴적으로 측정함\n으로서 포도의 선별작업 효율을 높이고 선별 신뢰도를 높이기 위함", "classSubHtml": "A01090426.html", "classSubIdx": "221", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090426.pdf", "classSubTitle": "포도 비파괴 당도 선별장치", "classSubUse": "Y", "regDate": "2010-04-19 16:05:42.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('189', '콩밭에 기생하는 미국실새삼 방제용 미생물제초제 개발', '콩에 기생하여 생육 및 수량에 심각한 피해를 주는 기생잡초인 미국실새삼 방제을 위하여 미생물
균주(BWC04-49-3)을 이용하여 미국실새삼의 줄기조직에 침투시켜 식물체를 고사시키는 기술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090626", "classSubContents": "콩에 기생하여 생육 및 수량에 심각한 피해를 주는 기생잡초인 미국실새삼 방제을 위하여 미생물\n균주(BWC04-49-3)을 이용하여 미국실새삼의 줄기조직에 침투시켜 식물체를 고사시키는 기술임", "classSubContents2": "미국실새삼은 1980년대 초반 수입농산물 속에 잡초종자가 섞여 들어 온 것으로 예측하고 있으며 \n주로 콩밭에 많이 발생하는 기생성 잡초로 발생시 콩을 완전히 고사시켜 수확을 불가능하게 함\n현재 콩, 도라지, 고추 등의 작물에도 기생하여 피해를 주고 있으며, 도로변 발생이 늘어나 점\n차 농경지로 확산하여 그 피해가 더욱 커 질 것으로 예상됨 \n선진국에서도 이 잡초의 방제에 많은 연구가 이루어지고 있으나 효과적인 방제법은 없는 실정임\n이렇게 골치 아픈 미국실새삼을 미생물을 이용하여 친환경적으로 방제    하고자 함\n미국실새삼이 2-3본/10m2만 발생하더라도 콩수량은 50%정도 감소", "classSubHtml": "A01090626.html", "classSubIdx": "189", "classSubMaster": "담당자 : 농업연구사 송석보 055-350-1254", "classSubMovieUrl": null, "classSubPdf": "A01090626.pdf", "classSubTitle": "콩밭에 기생하는 미국실새삼 방제용 미생물제초제 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:40:15.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('286', '에너지 절감형 산란계 점등시스템', '빛은 닭에 있어서 매우 중요한 환경요소로 산란계는 광도 10~20 Lux로
15~17시간(일조시간 포함), 육계는 광도 3~5 Lux로 12시간 이상(일조시간
포함)을 형광등이나 백열등과 같은 광원을 이용하여 점등을 실시하고 있다.
기존 점등광원을 대체한 LED 이용 점등장치를 사용하여 에너지 절감과 생
산성 향상을 얻을 수 있다.', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090827", "classSubContents": "빛은 닭에 있어서 매우 중요한 환경요소로 산란계는 광도 10~20 Lux로\n15~17시간(일조시간 포함), 육계는 광도 3~5 Lux로 12시간 이상(일조시간\n포함)을 형광등이나 백열등과 같은 광원을 이용하여 점등을 실시하고 있다.\n기존 점등광원을 대체한 LED 이용 점등장치를 사용하여 에너지 절감과 생\n산성 향상을 얻을 수 있다.", "classSubContents2": "○ 닭에 대한 빛의 직접적인 효과는 닭의 내분비 기관을 자극하여 육성기\n에는 성성숙을 지연 또는 촉진하며 산란기에는 산란촉진, 환우방지, 비타민\nD 합성에 관여\n○ 닭은 장일성 동물로 점등자극에 의하여 산란이 지속되어 형광등이나 백\n열전구와 같은 광원을 이용하여 점등을 실시하고 있음\n- 육계는 12시간이상, 산란계는 15～17시간\n○ 기존 점등광원인 백열전구는 에너지 효율이 낮아 금후 생산 중단 예정\n이며 이를 대체할 만한 점등광원의 필요성이 대두\n- EU는 2012, 한국은 2013, 호주는 2014년 백열구 생산 중단\n○ LED는 백열전구에 비해 점등광원으로서 많은 장점을 갖음\n- 수명시간 : 5만시간, 전기 에너지 절약, 여러 파장대를 선택적 이용", "classSubHtml": "A01090827.html", "classSubIdx": "286", "classSubMaster": "농업연구사 김민지 (041-580-6720)", "classSubMovieUrl": null, "classSubPdf": "A01090827.pdf", "classSubTitle": "에너지 절감형 산란계 점등시스템", "classSubUse": "Y", "regDate": "2010-04-20 09:56:54.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('222', '온실의 배기열 환원장치', '온풍난방기 사용시 연도를 통해 온실 외부로 버려지는 열에너지를
히트파이프를 이용한 배기열 환원장치로 회수하여 재이용하는 기
술이며, 약 16%의 에너지절감효과가 있음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090427", "classSubContents": "온풍난방기 사용시 연도를 통해 온실 외부로 버려지는 열에너지를\n히트파이프를 이용한 배기열 환원장치로 회수하여 재이용하는 기\n술이며, 약 16%의 에너지절감효과가 있음", "classSubContents2": "○ 시설원예 난방에 사용되는 온풍난방기 보급대수는 약 18만대를\n넘어서고 있음\n○ 열효율은 80～90% 수준으로 비교적 높은 수준이나 연도를 통\n하여 온실 밖으로 버려지는 배기열이 10～20%에 달하고 있어\n이를 재활용할 수 있는 기술개발이 필요함", "classSubHtml": "A01090427.html", "classSubIdx": "222", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090427.pdf", "classSubTitle": "온실의 배기열 환원장치", "classSubUse": "Y", "regDate": "2010-04-19 16:06:26.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('190', '콩 품종 판별마커 개발', '증폭기(PCR)를 이용하여 적은 양의 핵산(DNA)을 증폭시켜 품종 고유의 유전자형을 동정할 수 있
는 단순염기서열(SSR)의 마커(marker)조합을 찾아 이를 통해 국내에서 육성된 콩 품종의 구별에 
이용할 수 있도록 한 기술임.', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090627", "classSubContents": "증폭기(PCR)를 이용하여 적은 양의 핵산(DNA)을 증폭시켜 품종 고유의 유전자형을 동정할 수 있\n는 단순염기서열(SSR)의 마커(marker)조합을 찾아 이를 통해 국내에서 육성된 콩 품종의 구별에 \n이용할 수 있도록 한 기술임.", "classSubContents2": "현재 콩 품종의 판별은 국제 식물 신품종 보호동맹(UPOV) 기준에 의한 형태적 특성에 근거함\n형태적 특성의 평가를 위해서는 시간 및 비용이 과다하게 소요되며 재배환경에 따라 변이 발생\n의 가능성이 있으므로 특성평가에 주관성이 개입될 수 있어 형태적 특성에 의존하여 품종을 구별\n하는 데에 한계가 있으므로 이를 보완하고자 함\nDNA를 이용한 핵산지문법에 의한 품종판별기술은 분석방법에 대한 신뢰성이 높아 소비자에게 보\n다 객관적인 정보를 제공할 수 있음", "classSubHtml": "A01090627.html", "classSubIdx": "190", "classSubMaster": "담당자 : 농업연구사 서민정 (031-290-6752)", "classSubMovieUrl": null, "classSubPdf": "A01090627.pdf", "classSubTitle": "콩 품종 판별마커 개발", "classSubUse": "Y", "regDate": "2009-03-19 19:41:16.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('287', '국내 최초 개발 톨 페스큐 신품종', '병해 및 영속성이 강한 「그린마스터」의 개발 및 보급으로 초지의 영속성
향상 및 이용연한 증가', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090828", "classSubContents": "병해 및 영속성이 강한 「그린마스터」의 개발 및 보급으로 초지의 영속성\n향상 및 이용연한 증가", "classSubContents2": "○ 우리나라의 초지면적은 40천ha 정도이나 기후변화의 영향으로 초지의 부실\n화가 심하고 이용성이 낮아 환경적응성이 우수한 신품종 개발이 필요\n○ 영속성과 사료가치가 우수한 톨 페스큐 신품종 육성은 우리나라 초지산업\n의 발전을 위해 매우 중요함\n○ 농업농촌 어메니티 자원 활용 및 사료비 절감을 통한 조사료 생산 확대", "classSubHtml": "A01090828.html", "classSubIdx": "287", "classSubMaster": "농업연구사 이상훈 (041-580-6754), 농업연구관 최기준 (031-290-1751)", "classSubMovieUrl": null, "classSubPdf": "A01090828.pdf", "classSubTitle": "국내 최초 개발 톨 페스큐 신품종", "classSubUse": "Y", "regDate": "2010-04-20 09:58:05.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('223', '온실 수평커튼 개폐장치', '온실 내 사용되는 커튼 개폐장치로써 커튼을 열고 닫을 때 커튼 감김이나
풀림속도가 일정하게 자동 조절되고 커튼 그늘면적을 줄이면서 보온성은 높여
난방 에너지를 절감할 수 있는 기술임', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090428", "classSubContents": "온실 내 사용되는 커튼 개폐장치로써 커튼을 열고 닫을 때 커튼 감김이나\n풀림속도가 일정하게 자동 조절되고 커튼 그늘면적을 줄이면서 보온성은 높여\n난방 에너지를 절감할 수 있는 기술임", "classSubContents2": "○ 온 실에 사용되고 있는 커튼 개폐방식은 와이어 등으로 커튼을 끌어당겨\n커튼을 열고 닫는 예인식과 일정한 경사를 따라 권취축이 이동 회전하\n면서 커튼을 감아 열거나 풀어내려서 닫는 귄취식 있음.\n○ 예 인식은 구조가 간단하고 커튼길이가 길어도 작동상태가 양호하나, 낮\n에 커튼을 열었을 때 모아진 커튼에 의해 그림자가 많이 생겨 이곳의\n작물생육이 불량해지며 수확량이 감소되는 문제점이 있음.\n○ 권 취식은 축 자체가 이동하면서 커튼을 촘촘이 감기 때문에 그늘면적을\n감소시킬 수 있으나 축에 따라 느슨하게 감기는 부분과 팽팽하게 감기는\n부분이 생기는 등 권취상태가 균일하지 못하여 축이 휘어지거나 커튼이\n찢어지는 경우가 있음.\n○ 예 인식과 권취식의 장점은 살리면서 단점은 보완할 수 있는 커튼 개폐\n장치 개발이 필요하였음.", "classSubHtml": "A01090428.html", "classSubIdx": "223", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090428.pdf", "classSubTitle": "온실 수평커튼 개폐장치", "classSubUse": "Y", "regDate": "2010-04-19 16:07:15.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('191', 'TBIA(조직반점항원항체법)을 이용한 보리호위축병 신속 검정법', '질산 셀롤로오스 막에 병든 잎의 즙액을 묻히고 항혈청을 첨가하여 포장에서     신속 간편하게 
보리호위축병을 검정할 수 있는 기술 임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090628", "classSubContents": "질산 셀롤로오스 막에 병든 잎의 즙액을 묻히고 항혈청을 첨가하여 포장에서     신속 간편하게 \n보리호위축병을 검정할 수 있는 기술 임", "classSubContents2": "보리 바이러스병은 토양 곰팡이(Polymyxa graminis)에 의해 전염되는 병으로 병징이 동해 및 비\n료 부족 현상과 비슷하여 바이러스병 감염 판정 기술 개발이 필요\n효소항원 항체법(ELISA) 및 유전자 증폭법(PCR)은 바이러스병 검정을 위해 시간이 오래 걸리고 \n비용이 많이 들며 정밀성이 요구되어 현장에서 사용하기 곤람함\n포장에서 간단하게 식물 바이러스병 판단 할 수 있는 검정개발이 필요함", "classSubHtml": "A01090628.html", "classSubIdx": "191", "classSubMaster": "담당자 : 국립식량과학원 벼맥류부 농업연구관 현종내(063-840-2240)", "classSubMovieUrl": null, "classSubPdf": "A01090628.pdf", "classSubTitle": "TBIA(조직반점항원항체법)을 이용한 보리호위축병 신속 검정법", "classSubUse": "Y", "regDate": "2009-03-19 19:42:10.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('288', '송아지 제각모자 활용', '송 아지가 생후 1주일이 되어 뿔의 생장점이 솟아나올 때 뿔이 날 부위
의 털을 가위로 제거하고 동전크기로 제각연고를 뿔날 자리에 도포하고
제각모자를 씌어 어미소가 핥지 못하도록 하고 6～12시간후 제각모자를
벗겨 줌', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090829", "classSubContents": "송 아지가 생후 1주일이 되어 뿔의 생장점이 솟아나올 때 뿔이 날 부위\n의 털을 가위로 제거하고 동전크기로 제각연고를 뿔날 자리에 도포하고\n제각모자를 씌어 어미소가 핥지 못하도록 하고 6～12시간후 제각모자를\n벗겨 줌", "classSubContents2": "○ 암 소의 유산방지 및 수소의 투쟁심 최소화\n○ 큰 소는 보정이 어렵고 제각시 출혈이 많이 발생하나 어린송아지 시기\n제 각은 작 업 이 용이함\n○ 어 린송아지를 제각시키고자 할때 뿔이 날 부위에 제각연고를 바르고 어\n미 소가 핥 지 못하도록 어미소와 송아지를 강제분리하지 않고 제각모자\n를 씌 워 제각 연고의 작용이 방해받지 않도록 하여 제각효과의 극대화", "classSubHtml": "A01090829.html", "classSubIdx": "288", "classSubMaster": "농업연구사 이명식 (033-330-0625)", "classSubMovieUrl": null, "classSubPdf": "A01090829.pdf", "classSubTitle": "송아지 제각모자 활용", "classSubUse": "Y", "regDate": "2010-04-20 09:59:30.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('228', '양파 일대잡종 “영보황” 개발', '양파 일대잡종 “영보황”은 저장성이 좋은 웅성불임 모친과 구가 둥글고 맛
이 좋은 화분친으로 교배하여 2007년부터 2009년까지 3년 동안 무안, 창녕,
안동 등 지역적응 시험에서 우수하였음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090429", "classSubContents": "양파 일대잡종 “영보황”은 저장성이 좋은 웅성불임 모친과 구가 둥글고 맛\n이 좋은 화분친으로 교배하여 2007년부터 2009년까지 3년 동안 무안, 창녕,\n안동 등 지역적응 시험에서 우수하였음", "classSubContents2": "○ 양파 재배농가의 종자는 외국산 의존도 높아 외화 유출 심화\n-‘09 총 채소종자 수입액 중 28%\n○ 양파 재배농가 고 저장성 양파 육성 희망", "classSubHtml": "A01090429.html", "classSubIdx": "228", "classSubMaster": "농업연구사 이을태 061-450-0192", "classSubMovieUrl": null, "classSubPdf": "A01090429.pdf", "classSubTitle": "양파 일대잡종 “영보황” 개발", "classSubUse": "Y", "regDate": "2010-04-19 16:24:58.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('199', '가축이 좋아하는 삼차망 청보리 『유연』개발', '유연보리는 그동안 가축 급여시 저해요인이 되었던 날까로운 톱니 모양의 까락을 변형된 삼차망
으로 개선하였고, 줄기는 부드러워 가축의 기호성이 우수하며 건물수량이 1,080kg/10a로 조사료 
품질고급화 및 자급률 제고에 기여할 것임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090629", "classSubContents": "유연보리는 그동안 가축 급여시 저해요인이 되었던 날까로운 톱니 모양의 까락을 변형된 삼차망\n으로 개선하였고, 줄기는 부드러워 가축의 기호성이 우수하며 건물수량이 1,080kg/10a로 조사료 \n품질고급화 및 자급률 제고에 기여할 것임", "classSubContents2": "1) 목적\n   ○ 조사료 자급 “제2녹색혁명”의 조기 달성을 위한 기술적 지원\n   ○ 청보리 전용품종개발 및 보급으로 조사료 품질고급화 및 자급률 제고\n   ○ 경종농가의 소득보전 및 축산농가의 소득 증대 및 국제경쟁력 향상\n2) 필요성\n   ○ 배합사료 및 조사료 수입가격 급등으로 축산 농가 어려움 가중\n     - 배합사료 가격 : (‘07) 251/kg → (&#39;08) 482 (92% 증) \n     - 조사료 평균가격 : (‘07) 313원/kg → (&#39;08) 481 (54% 증) \n   ○ 국내 조사료 총수요는 &#39;12년 612만톤으로 국내산 조사료 확대공급 필요\n     - 급여비율 개선 : (‘07) 조사료 40 : 배합 60 → (&#39;12) 60 : 40\n     - 조사료 자급율 : (‘07) 78% → (&#39;12) 90\n   ○ 조사료 재배면적은 확대되고 있으나 종자공급 및 기술 확산 미흡\n     - &#39;08/&#39;09 청보리 재배(48천ha)에 필요한 종자(9,600톤)의 37%(3,546톤) 공급", "classSubHtml": "A01090629.html", "classSubIdx": "199", "classSubMaster": "담당자 : 농업연구관 박 태 일 063-840-2239", "classSubMovieUrl": null, "classSubPdf": "A01090629.pdf", "classSubTitle": "가축이 좋아하는 삼차망 청보리 『유연』개발", "classSubUse": "Y", "regDate": "2009-06-12 15:03:20.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('289', '도체품질 향상을 위한 비타민C 제제 급여기술', '○ 한우 거세우 장기 비육하는 고급육 생산농가에 적용시 효과적
○ 육성기 농후사료 제한사양과 조기거세 기술 적용 시 효과
○ 비타민C 첨가제 급여시 EC(에틸셀룰로스)코팅형과 지방코팅형 첨가제
이용시 육질 및 육량등급 개선효과 우수하여 도체의 품질이 향상', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090830", "classSubContents": "○ 한우 거세우 장기 비육하는 고급육 생산농가에 적용시 효과적\n○ 육성기 농후사료 제한사양과 조기거세 기술 적용 시 효과\n○ 비타민C 첨가제 급여시 EC(에틸셀룰로스)코팅형과 지방코팅형 첨가제\n이용시 육질 및 육량등급 개선효과 우수하여 도체의 품질이 향상", "classSubContents2": "○ 영양학적 조절에 의한 고급육생산 방법으로서 비타민A결핍사료가 개발\n되었으나, 증체의 저하와 근육수종 등의 문제가 발생하고 있어 고급육생\n산을 위한 영양조절에 의한 방법이 요구되고 있음\n○ 일본 화우에서 반추위 우회 지방코팅 비타민C를 12～24개월령까지 체중\nkg당 40mg 급여시 근내지방도와 조직감이 대폭 개선된 결과를 발표하\n였으나, 한우에 대한 연구결과 13～29개월령까지 급여 시 효과가 좋았음", "classSubHtml": "A01090830.html", "classSubIdx": "289", "classSubMaster": "농업연구사 장선식 (033-330-0615)", "classSubMovieUrl": null, "classSubPdf": "A01090830.pdf", "classSubTitle": "도체품질 향상을 위한 비타민C 제제 급여기술", "classSubUse": "Y", "regDate": "2010-04-20 10:03:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('256', '컨테이너형 식물공장을 이용한 신선채소 생산기술 개발', '남 극 등 극단적으로 불량한 환경에서도 에너지 소모를 최소화 하고, 안전
하게 채소를 생산할 수 있도록 컨테이너 단위의 식물공장을 개발하였다.
-40℃에서도 온도를 유지할수 있도록 벽면 20cm 두께로 우레탄 방열하였
고, 3단으로 재배 베드를 설치하여, 인공조명으로 최대한 공간활용도를 높
이도록 구성되어있다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090430", "classSubContents": "남 극 등 극단적으로 불량한 환경에서도 에너지 소모를 최소화 하고, 안전\n하게 채소를 생산할 수 있도록 컨테이너 단위의 식물공장을 개발하였다.\n-40℃에서도 온도를 유지할수 있도록 벽면 20cm 두께로 우레탄 방열하였\n고, 3단으로 재배 베드를 설치하여, 인공조명으로 최대한 공간활용도를 높\n이도록 구성되어있다.", "classSubContents2": "○ 남극 등 신선채소의 공급이 되지 못하는 지역에서 근무하는 연구원들을 위하여\n신선채소를 안정적으로 공급하여 연구능률 향상할 필요가 있음\n○ 에 너지의 소모를 최소화하고 안정적으로 신선채소를 재배할 수 있는 식\n물공장 시스템을 제작하고 신선채소 재배에 적합한 순환식 수경재배 기\n술을 확립하고자 함", "classSubHtml": "A01090430.html", "classSubIdx": "256", "classSubMaster": "농업연구관 엄영철 031)240-3657", "classSubMovieUrl": null, "classSubPdf": "A01090430.pdf", "classSubTitle": "컨테이너형 식물공장을 이용한 신선채소 생산기술 개발", "classSubUse": "Y", "regDate": "2010-04-19 18:11:17.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('200', '국내산 최고급 밀 브랜드‘참들락’개발', '국산밀의 안전성과 최고품질을 유지하기 위하여 재배, 수확, 저장, 가공, 유통 등의 일괄 생산관
리 체계화를 통한 대표 브랜드 개발로 국산 밀 소비 촉진 및 농가소득 향상에 기여 함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090630", "classSubContents": "국산밀의 안전성과 최고품질을 유지하기 위하여 재배, 수확, 저장, 가공, 유통 등의 일괄 생산관\n리 체계화를 통한 대표 브랜드 개발로 국산 밀 소비 촉진 및 농가소득 향상에 기여 함", "classSubContents2": "1) 목적\n   ○ 국내산 밀제품의 품질 고급화 및 차별화로 농가소득 향상\n   ○ 안전하고 우수한 국산 밀 공급확대로 자급률 제고\n\n 2) 필요성\n   ○ 국산밀은 생산관리 미흡과 유통 및 가공 시설 영세성으로 소비자 선호도가 낮음\n   ○ 생산관리 체계화를 통한 품질 향상으로 국내산 밀에 대한 소비자의 신뢰도 제고 및 \n      농가소득 향상 필요", "classSubHtml": "A01090630.html", "classSubIdx": "200", "classSubMaster": "담당자 : 농업연구관 정 영 근 063-840-2251", "classSubMovieUrl": null, "classSubPdf": "A01090630.pdf", "classSubTitle": "국내산 최고급 밀 브랜드‘참들락’개발", "classSubUse": "Y", "regDate": "2009-06-12 15:05:42.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('290', '말 사양관리프로그램 ‘Horse Power&#39; 활용', '마필 생산 농가, 관리자 등 관련 종사자들이 과학적 말 사양관리를 하기
위해, 말 성장단계별, 이용형태별 영양소 요구량 계산 및 영양진단이 가능
한 말 사양관리 프로그램 ‘Horse Power&#39; 활용', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090831", "classSubContents": "마필 생산 농가, 관리자 등 관련 종사자들이 과학적 말 사양관리를 하기\n위해, 말 성장단계별, 이용형태별 영양소 요구량 계산 및 영양진단이 가능\n한 말 사양관리 프로그램 ‘Horse Power&#39; 활용", "classSubContents2": "○ 경주마, 승용마, 육용마 등 말 사육두수가 꾸준히 증가하고 있음\n- 말 사육두수 : 10,597(‘90) → 16,302(’00) → 18,539(‘04) → 27,881(‘08)\n○ 마필 선진국에 비해 말 사양관리기술은 미진한 실정이며, 영양소 부족으로\n인한 경제적 손실 등 문제점 발생\n○ 말 품종별, 성장단계별, 이용형태별 등의 영양소 요구량을 결정하고, 이 요\n구량에 따른 사료 급여 및 영양진단 필요", "classSubHtml": "A01090831.html", "classSubIdx": "290", "classSubMaster": "농업연구사 이종언 (064-754-5721)", "classSubMovieUrl": null, "classSubPdf": "A01090831.pdf", "classSubTitle": "말 사양관리프로그램 ‘Horse Power&#39; 활용", "classSubUse": "Y", "regDate": "2010-04-20 10:04:31.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('257', '신선딸기 수출확대의 주역 “수경” 품종', '날 씨가 더운 동남아 국가로의 수출을 목표로 개발된 고품질 딸기 ‘수
경’은 촉성재배품종으로 11월 초순부터 수확할 수 있고 고온기에도 물
러지지 않아 5~6월까지 수출이 가능한 고경도의 수출유망 품종이다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090431", "classSubContents": "날 씨가 더운 동남아 국가로의 수출을 목표로 개발된 고품질 딸기 ‘수\n경’은 촉성재배품종으로 11월 초순부터 수확할 수 있고 고온기에도 물\n러지지 않아 5~6월까지 수출이 가능한 고경도의 수출유망 품종이다.", "classSubContents2": "○ 시 설딸기는 겨울철 난방수요가 작아 재배면적 증가로 산업적 비중이 큼\n○ 신 선딸기 수출은 2005년부터 동남아 시장으로 급속히 확대\n○ 로열티 지불로 인한 수출용 국내 품종 보급 절실", "classSubHtml": "A01090431.html", "classSubIdx": "257", "classSubMaster": "농업연구사 정재완 051)602-2124", "classSubMovieUrl": null, "classSubPdf": "A01090431.pdf", "classSubTitle": "신선딸기 수출확대의 주역 “수경” 품종", "classSubUse": "Y", "regDate": "2010-04-19 18:13:21.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('201', '녹비작물 헤어리베치 국산품종‘베치1호’개발', '베치1호는 화학비료 대체를 위하여 수집 유전자원을 순계 분리하여 최초로 개발한 품종으로 추위
에 강해서 월동율이 92.3%로 높고, 개화기가 수입품종(Welta)보다 13일이 빠르며, 생초량이 
2,424kg/10a로 많아서 질소 생산성이 높음.', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090631", "classSubContents": "베치1호는 화학비료 대체를 위하여 수집 유전자원을 순계 분리하여 최초로 개발한 품종으로 추위\n에 강해서 월동율이 92.3%로 높고, 개화기가 수입품종(Welta)보다 13일이 빠르며, 생초량이 \n2,424kg/10a로 많아서 질소 생산성이 높음.", "classSubContents2": "1) 목적\n   ○ 수입종 종자 대체 녹비작물 종자 국산화 제고 : (‘12) 80 → (’17) 100%\n   ○ 화학비료 대체 녹비작물 기술 개발로 친환경 농산물 생산 및 농가소득 증진\n\n2) 필요성\n   ○ 화학비료 가격 상승으로 농가 경영비 부담 증가\n    - 비료가격 : ’07 대비 평균 86% 상승 → 경영비 증가 7% 주도\n   ○ 녹비작물 재배확대에 따른 종자수급 및 녹비이용기술 개발 필요\n    - 재배면적 : (‘02)45천㏊ ⇒ (‘04)66 ⇒ (&#39;07)134(&#39;02대비 3배 증가)\n     * 녹비작물 종자 수급 : 전량 수입에 의존 (’08년도 7,408톤 수입)", "classSubHtml": "A01090631.html", "classSubIdx": "201", "classSubMaster": "담당자 : 농업연구사 김 민 태 031-290-6775", "classSubMovieUrl": null, "classSubPdf": "A01090631.pdf", "classSubTitle": "녹비작물 헤어리베치 국산품종‘베치1호’개발", "classSubUse": "Y", "regDate": "2009-06-12 15:07:12.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('291', '한우 알비노 개체 추적 및 판별을 위한 유전자 분석기법 활용', '흰 색(알 비노) 한우 송아지 발생의 유전적 원인을 구명하고, 열성 유전인자
를 가지고 있는 보인자까지 판별할 수 있는 유전자 분석법을 확립함으로써
농가의 피해 방지 및 한우 보증종모우 선발 등에 적용 가능한 기술', NULL, NULL, '{"classCode": "A010908", "className": "축산", "classSubCode": "A01090832", "classSubContents": "흰 색(알 비노) 한우 송아지 발생의 유전적 원인을 구명하고, 열성 유전인자\n를 가지고 있는 보인자까지 판별할 수 있는 유전자 분석법을 확립함으로써\n농가의 피해 방지 및 한우 보증종모우 선발 등에 적용 가능한 기술", "classSubContents2": "○ 여 러 보도 매체에서 흰색 한우 송아지의 출생에 대해 보도\n- 2 005 년 이후 전북 정읍, 전남 무안, 전북 순창, 대전 등\n○ 최 근까지 정확한 발생원인 미 구명\n- 한 우 등록 시 결격사유에 해당\n- 도 축 시 육안판독 → 교잡우 취급 → 농가 피해 우려\n- 산 발적 으로 계속적인 발생 우려가 있어 발생 원인 구명 시급", "classSubHtml": "A01090832.html", "classSubIdx": "291", "classSubMaster": "농업연구사 이성수 (064-754-5710)", "classSubMovieUrl": null, "classSubPdf": "A01090832.pdf", "classSubTitle": "한우 알비노 개체 추적 및 판별을 위한 유전자 분석기법 활용", "classSubUse": "Y", "regDate": "2010-04-20 10:31:20.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('258', '&#39;홍로’ 사과 품종을 특이적으로 판별하는 DNA마커 개발', '본 기술은 우리나라에서 육성된 사과 품종인 ‘홍로’의 잎에서 추출한
DNA를 이용하여 과실이 결실되기 전 유목기에도 품종을 정확하게 구별
할 수있는 유전자 기술로 국내 사과 품종 보호와 품종혼입으로 발생하는
분쟁해결에 효율적으로 활용할 수 있음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090432", "classSubContents": "본 기술은 우리나라에서 육성된 사과 품종인 ‘홍로’의 잎에서 추출한\nDNA를 이용하여 과실이 결실되기 전 유목기에도 품종을 정확하게 구별\n할 수있는 유전자 기술로 국내 사과 품종 보호와 품종혼입으로 발생하는\n분쟁해결에 효율적으로 활용할 수 있음", "classSubContents2": "○ 사과 ‘홍로’ 품종의 재배면적 증가로 지속적인 우량 묘목 공급이 요구\n- 재 배면 적 : (’97) 577ha, 1.4% → (’07) 3,381ha, 10.6%\n○ 일 반적으로 사과 국내육성 품종들은 내수용과 수출용 모두 묘목 상태\n로 공급되고 있어 형태적으로 품종 판별이 불가능\n○ 과 수 묘목 생산 및 유통현장에서 다른 품종이 섞여 생산자와 농업인간\n의 분쟁이 많이 발생하고 있음\n○ 따 라서 과수 묘목 선도업체 등에서 품종판별을 위한 분자표지 기술 개\n발의 요구도가 증가하고 있음", "classSubHtml": "A01090432.html", "classSubIdx": "258", "classSubMaster": "농업연구사 조강희 031)240-3676", "classSubMovieUrl": null, "classSubPdf": "A01090432.pdf", "classSubTitle": "&#39;홍로’ 사과 품종을 특이적으로 판별하는 DNA마커 개발", "classSubUse": "Y", "regDate": "2010-04-19 18:15:20.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('202', '벼 흰잎마름병 신균계(K3a) 저항성 품종‘진백’개발', '진백은 벼 흰잎마름병 발병상습지와 새로운 변이균(K3a) 출현으로 피해면적이 증가되는 지역에 
적합한 저항성 품종으로 고품질이면서 쌀수량은 530kg/10a로 친환경 쌀 생산 및 농가소득에 기여
할 것임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090632", "classSubContents": "진백은 벼 흰잎마름병 발병상습지와 새로운 변이균(K3a) 출현으로 피해면적이 증가되는 지역에 \n적합한 저항성 품종으로 고품질이면서 쌀수량은 530kg/10a로 친환경 쌀 생산 및 농가소득에 기여\n할 것임", "classSubContents2": "1) 목적\n   ○ 벼 흰잎마름병 발병상습지에서 수량 및 재배 안정화\n   ○ 고품질 쌀 생산 및 화학농약 사용 절감으로 인한 농가소득 증대\n2) 필요성\n   ○ 벼 흰잎마름병 우점레이스의 변화 및 발생면적 증가\n     - 우점 레이스 변화 : K1, K2, K3 → K3a, K4, K5\n     - 발병면적(ha) : 918(&#39;01) → 29,485(&#39;06) → 19,605(&#39;08)\n   ○ 육성 벼품종의 급속한 이병화 및 방제약제가 없음\n     - 국내 벼 품종보유 흰잎마름병 저항성 유전자 : Xa1, Xa3\n     - 세균병으로 뚜렷한 약제방제효과가 없어 저항성품종 육성이 시급함", "classSubHtml": "A01090632.html", "classSubIdx": "202", "classSubMaster": "담당자 : 농업연구사 김 기 영 063-840-2162", "classSubMovieUrl": null, "classSubPdf": "A01090632.pdf", "classSubTitle": "벼 흰잎마름병 신균계(K3a) 저항성 품종‘진백’개발", "classSubUse": "Y", "regDate": "2009-06-12 15:09:09.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('259', '생식용 포도 ‘홍아람’ 및 양조용 포도 ‘나르샤’', '이색 적이고 다양한 포도를 원하는 소비자의 기호성을 충족시키고 국내 포
도주 산업 활성화와 대한민국 특화 포도주 생산을 위해 교배 육종을 통
한 전략적인 포도 품종 개발', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090433", "classSubContents": "이색 적이고 다양한 포도를 원하는 소비자의 기호성을 충족시키고 국내 포\n도주 산업 활성화와 대한민국 특화 포도주 생산을 위해 교배 육종을 통\n한 전략적인 포도 품종 개발", "classSubContents2": "○ 새로 운 소비기호에 따른 포도 생과 수입증가 및 국산 포도에 대한 품질만\n족도 저하 등으로 포도 소비가 점차 다른 과종으로 이탈되고 있음\n- 포 도생 과 수입물량 : (’00) 7.9 → (’04) 9.9 → (’08) 32.5천톤\n○ 최 근 웰빙 소비추세에 힘입어 포도주 수입량은 급증하고 있음\n- 포 도주 수입물량 : (&#39;01) 8.9 → (&#39;06) 22 → (&#39;07) 31천톤(150백만불)\n○ 따라 서, 소비를 선도할 수 있는 생식용 및 양조용 품종 개발&#8228;보급이 시급함", "classSubHtml": "A01090433.html", "classSubIdx": "259", "classSubMaster": "농업연구사 노정호 031)240-3696", "classSubMovieUrl": null, "classSubPdf": "A01090433.pdf", "classSubTitle": "생식용 포도 ‘홍아람’ 및 양조용 포도 ‘나르샤’", "classSubUse": "Y", "regDate": "2010-04-19 18:16:14.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('229', '미량영양소 고함유 벼품종 ‘고아미4호’', '쌀에는 인체에 필요한 철분 및 아연 등 미량원소의 성분이 부족하기 때문에
이러한 성분이 강화된 쌀은 소비자의 건강증진에 큰 도움을 줄 수 있어 미
량영양소 함량이 높은 벼 품종을 개발하였음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090633", "classSubContents": "쌀에는 인체에 필요한 철분 및 아연 등 미량원소의 성분이 부족하기 때문에\n이러한 성분이 강화된 쌀은 소비자의 건강증진에 큰 도움을 줄 수 있어 미\n량영양소 함량이 높은 벼 품종을 개발하였음", "classSubContents2": "○ 소비자의 건강 증진에 대한 관심 증가에 따른 기능성 벼 품종의 요구도가\n증대되고 있음\n○ 최근 쌀 소비 감소에 의한 주곡의 안정적인 생산기반 유지를 위해 기능성\n품종의 개발이 시급함", "classSubHtml": "A01090633.html", "classSubIdx": "229", "classSubMaster": "농업연구사 양창인 031-290-6702", "classSubMovieUrl": null, "classSubPdf": "A01090633.pdf", "classSubTitle": "미량영양소 고함유 벼품종 ‘고아미4호’", "classSubUse": "Y", "regDate": "2010-04-19 16:27:03.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('260', '고품질 신수요 창출형 사과 ‘황옥’ 및 ‘아이사랑’', '사과 품종의 다양화를 위해서 과실이 크지 않으면서 색깔이 황색인 ‘황
옥’과 붉은색인 ‘아이사랑’을 육성', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090434", "classSubContents": "사과 품종의 다양화를 위해서 과실이 크지 않으면서 색깔이 황색인 ‘황\n옥’과 붉은색인 ‘아이사랑’을 육성", "classSubContents2": "○ 기 존의 주요 재배품종은 대부분 적색의 대과성 품종임\n○ 재 배면적 증가로 과잉생산이 우려되며, 착색불량 등 기후 온난화에 따\n른 문제점 발생 증가\n○ 다 양한 소비자들의 욕구 충족으로 소비의 저변확대를 꾀하고 기후 변화\n에 대응할 수 있는 고품질의 차별화된 품종 육성 필요", "classSubHtml": "A01090434.html", "classSubIdx": "260", "classSubMaster": "농업연구관 김목종 054)380-3130", "classSubMovieUrl": null, "classSubPdf": "A01090434.pdf", "classSubTitle": "고품질 신수요 창출형 사과 ‘황옥’ 및 ‘아이사랑’", "classSubUse": "Y", "regDate": "2010-04-20 09:05:26.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('230', '세계최초 사일리지용 다수성 총체밀 &#39;청우&#39; 개발', '범국가적으로 추진하고 있는 조사료 자급률 향상을 위하여 사료맥류 작목을
다양화하고 양질의 조사료를 생산할 필요성이 대두되어 세계 최초로 조사료
전용 총체밀을 개발', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090634", "classSubContents": "범국가적으로 추진하고 있는 조사료 자급률 향상을 위하여 사료맥류 작목을\n다양화하고 양질의 조사료를 생산할 필요성이 대두되어 세계 최초로 조사료\n전용 총체밀을 개발", "classSubContents2": "1) 목적\n○ 수요자의 조사료 작물에 대한 선택의 폭을 확대하고 양질 조사료 생산\n및 조사료 자급률 향상\n○ 사료맥류의 작물을 연계 재배함으로써 작물별 수확적기에 양질조사료를\n생산하고 대형기계의 작업기간 연장으로 효율성 제고\n2) 필요성\n○ 겨울철 유휴지를 활용한 사료맥류 연계재배 확대 필요\n- 사료맥류 작물의 다양화를 통한 양질의 조사료 생산\n○ 기존 청보리 위주의 수확작업은 수확기계의 작업효율 저하\n- 청보리 단일 작물의 대단위 면적 재배 및 짧은 기간의 수확작업은 비싼 농\n기계의 효율성이 떨어뜨리고 사일리지 품질저하의 원인이 됨\n- 총체밀은 수확적기가 청보리보다 늦어 청보리 수확 후 연계수확 가능", "classSubHtml": "A01090634.html", "classSubIdx": "230", "classSubMaster": "농업연구사 김경훈 063-840-2164", "classSubMovieUrl": null, "classSubPdf": "A01090634.pdf", "classSubTitle": "세계최초 사일리지용 다수성 총체밀 &#39;청우&#39; 개발", "classSubUse": "Y", "regDate": "2010-04-19 16:28:33.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('261', '추석출하 및 수출용 고품질 중생종 ‘신화’, 창조’ 육성', '추 석 명절은 배 과실을 가장 많이 소비하는 시기이지만 음력이 기준인
추석은 9월 상순에서 10월 상순까지 변화폭이 넓은 반면에 가장 많이
재배되고 있는 신고는 10월 상순에 수확되어 이른 추석에 출하할 수
있는 중생종의 고품질 배 ‘신화’와 ‘창조’를 육성하게 됨.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090435", "classSubContents": "추 석 명절은 배 과실을 가장 많이 소비하는 시기이지만 음력이 기준인\n추석은 9월 상순에서 10월 상순까지 변화폭이 넓은 반면에 가장 많이\n재배되고 있는 신고는 10월 상순에 수확되어 이른 추석에 출하할 수\n있는 중생종의 고품질 배 ‘신화’와 ‘창조’를 육성하게 됨.", "classSubContents2": "○ ‘신 고’ 배의 재배면적은 전체 배의 81.5%(’07, 과수실태조사)를 차지하\n고 있어 추석이 빠른 해에는 미숙과 출하가 우려됨\n○ 단 일 품종 편중재배로 추석이 빠른 해에 추석 명절에 배를 시장에 공\n급하기 위해 적정 수확기보다 일찍 수확하는 사례가 빈번함\n- 배 에 대한 소비자들의 부정적 이미지가 점차 커지고 있음\n○ 이 른 추석에 출하할 수 있는 고품질의 중생종으로 재배가 용이한 배\n품종에 대한 요구가 증대됨\n○ 생 산자와 소비자를 동시에 만족시킬 수 있는 기존의 ‘신고’와 유사한\n재배 및 유통 특성을 가진 고품질의 중생종 품종을 육성하게 됨", "classSubHtml": "A01090435.html", "classSubIdx": "261", "classSubMaster": "농업연구사 강삼석 061)330-1541", "classSubMovieUrl": null, "classSubPdf": "A01090435.pdf", "classSubTitle": "추석출하 및 수출용 고품질 중생종 ‘신화’, 창조’ 육성", "classSubUse": "Y", "regDate": "2010-04-20 09:06:15.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('231', '수입종보다 맛과 당도가 뛰어난 단옥수수 ‘구슬옥’', '국내 최초로 개발된 고당도 유전자 sugary enhancer(se) 계열의 간식용 단
옥수수 ‘구슬옥’은 당도가 높은 초당옥수수와 발아율이 좋은 단옥수수의 장
점을 집약시킨 신품종임. 기존의 수입종 단옥수수에 비하여 당도가 높으면
서도 씹었을 때 찰옥수수처럼 쫄깃한 느낌을 주어 한국인의 입맛에 알맞음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090635", "classSubContents": "국내 최초로 개발된 고당도 유전자 sugary enhancer(se) 계열의 간식용 단\n옥수수 ‘구슬옥’은 당도가 높은 초당옥수수와 발아율이 좋은 단옥수수의 장\n점을 집약시킨 신품종임. 기존의 수입종 단옥수수에 비하여 당도가 높으면\n서도 씹었을 때 찰옥수수처럼 쫄깃한 느낌을 주어 한국인의 입맛에 알맞음", "classSubContents2": "○ 수입 단옥수수는 당도가 떨어지고, 초당옥수수는 발아율이 낮아 재배가\n어렵고 이삭의 씹는 맛이 나빠 농가에서 외면당하고 있는 실정임\n○ 단옥수수와 초당옥수수 종자는 국산품종의 공급이 미미하여, 매년 수입\n에 의존하여 왔으며 그나마도 초당옥수수의 경우는 2009년에 수입이 전\n무하여 신품종의 보급이 요구되는 상황임.", "classSubHtml": "A01090635.html", "classSubIdx": "231", "classSubMaster": "농업연구관 백성범 031-290-6760", "classSubMovieUrl": null, "classSubPdf": "A01090635.pdf", "classSubTitle": "수입종보다 맛과 당도가 뛰어난 단옥수수 ‘구슬옥’", "classSubUse": "Y", "regDate": "2010-04-19 17:31:16.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('262', '에틸렌 발생제를 이용한 떫은 감 연시 제조 방법 개발', '떫 은 감은 자연 상태에서 연시가 될 확률이 10～20% 정도 이므로 인위적으로
연시를 만들어야 하는데 위생적이고 안전한 과실 후숙 촉진제인 ‘에틸렌발
생제’를 개발하여 연시를 효율적으로 제조함', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090436", "classSubContents": "떫 은 감은 자연 상태에서 연시가 될 확률이 10～20% 정도 이므로 인위적으로\n연시를 만들어야 하는데 위생적이고 안전한 과실 후숙 촉진제인 ‘에틸렌발\n생제’를 개발하여 연시를 효율적으로 제조함", "classSubContents2": "○ 떫은 감은 유해물질인 ‘카바이드’로 연시를 제조하여 작업자의 안전성과 소비자의\n보건 위생상 문제점으로 대두되고 있음\n○ 안전 한 물질인 에틸렌을 이용하여 연시 및 후숙 촉진 기술을 개발하고자 함", "classSubHtml": "A01090436.html", "classSubIdx": "262", "classSubMaster": "농업연구사 홍윤표 031)240-3672", "classSubMovieUrl": null, "classSubPdf": "A01090436.pdf", "classSubTitle": "에틸렌 발생제를 이용한 떫은 감 연시 제조 방법 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:07:31.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('232', '콩 소립 녹색자엽 검정콩 &#39;소흑&#39;', '소립 녹색자엽 검정콩 신품종 “소흑”은 기능성 약콩으로 재래종 쥐눈이콩을
대체하기 위해 개발되었으며, 기존 소립 검정콩의 물을 잘 흡수하지 않는 단
점을 개량한 것으로 키가 작고 도복에 강하며 청국장 가공적성이 우수함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090636", "classSubContents": "소립 녹색자엽 검정콩 신품종 “소흑”은 기능성 약콩으로 재래종 쥐눈이콩을\n대체하기 위해 개발되었으며, 기존 소립 검정콩의 물을 잘 흡수하지 않는 단\n점을 개량한 것으로 키가 작고 도복에 강하며 청국장 가공적성이 우수함", "classSubContents2": "○ 소립 녹색자엽 검정콩으로 콩 품종개발\n○ 건강기능성이 우수한 약콩 콩 품종개발\n○ 검정콩으로 청국장 등 가공적성이 우수한 품종개발", "classSubHtml": "A01090636.html", "classSubIdx": "232", "classSubMaster": null, "classSubMovieUrl": null, "classSubPdf": "A01090636.pdf", "classSubTitle": "콩 소립 녹색자엽 검정콩 &#39;소흑&#39;", "classSubUse": "Y", "regDate": "2010-04-19 17:32:07.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('263', '포도 수출시 선도유지 시스템 개발', '포 도 수출 또는 장기 저장시 품질을 보전하기 위해, 부패억제를 위해서
는 수확후 또는 선별 전 이산화염소 훈증을, 시들음 억제를 위해서는
2%유공 PE0.03mm 필름으로 속포장하며, 수확후부터 저장, 전처리, 선
별, 유통시 적정 저온을 제시하였음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090437", "classSubContents": "포 도 수출 또는 장기 저장시 품질을 보전하기 위해, 부패억제를 위해서\n는 수확후 또는 선별 전 이산화염소 훈증을, 시들음 억제를 위해서는\n2%유공 PE0.03mm 필름으로 속포장하며, 수확후부터 저장, 전처리, 선\n별, 유통시 적정 저온을 제시하였음", "classSubContents2": "○ 포 도 수출의 꾸준한 증가추세 : (’05) 817 → (’08) 1,588 천불\n※ 주요 수출국 : 미국, 싱가포르, 괌, 홍콩, 베트남, 인도네시아, 하와이, 캐나다 등\n○ 수출 국까지 최대 12~15일 정도의 선박운송 기간이 소요되며, 수출중 곰팡\n이병, 탈립 및 중량감소에 의한 시들음이 문제가 되고 있음", "classSubHtml": "A01090437.html", "classSubIdx": "263", "classSubMaster": "농업연구사 조미애 031)240-3689", "classSubMovieUrl": null, "classSubPdf": "A01090437.pdf", "classSubTitle": "포도 수출시 선도유지 시스템 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:08:35.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('233', '콩잎 쌈 이용 대립 검정콩 &#39;청엽&#39;', '주로 우리나라의 제주도 지역에서 회나 고기를 쌈싸서 먹을때 콩잎을 이용
하고 있다. 콩잎으로 이용되는 것은 콩알이 굵고 잎이 크며 줄기의 직경이 두
꺼워 채엽시 쉽게 부러지지 않아 작업에 편리한 것이 선호되고 있다. 지금까
지 농가에서는 재래종인 서리태나 일본에서 수입된 단파흑두 종자를 심고 있
어왔다. “청엽”은 재래종과 수입종자를 대체하기 위해 개발되었으며, 쌈용 콩
잎으로서 가지는 특성과 콩잎의 건강 기능성이 매우 우수함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090637", "classSubContents": "주로 우리나라의 제주도 지역에서 회나 고기를 쌈싸서 먹을때 콩잎을 이용\n하고 있다. 콩잎으로 이용되는 것은 콩알이 굵고 잎이 크며 줄기의 직경이 두\n꺼워 채엽시 쉽게 부러지지 않아 작업에 편리한 것이 선호되고 있다. 지금까\n지 농가에서는 재래종인 서리태나 일본에서 수입된 단파흑두 종자를 심고 있\n어왔다. “청엽”은 재래종과 수입종자를 대체하기 위해 개발되었으며, 쌈용 콩\n잎으로서 가지는 특성과 콩잎의 건강 기능성이 매우 우수함", "classSubContents2": "○ 재래종과 수입종자를 대체하기 위한 쌈용 콩 품종개발\n○ 콩잎의 건강기능성이 우수한 콩 품종개발", "classSubHtml": "A01090637.html", "classSubIdx": "233", "classSubMaster": "농업연구사 한원영 055-350-1244", "classSubMovieUrl": null, "classSubPdf": "A01090637.pdf", "classSubTitle": "콩잎 쌈 이용 대립 검정콩 &#39;청엽&#39;", "classSubUse": "Y", "regDate": "2010-04-19 17:32:53.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('264', '감귤을 이용한 의료용 소재 개발', '인공 피부에 이용되는 겔은 감귤에서 유래된 물질로 수분보유력(97.5%)이
뛰어나고 고형분의 80% 이상이 순수 식물성 cellulose로서 발효균이 감
귤에 있는 영양분을 사용하여 제조한 것임. 기 존균보다 겔을 2배 이상
빠르게 만들어 내는 능력을 지닌 생성균을 찾아내어 신속하고 간단하게
고품질 겔을 제조·생산할 수 있는 기반을 확립', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090438", "classSubContents": "인공 피부에 이용되는 겔은 감귤에서 유래된 물질로 수분보유력(97.5%)이\n뛰어나고 고형분의 80% 이상이 순수 식물성 cellulose로서 발효균이 감\n귤에 있는 영양분을 사용하여 제조한 것임. 기 존균보다 겔을 2배 이상\n빠르게 만들어 내는 능력을 지닌 생성균을 찾아내어 신속하고 간단하게\n고품질 겔을 제조·생산할 수 있는 기반을 확립", "classSubContents2": "○ 감귤 등 생과 소비는 2000년대 이후 정체 상태임\n○ 새로 운 소비 창출을 위해 국민건강에 기여할 수 있는 제품 개발이 필요함\n○ 감귤 과잉생산 문제 해결을 위한 가공산업의 활성화가 필요함 : 10만톤/년", "classSubHtml": "A01090438.html", "classSubIdx": "264", "classSubMaster": "농업연구관 최영훈 064)730-4107", "classSubMovieUrl": null, "classSubPdf": "A01090438.pdf", "classSubTitle": "감귤을 이용한 의료용 소재 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:09:43.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('234', '국내 최초 녹비작물 헤어리베치 ‘보라’ 개발', '비료가격 상승과 친환경농업의 확산으로 녹비작물 재배면적이 증가됨에 따
라 전량 수입하는 녹비작물 종자의 안정적인 공급을 위하여 국내 최초로
헤어리베치 신품종 ‘보라’를 개발 하였으며, 농가보급을 위해 우량종자를 생
산하고 있음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090638", "classSubContents": "비료가격 상승과 친환경농업의 확산으로 녹비작물 재배면적이 증가됨에 따\n라 전량 수입하는 녹비작물 종자의 안정적인 공급을 위하여 국내 최초로\n헤어리베치 신품종 ‘보라’를 개발 하였으며, 농가보급을 위해 우량종자를 생\n산하고 있음", "classSubContents2": "○ 최근 친환경농업의 확대와 소비자의 안전농산물 수요가 증가되면서 화학비\n료를 대체할 녹비작물 재배면적이 급속히 증가\n○ 지금까지 녹비작물 종자는 매년 외국에서 전량 수입해 왔으며 2009년의 경\n우 그 양이 13,614톤(269억원)에 달할 만큼 외화유출이 컸음\n○ 녹비작물 종자의 국산화를 위하여 화학비료 대체효과가 우수한 헤어리베\n치의 품종개발이 필요함", "classSubHtml": "A01090638.html", "classSubIdx": "234", "classSubMaster": "농업연구사 김민태 031-290-6775", "classSubMovieUrl": null, "classSubPdf": "A01090638.pdf", "classSubTitle": "국내 최초 녹비작물 헤어리베치 ‘보라’ 개발", "classSubUse": "Y", "regDate": "2010-04-19 17:33:47.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('265', '식물의 기능성과 IT를 활용한 생활원예 상품 개발', '식 물의 이용확대를 위하여 소비자가 가상공간에서 자유롭게 꾸며볼 수
있는 디지털 온라인 정원 프로그램, 핸드폰을 이용하여 손쉽게 원하는 식
물정보를 받을 수 있는 식물관리정보 시스탬, 식물의 공기정화 기능성을
활용한 친환경 식물-공기청정기 및 실용화 모델 등을 개발하였다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090439", "classSubContents": "식 물의 이용확대를 위하여 소비자가 가상공간에서 자유롭게 꾸며볼 수\n있는 디지털 온라인 정원 프로그램, 핸드폰을 이용하여 손쉽게 원하는 식\n물정보를 받을 수 있는 식물관리정보 시스탬, 식물의 공기정화 기능성을\n활용한 친환경 식물-공기청정기 및 실용화 모델 등을 개발하였다.", "classSubContents2": "○ 새집 증후군, 환경호르몬 등 국민의 실내 공기에 대한 관심 증가\n- 포 름알 데히드 등 10종의 유해물질 허용기준 설정(’05. 12월 시행)\n○ 최근 도시민들의 생활방식이 개인의 건강과 사회의 지속가능성을 강조한 로\n하스(LOHAS) 확대로 생활원예 관심 증대\n- 분화 소 비량 증가 : (’01) 4.9 → (’03) 5.6 → (’08) 8.3천원/인/년", "classSubHtml": "A01090439.html", "classSubIdx": "265", "classSubMaster": "농업연구관 정명일 031)290-6149", "classSubMovieUrl": null, "classSubPdf": "A01090439.pdf", "classSubTitle": "식물의 기능성과 IT를 활용한 생활원예 상품 개발", "classSubUse": "Y", "regDate": "2010-04-20 09:12:07.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('235', '중부지역에서 춘파 가능한 경관겸용 녹비작물 추천', '중부지역에서 봄에 파종하여 아름다운 꽃 경관을 보여주면서 화학비료 대
체용으로 사용 할 수 있는 녹비작물로서 크림손클로버, 황화초, 메밀, 파
셀리아, 루핀 등을 선발하였음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090639", "classSubContents": "중부지역에서 봄에 파종하여 아름다운 꽃 경관을 보여주면서 화학비료 대\n체용으로 사용 할 수 있는 녹비작물로서 크림손클로버, 황화초, 메밀, 파\n셀리아, 루핀 등을 선발하였음", "classSubContents2": "○ 농촌의 고령화 및 기계화로 휴경지면적이 증가하고 있음\n- 휴경률(%) : ‘85(0.9%) → ‘90(1.9) → ‘00(0.9) → ‘07(2.1)\n○ 지역단위별 문화관광축제, 농촌의 관광사업 급증으로 경관조성 및 지력유지\n를 동시에 할 수 있는 경관겸용 녹비작물 필요\n- ‘09년 지역단위 문화관광축제 : 16개시군 898건\n- ‘05년부터 경관보전직불금 지원 : 100 ~ 170만원/ha\n○ 경관 및 녹비겸용을 위하여 여러 종류의 녹비작물이 요구되고 있으나 중부\n지역에서 가을에 파종하여 이용 가능한 녹비작물은 녹비보리, 헤어리베치\n로 한정되어 있음\n○ 녹비작물의 이용 확대와 농민의 욕구 충족을 위하여 농경지에 이용 가능\n한 녹비작물의 종류를 다양화 할 필요가 있음", "classSubHtml": "A01090639.html", "classSubIdx": "235", "classSubMaster": "농업연구사 조현숙 031-290-6784", "classSubMovieUrl": null, "classSubPdf": "A01090639.pdf", "classSubTitle": "중부지역에서 춘파 가능한 경관겸용 녹비작물 추천", "classSubUse": "Y", "regDate": "2010-04-19 17:34:40.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('266', '수출 및 수입 대체용 난 신품종', '분화 꽃으로 인기가 높은 심비디움과 팔레놉시스의 수출 및 수입대체를 위해 생
육이 강건하고 화색, 화형 등이 우수한 형질을 가진 유전자원을 양친으로 활용, 교
배하여 후대 양성과 선발, 특성검정을 거쳐 최종적으로 품종으로 개발하였다', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090440", "classSubContents": "분화 꽃으로 인기가 높은 심비디움과 팔레놉시스의 수출 및 수입대체를 위해 생\n육이 강건하고 화색, 화형 등이 우수한 형질을 가진 유전자원을 양친으로 활용, 교\n배하여 후대 양성과 선발, 특성검정을 거쳐 최종적으로 품종으로 개발하였다", "classSubContents2": "○ 우 리나라 화훼의 분화류 중 생산액이 가장 높은 작목\n- 재 배면 적 : (&#39;01) 305 → (&#39;08) 268ha, 감소 추세\n- 생 산 액 : (&#39;01) 1,240 → (&#39;08) 1,032억원, 감소 추세\n- 수 출 액 : (&#39;01) 474 → (&#39;08) 2,597만$, 수출 증가\n○ 수출 화훼 1위 작목이나 종묘를 전량 수입에 의존하고 있어 농가 부담이 큼\n- 로 열티 지불 추정액(’08) : 약 27억원/년", "classSubHtml": "A01090440.html", "classSubIdx": "266", "classSubMaster": "농업연구사 김미선 031)290-6146", "classSubMovieUrl": null, "classSubPdf": "A01090440.pdf", "classSubTitle": "수출 및 수입 대체용 난 신품종", "classSubUse": "Y", "regDate": "2010-04-20 09:12:54.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('236', '‘무균포장밥’을 비롯한 식은밥 가공적성 우수품종 ‘주안벼’', '편의식품 소비증가로 인하여 무균포장밥, 삼각김밥 등 편의식품 전용품종 요
구도가 증가하고 있는 시점에서 식은밥과 무균포장밥의 밥맛이 기존 원료곡인
추청벼나 고시히까리보다 우수한 ‘주안벼’를 선발하여 국내유명식품업체와 공동
으로 산업화를 준비 중임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090640", "classSubContents": "편의식품 소비증가로 인하여 무균포장밥, 삼각김밥 등 편의식품 전용품종 요\n구도가 증가하고 있는 시점에서 식은밥과 무균포장밥의 밥맛이 기존 원료곡인\n추청벼나 고시히까리보다 우수한 ‘주안벼’를 선발하여 국내유명식품업체와 공동\n으로 산업화를 준비 중임", "classSubContents2": "○ 쌀 소비확대를 위한 가공 용도별 맞춤형 벼 품종개발이 필요함\n- ‘무균포장밥’ 소비량 증가 : (‘04) 5.2천톤 → (‘06) 7.9 → (’08) 10.1\n* 일본 : (‘96) 19천톤 → (‘06) 94 → (’08) 105\n○ 최근 학교급식, 레저 및 기내식 등 가공밥(즉석밥) 이용 확대\n- 무균포장밥, 도식락, 삼각김밥 및 샌드위치 등 편의식품 소비증가\n* ’09상반기 즉석밥 판매량 : ‘08 대비 38% 증가(2～3천원대 도시락 683% 증가)\n○ 맞춤형 우량품종을 활용한 편의식품 품질향상 및 산업화 촉진이 요구됨\n○ 국내육성 품종을 공시하여 무균포장밥, 삼각김밥 및 도시락 등 가공밥용으\n로 적합한 품종을 선발하고, 농가보급확대와 산업화를 목적으로 본 연구를\n추진하였음", "classSubHtml": "A01090640.html", "classSubIdx": "236", "classSubMaster": "농업연구사 오세관 031-290-6722", "classSubMovieUrl": null, "classSubPdf": "A01090640.pdf", "classSubTitle": "‘무균포장밥’을 비롯한 식은밥 가공적성 우수품종 ‘주안벼’", "classSubUse": "Y", "regDate": "2010-04-19 17:35:30.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('267', '수출용 스프레이 국화 2009신품종', '국 내 수집, 조사된 유전자원을 이용하여 새로운 화색 또는 화형을 지닌
소비자 기호성 국화 품종을 개발, 보급함으로서 내수 및 수출 증대에 기여', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090441", "classSubContents": "국 내 수집, 조사된 유전자원을 이용하여 새로운 화색 또는 화형을 지닌\n소비자 기호성 국화 품종을 개발, 보급함으로서 내수 및 수출 증대에 기여", "classSubContents2": "○ 우 리나라 화훼류 중 비중이 큰 작목으로 국산 품종 수출 활성화\n- 재 배면 적 : (&#39;01) 751 → (&#39;08) 723ha, 현상 유지\n- 생 산 액 : (&#39;01) 587 → (&#39;08) 828억원, 증가 추세\n- 수 출 액 : (&#39;01) 725 → (&#39;09) 798만$, 증가 추세\n○ 육 성 품종 대일 수출량 증가 : 전체 수출량의 (’08) 20 → (’09) 35%\n○ 대 외 로열티 지불 부담 증가 : 로열티 지불 추정액 (’08) 10.8억원", "classSubHtml": "A01090441.html", "classSubIdx": "267", "classSubMaster": "농업연구사 임진희 031)290-6144", "classSubMovieUrl": null, "classSubPdf": "A01090441.pdf", "classSubTitle": "수출용 스프레이 국화 2009신품종", "classSubUse": "Y", "regDate": "2010-04-20 09:14:09.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('237', '양조용 맞춤형 품종「설갱벼」산업화', '양조용 맞춤형 품종인 설갱벼를 개발하여 국순당 ‘백세주 담’의 원료곡 제
공으로 제품의 품질 고급화 및 농가 계약재배로 농가소득 증대에 기여함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090641", "classSubContents": "양조용 맞춤형 품종인 설갱벼를 개발하여 국순당 ‘백세주 담’의 원료곡 제\n공으로 제품의 품질 고급화 및 농가 계약재배로 농가소득 증대에 기여함", "classSubContents2": "○ 기능성 특수미 품종 설갱벼의 재배 확대를 통한 농가소득 증대\n○ 양조용 맞춤형 품종의 산업화를 통한 국내 양조제품의 품질 향상", "classSubHtml": "A01090641.html", "classSubIdx": "237", "classSubMaster": "농업연구사 천아름 031-290-6720", "classSubMovieUrl": null, "classSubPdf": "A01090641.pdf", "classSubTitle": "양조용 맞춤형 품종「설갱벼」산업화", "classSubUse": "Y", "regDate": "2010-04-19 17:36:17.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('268', '병에 강하고 절화수명이 우수한 장미 신품종', '장미 는 우리나라 화훼중 비중이 큰 작목이나 외국 품종 재배시 농가의 로
열티 부담이 커 국산품종 개발이 시급한 작목임. ‘92년부터 품종개발을 시
작하여 현재까지 매직레드 등 50품종을 개발하였으며 이 품종들은 절화수
명이 우수하고 병에 강해 농약비용 및 병방제 노동력 절감이 가능하고 앞
으로 육성품종 재배가 확대되면 로열티 절감 및 한국기후에 적합한 품종
재배로 고품질 절화 생산이 가능하여 농가소득이 증대될 것으로 전망', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090442", "classSubContents": "장미 는 우리나라 화훼중 비중이 큰 작목이나 외국 품종 재배시 농가의 로\n열티 부담이 커 국산품종 개발이 시급한 작목임. ‘92년부터 품종개발을 시\n작하여 현재까지 매직레드 등 50품종을 개발하였으며 이 품종들은 절화수\n명이 우수하고 병에 강해 농약비용 및 병방제 노동력 절감이 가능하고 앞\n으로 육성품종 재배가 확대되면 로열티 절감 및 한국기후에 적합한 품종\n재배로 고품질 절화 생산이 가능하여 농가소득이 증대될 것으로 전망", "classSubContents2": "○ 우 리나라 화훼류 중 비중이 큰 작목임\n- 재 배면 적 : (’01) 728 → (’08) 578ha, 감소 추세\n- 생 산 액 : (’01) 1,498 → (’08) 1,301억원, 완만한 감소 추세\n- 수 출 액 : (’01) 1,022 → (’08) 1,181만$, 지속 수출\n○ 품 종 기호도의 변화가 빨라 새로운 품종 개발 수요가 큼\n○ 농 가 로열티 부담 증가 : 로열티 지불추정액 (’08) 47.4억원\n○ 농 약비용 및 방제노동력 절감형 품종 및 절화수명 우수 품종 개발 시급", "classSubHtml": "A01090442.html", "classSubIdx": "268", "classSubMaster": "농업연구관 김원희 031)290-6151", "classSubMovieUrl": null, "classSubPdf": "A01090442.pdf", "classSubTitle": "병에 강하고 절화수명이 우수한 장미 신품종", "classSubUse": "Y", "regDate": "2010-04-20 09:15:55.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('238', '‘발아현미’ 가공용 적합품종 추천', '발아현미는 현미자체를 제품화한 식품으로서 무농약 친환경재배로 생산된 현
미만 원료로 사용하고 있는 실정이며, 발아현미용으로 적합하며 친환경재배 적
응성이 우수한 삼광벼, 설갱벼, 큰눈벼, 화선찰벼, 흑광벼 및 홍진주벼 등 6품종
을 선발하였으며, 특히 발아현미 가공적성과 기능성이 우수한 삼광벼, 큰눈벼
및 설갱벼를 2009년부터 발아현미용 원료곡 생산용으로 농가에 보급하고 있음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090642", "classSubContents": "발아현미는 현미자체를 제품화한 식품으로서 무농약 친환경재배로 생산된 현\n미만 원료로 사용하고 있는 실정이며, 발아현미용으로 적합하며 친환경재배 적\n응성이 우수한 삼광벼, 설갱벼, 큰눈벼, 화선찰벼, 흑광벼 및 홍진주벼 등 6품종\n을 선발하였으며, 특히 발아현미 가공적성과 기능성이 우수한 삼광벼, 큰눈벼\n및 설갱벼를 2009년부터 발아현미용 원료곡 생산용으로 농가에 보급하고 있음", "classSubContents2": "○ 쌀 수입개방 확대 및 국민식생활의 서구화로 인하여 1인당 쌀 소비량 감소추세임\n- (&#39;06) 78.8kg / 1인 → (&#39;07) 76.9 → (&#39;08) 75.8\n○ 최근 국민건강에 관심이 높아져 Well-being식품 요구증가에 따른 영양성\n및 기능성이 증대된 식품선호로 인하여 발아현미 제품의 난립예상\n○ 쌀을 밥용으로만 소비하지 않고 다양한 편의식품 개발로 고부가가치 창출필요\n○ 국내에서는 아직 발아현미의 품질기준 및 발아현미 전용품종 추천실적 없음\n○ 친환경재배에서도 안정적이면서 발아현미 가공적성과 품질 및 기능성이 우\n수한 품종을 선발하여 산업화를 목적으로 본 연구를 추진하였음", "classSubHtml": "A01090642.html", "classSubIdx": "238", "classSubMaster": "농업연구사 오세관 031-290-6722", "classSubMovieUrl": null, "classSubPdf": "A01090642.pdf", "classSubTitle": "‘발아현미’ 가공용 적합품종 추천", "classSubUse": "Y", "regDate": "2010-04-19 17:37:18.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('269', '에너지 절감형 망고 시설재배기술', '시 설 재배 망 고하우스에 온풍난방기로 시설온도를 10℃까지 보조가온 후
히트펌프를 이용하여 망고 생육온도(20～25℃)에 맞게 난방으로 온풍난방
기에 비하여 49%의 에너지를 절감 할 수 있는 기술 및 고품질 망고생산
을 위한 적과기술을 개발함', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090443", "classSubContents": "시 설 재배 망 고하우스에 온풍난방기로 시설온도를 10℃까지 보조가온 후\n히트펌프를 이용하여 망고 생육온도(20～25℃)에 맞게 난방으로 온풍난방\n기에 비하여 49%의 에너지를 절감 할 수 있는 기술 및 고품질 망고생산\n을 위한 적과기술을 개발함", "classSubContents2": "○ 국 민소득 증가 및 웰빙 소비 확대로 열대과일 수입량 및 열대과수 시설\n재배 면적 증가\n- 재배 면 적 : (’01) 30 → (’08) 52.5ha, 수입량 : (’03) 275 → (’08) 347천톤\n○ 망고 시설재배 경영 비중 시설난방비 55% 점유로 농가의 경영수지 악화 초래 및\n에너지 절감 시설재배기술 개발 시급\n- 망 고 시설재배 난방비 : 5,560천원/10a(경영비 10,165천원의 55%)", "classSubHtml": "A01090443.html", "classSubIdx": "269", "classSubMaster": "농업연구관 전승종 064)741-2550", "classSubMovieUrl": null, "classSubPdf": "A01090443.pdf", "classSubTitle": "에너지 절감형 망고 시설재배기술", "classSubUse": "Y", "regDate": "2010-04-20 09:17:44.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('239', '약배양과 여교잡 기술을 이용한 우량 벼 형질전환체 단기생산법', '벼 약배양기술을 이용하여 형질전환 당대에 유전적으로 고정된 개체들을
확보하고, 원품종과 여교잡을 통하여 형질전환체에 내포된 불량 체세포변이인
자를 제거, 36개월 이내에 우량 벼 형질전환계통을 확립하는 기법임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090643", "classSubContents": "벼 약배양기술을 이용하여 형질전환 당대에 유전적으로 고정된 개체들을\n확보하고, 원품종과 여교잡을 통하여 형질전환체에 내포된 불량 체세포변이인\n자를 제거, 36개월 이내에 우량 벼 형질전환계통을 확립하는 기법임", "classSubContents2": "○ 종&#8228;속간 교잡장벽 극복 및 도입대상 유전자위에 연관되어 있는 열악형\n질 들의 제거에 많은 시간과 노력이 요구되는 ‘교잡육종’에 비해 ‘형질전\n환’은 1) 하나의 유전자에만 연구를 집중할 수 있고, 2) 육성된 신기능성\n품종에 대한 지적소유권관리가 상대적으로 용이하여 형질전환작물 개발\n및 그 경제적 파급효과는 매년 가파르게 상승하고 있음\n○ 벼에 있어서도 1) 수량성증대, 2) 내병해충성 증강, 3) 불량환경에 대한\n적응력 제고, 4) 신기능성 물질생산 등에 형질전환기술을 활용하고자 하\n는 노력과 경쟁이 치열한 추세임\n○ 이배체인 종실캘러스로의 형질전환 당대(T0)에는 도입유전자들이 헤테로\n상태이므로 자가수정에 의해 작성된 분리세대(T1)에 대한 별도의 검정을\n통해서만 호모상태의 형질전환체들을 확보할 수 있음\n○ 유전적으로 고정된 형질전환체들의 표현형 발현은 도입된 외래유전자의\n수(copy number), 염색체상의 위치(positional effect), 그리고 조직배양과\n정에서 무작위로 유발된 체세포변이(somaclonal variation) 등에 의해 크\n게 달라질 수 있음\n○ 그러므로 도입된 유전자가 고정되어 건실히 발현되는 형질전환 후대계통\n이라 할지라도 원품종(wild type)의 작물학적 특성이 교란되어 상품성을\n상실하는 경우가 흔히 관찰되는데, 이를 극복하기 위해서는 방대한 규모\n의 형질전환체 육성과 다년간에 걸친 검증이 요구됨", "classSubHtml": "A01090643.html", "classSubIdx": "239", "classSubMaster": "농업연구사 정지웅 031-290-6728", "classSubMovieUrl": null, "classSubPdf": "A01090643.pdf", "classSubTitle": "약배양과 여교잡 기술을 이용한 우량 벼 형질전환체 단기생산법", "classSubUse": "Y", "regDate": "2010-04-19 17:38:31.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('270', '단동 비닐하우스용 다겹보온커튼 개폐 장치', '단동 비닐하우스는 2중이나 3중으로 비닐을 피복하여 보온하는 방식이 대부
분이므로 단동 비닐하우스용 다겹보온커튼을 설치하여 보온성을 40∼50%
향상시킴으로써 겨울철 작물 피해를 최소화하고 난방 에너지를 절감할
수 있음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090444", "classSubContents": "단동 비닐하우스는 2중이나 3중으로 비닐을 피복하여 보온하는 방식이 대부\n분이므로 단동 비닐하우스용 다겹보온커튼을 설치하여 보온성을 40∼50%\n향상시킴으로써 겨울철 작물 피해를 최소화하고 난방 에너지를 절감할\n수 있음", "classSubContents2": "○ 시 설원예 난방 면적의 증가로 유류 소비량 증가\n- 시 설면 적 : (’95) 43 → (’08) 53천ha, 난방면적 : (’95) 6.9 → (’08) 13천ha\n○ 경 영비 중 난방비 비중 증가로 농가 부담 가중 : 20∼30 → 30∼40%\n○ 단동 비닐하우스는 2중·3중 비닐 보온으로 연동 대비 보온성이 매우 낮음\n- 다 중비 닐 42%, 내부터널 37%, 외부보온 6%, 기타 15%\n○ 전 체 시설면적의 대부분을 차지하고 있는 단동 하우스의 보온성 향상으\n로 동절기 작물 피해 최소화 및 국가적인 차원의 난방에너지 절감 필요", "classSubHtml": "A01090444.html", "classSubIdx": "270", "classSubMaster": "이시영 농업연구사 051)602-2152", "classSubMovieUrl": null, "classSubPdf": "A01090444.pdf", "classSubTitle": "단동 비닐하우스용 다겹보온커튼 개폐 장치", "classSubUse": "Y", "regDate": "2010-04-20 09:18:36.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('240', '질병예방 및 치료용 고기능성 ‘토코트리에놀 합성 콩’ 개발', '기능성이 우수한 토코트리에놀 성분을 합성하는 콩을 개발하기위해 벼에서
분리한 토코트리에놀 합성 유전자(HGGT)를 콩에 도입하고 최적의 조건으로
발현시킴으로써 잎과 종자에서 토코트리에놀이 합성되는 콩을 개발하였음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090644", "classSubContents": "기능성이 우수한 토코트리에놀 성분을 합성하는 콩을 개발하기위해 벼에서\n분리한 토코트리에놀 합성 유전자(HGGT)를 콩에 도입하고 최적의 조건으로\n발현시킴으로써 잎과 종자에서 토코트리에놀이 합성되는 콩을 개발하였음", "classSubContents2": "○ 고령화 사회로의 진입과 소득수준의 향상으로 치료중심의 의료에서 예방\n중심의 의료로 전환되고 있으며, 이에 따라 고부가가치 식&#8228;의약 소재개발에\n대한 요구가 증가하고 있음\n- 생물의약 분야 : 688억달러(‘08)→1,155억달러(’13)\n- 바이오기능성 식품분야 : 75억달러(‘08)→126억달러(’13)\n* OECD 및 Consulting Resources Corporation 예측자료(2006)\n○ 전 세계 비타민 시장은 약 326천만불(1999년)로 추정되며, 그 중 비타민E\n는 판매량의 30%를 차지하고 있으며 성인의 약 10%가 매일 복용하고 있\n음.\n○ 비타민 E를 구성하는 물질인 토코트리에놀은 토코페롤보다 40～60배\n활성이 우수하며, 다양한 종류의 인체 기능 향상 효과를 나타내어 최\n근 각광받는 기능성 소재이나 기존 콩에는 합성되지 않는 성분임. 따\n라서 생명공학기술을 이용하여 토코트리에놀 성분이 합성되는 콩을 개발\n하고자함", "classSubHtml": "A01090644.html", "classSubIdx": "240", "classSubMaster": "농업연구사 김율호 031-290-6751", "classSubMovieUrl": null, "classSubPdf": "A01090644.pdf", "classSubTitle": "질병예방 및 치료용 고기능성 ‘토코트리에놀 합성 콩’ 개발", "classSubUse": "Y", "regDate": "2010-04-19 17:39:22.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('271', '현장진단용 박과작물 바이러스 진단키트 개발 및 보급', '개발 한 키트는 미세한 나노 크기(직경 40nm, 1nm는 10억분의 1m)의 금
입자에 특이적 항체를 부착하여 바이러스와 결합반응의 원리를 이용한
것으로 검정 대상 식물의 즙액에 진단키트를 담그면 2분내 2줄의 붉은 띠
형성 유무로 바이러스 감염 확인 가능하다. 고추 등 박과작물 CGMMV,
ZGMMV, KGMMV, CMV을 진단해낼 수 있는 키트가 보급되었다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090445", "classSubContents": "개발 한 키트는 미세한 나노 크기(직경 40nm, 1nm는 10억분의 1m)의 금\n입자에 특이적 항체를 부착하여 바이러스와 결합반응의 원리를 이용한\n것으로 검정 대상 식물의 즙액에 진단키트를 담그면 2분내 2줄의 붉은 띠\n형성 유무로 바이러스 감염 확인 가능하다. 고추 등 박과작물 CGMMV,\nZGMMV, KGMMV, CMV을 진단해낼 수 있는 키트가 보급되었다.", "classSubContents2": "○ 지구 온난화 등에 따른 생물다양성 변화로 식물 바이러스병 확산\n- (’9 0년 대) 800 → (’00년대) 1,000여종\n○ 원예 작물 바이러스병의 조기 예방대책 수립을 위해 현장 진단용 키트 개발\n및 활용 시급", "classSubHtml": "A01090445.html", "classSubIdx": "271", "classSubMaster": "농업연구관 최국선 031)290-6234", "classSubMovieUrl": null, "classSubPdf": "A01090445.pdf", "classSubTitle": "현장진단용 박과작물 바이러스 진단키트 개발 및 보급", "classSubUse": "Y", "regDate": "2010-04-20 09:19:50.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('241', '볏짚시용에 의한 간척지 토양유기물 및 입단화도 증대효과 구명', '볏짚의 사료화(곤포) 및 보릿짚의 소각화로 자원낭비와 논토양의 지력저하가 심
하므로 볏짚 등 유기물을 토양에 환원하여 토양탄소 축적 및 작물 안정생산에
기여하기 위한 것임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090645", "classSubContents": "볏짚의 사료화(곤포) 및 보릿짚의 소각화로 자원낭비와 논토양의 지력저하가 심\n하므로 볏짚 등 유기물을 토양에 환원하여 토양탄소 축적 및 작물 안정생산에\n기여하기 위한 것임", "classSubContents2": "1) 목적\n○ 구 간척지논에 대한 토양탄소 축적 평가자료 구축 및 쌀 생산성 구명\n○ 유기물 장기연용에 의한 간척지 토양의 물리&#8228;화학성 변동 자료 제공\n2) 필요성\n○ 하해혼성충적논에 대한 토양탄소 평가자료 부재\n- 기존의 일반논, 밭의 토양탄소 변동평가 자료는 적음\n- 간척지유래 논토양(226,746㏊)에 대한 토양탄소 자료는 미비한 실정임\n○ 유기물 장기연용에 의한 간척지 토양의 물리&#8228;화학성 변동 자료 필요\n- 간척지에서 유기물 장기연용에 의한 쌀수량 및 미질 변화 구명\n- 토양유기물 함량에 따른 연차별 간척지 토양의 특성 변화 제시", "classSubHtml": "A01090645.html", "classSubIdx": "241", "classSubMaster": "농업연구사 이장희 063-840-2265", "classSubMovieUrl": null, "classSubPdf": "A01090645.pdf", "classSubTitle": "볏짚시용에 의한 간척지 토양유기물 및 입단화도 증대효과 구명", "classSubUse": "Y", "regDate": "2010-04-19 17:40:49.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('272', '유비쿼터스(u-IT) 기반 무인 과수해충 감시시스템 구축', '개 발 한 무인 과수 해충 감시 시스템은 성페로몬트랩에 유인된 해충 이미
지를 컴퓨터로 판독하여 실시간 방제 유무를 결정하는 기술로 기존에 육
안 관찰에 의한 과수 해충 발생 예찰하던 방식을 IT와 BT 기술 이용하
여 무인 자동화하는 시스템임', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090446", "classSubContents": "개 발 한 무인 과수 해충 감시 시스템은 성페로몬트랩에 유인된 해충 이미\n지를 컴퓨터로 판독하여 실시간 방제 유무를 결정하는 기술로 기존에 육\n안 관찰에 의한 과수 해충 발생 예찰하던 방식을 IT와 BT 기술 이용하\n여 무인 자동화하는 시스템임", "classSubContents2": "○ 대부 분 과수 농업인은 경험에 의존하여 방제시기를 결정하고 약제를 살포\n○ 과 실 수출을 위해 복숭아심식나방, 복숭아순나방 등의 나방류에 대한 과\n학적인 예찰체계 구축과 방제 대책이 매우 중요\n○ 친 환경 농산물에 대한 소비자의 요구와 경쟁력 있는 안전농산물 생산을 위해\n과수 병&#8228;해충 종합관리시스템의 구축과 생산 현장 적용이 반드시 필요", "classSubHtml": "A01090446.html", "classSubIdx": "272", "classSubMaster": "농업연구관 이동혁 054)380-3170", "classSubMovieUrl": null, "classSubPdf": "A01090446.pdf", "classSubTitle": "유비쿼터스(u-IT) 기반 무인 과수해충 감시시스템 구축", "classSubUse": "Y", "regDate": "2010-04-20 09:20:49.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('242', '작물가해 노린재류 유인효과 증진용 페로몬트랩 개발', '콩 및 과실 가해 노린재의 종류는 4~6종으로 집합페로몬에 의한 노린재류
의 유인효과는 트랩종류에 따라 차이가 있으므로 노린재류의 행동특성을
고려한 트랩개발로 유인물에 의한 노린재류의 유인효과를 증진시킴', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090646", "classSubContents": "콩 및 과실 가해 노린재의 종류는 4~6종으로 집합페로몬에 의한 노린재류\n의 유인효과는 트랩종류에 따라 차이가 있으므로 노린재류의 행동특성을\n고려한 트랩개발로 유인물에 의한 노린재류의 유인효과를 증진시킴", "classSubContents2": "○ 노린재류에 의한 두류 및 과실의 수량감소 및 품질저하 피해 심각\n○ 작물가해 노린재류는 비행성이 뛰어난 그룹과 낮은 것으로 구분할 수\n있으며, 노린재류의 행동(비행)특성에 맞는 페로몬 트랩 개발 필요\n○ 먹이와 성충을 이용한 노린재의 화학적 통신작용 효과로 노린재류의 유\n인효과를 증진시키는 기술 개발", "classSubHtml": "A01090646.html", "classSubIdx": "242", "classSubMaster": "농업연구사 배순도 055-350-1272", "classSubMovieUrl": null, "classSubPdf": "A01090646.pdf", "classSubTitle": "작물가해 노린재류 유인효과 증진용 페로몬트랩 개발", "classSubUse": "Y", "regDate": "2010-04-19 17:41:38.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('273', '고압살수 나무껍질 제거로 배 월동해충 방제', '배 월동병해충을 고압살수기를 이용하여 나무껍질을 제거하여 배 월동해충
(깍지벌레류, 꼬마배나무이 등)을 살충제를 사용하지 않고 방제하는 기술이
며, 겨울철 전정직후부터 꼬마배나무이 월동성충이 이동하기 전에 수행한다.', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090447", "classSubContents": "배 월동병해충을 고압살수기를 이용하여 나무껍질을 제거하여 배 월동해충\n(깍지벌레류, 꼬마배나무이 등)을 살충제를 사용하지 않고 방제하는 기술이\n며, 겨울철 전정직후부터 꼬마배나무이 월동성충이 이동하기 전에 수행한다.", "classSubContents2": "○ 지 구 온난화 및 이상고온으로 인한 병해충 발생량 증가\n- 사과 , 배, 포도, 복숭아, 감귤 등 과수원 월동해충 증가\n⇒ 과 수 거 친껍질속, 낙엽, 눈 등에서 병해충 월동(월동 후 1차 전염원)\n- 노목 의 나무껍질 제거 작업 효율 낮음\n&#8228; 꺼 친 껍질 제거에 따른 수작업 의존 비율 : 95%(’08)\n○ 주요 식량 및 원예작물 이상 돌발 병해충 발생량 증가\n- 병 해충 초기밀도 억제로 생육기 대발생 위험 저하유도\n⇒ 주 요 재배작물 농약사용 억제 및 친환경 방제 시급", "classSubHtml": "A01090447.html", "classSubIdx": "273", "classSubMaster": "농업연구사 조영식 061)330-1582", "classSubMovieUrl": null, "classSubPdf": "A01090447.pdf", "classSubTitle": "고압살수 나무껍질 제거로 배 월동해충 방제", "classSubUse": "Y", "regDate": "2010-04-20 09:21:48.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('247', '새싹 보리를 이용한 건강 기능성 신소재 개발', '새싹보리로부터 항암, 미백, 항산화 효과가 뛰어난 폴리페놀성 생리활성 물질인
루테오린, 사포나린 등을 분리하고 추출물을 이용하여 천연비누, 미용팩,
천연화장품 등의 시제품을 개발하였음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090647", "classSubContents": "새싹보리로부터 항암, 미백, 항산화 효과가 뛰어난 폴리페놀성 생리활성 물질인\n루테오린, 사포나린 등을 분리하고 추출물을 이용하여 천연비누, 미용팩,\n천연화장품 등의 시제품을 개발하였음", "classSubContents2": "○ 보리는 쌀과 더불어 우리나라의 주곡작물 중의 하나였지만 근래에 들어\n생활수준의 향상과 식생활의 변화에 따라 국내 소비량이 급격히 감소되고\n있는 실정임\n○ 최근에는 웰빙추세에 따라 보리에 함유되어 있는 영양성분과 건강 기능성\n물질이 재조명되면서 건강기능성 식품으로 국민관심이 증가하고 있는\n추세이며 가축 사료용 등으로도 우수한 평가를 받고 있음\n○ 호주, 일본 등 외국에서는 일찍부터 “새싹보리”의 영양성과 건강기능성을\n인식하여 항산화 건강식품 개발하여 산업화하고 있음\n○ 국내 보리 소비량 감소에 따른 재고량 증가로 보리소비를 촉진할 수 있는\n신수요 창출과 농가소득 증대에 기여할 수 있는 녹색기술 개발이 시급한 실정임", "classSubHtml": "A01090647.html", "classSubIdx": "247", "classSubMaster": "농업연구사 장기창 055-350-1172", "classSubMovieUrl": null, "classSubPdf": "A01090647.pdf", "classSubTitle": "새싹 보리를 이용한 건강 기능성 신소재 개발", "classSubUse": "Y", "regDate": "2010-04-19 17:58:59.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('292', '안토시아닌 함유 당근 ‘보라매’', '당근은 주황색으로 베타 카로틴을 가장 많이 함유한 뿌리 채소로 알려져
있으나 안토시아닌과 베타 카로틴을 동시에 함유한 보라색 당근을 국내에서
개발하여 외국 수입품종에 의존하던 것을 수입 대체할 수 있고 소비자의 요
구를 충족할 수 있음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090448", "classSubContents": "당근은 주황색으로 베타 카로틴을 가장 많이 함유한 뿌리 채소로 알려져\n있으나 안토시아닌과 베타 카로틴을 동시에 함유한 보라색 당근을 국내에서\n개발하여 외국 수입품종에 의존하던 것을 수입 대체할 수 있고 소비자의 요\n구를 충족할 수 있음", "classSubContents2": "○ 당근을 채소개념에서 기능성 식품 개념을 소비자에 인식 필요\n○ 당근 수입품종 대체 및 다양한 당근 재배로 농가 부가가치 향상", "classSubHtml": "A01090448.html", "classSubIdx": "292", "classSubMaster": "농업연구사 권영석 033-330-1640", "classSubMovieUrl": null, "classSubPdf": "A01090448.pdf", "classSubTitle": "안토시아닌 함유 당근 ‘보라매’", "classSubUse": "Y", "regDate": "2010-04-21 13:50:02.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('248', '유색벼 이용 논모자이크 광고 홍보방법 개발', '유색벼를 이용한 논 모자이크 광고 홍보방법은 2007년 농촌진흥청 신소재
개발과에서 개발한 기술로 현재 특허등록 중이며 잎과 줄기의 색이 있는
자색벼, 황색벼 등을 이용하여 형상화된 도안을 시각화 하는 방법임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090648", "classSubContents": "유색벼를 이용한 논 모자이크 광고 홍보방법은 2007년 농촌진흥청 신소재\n개발과에서 개발한 기술로 현재 특허등록 중이며 잎과 줄기의 색이 있는\n자색벼, 황색벼 등을 이용하여 형상화된 도안을 시각화 하는 방법임", "classSubContents2": "○ WTO, FTA를 비롯한 농업분야의 개방화에 따라 우리 쌀에 대한 위기감이\n고조되고 있어 벼를 광고 홍보의 매체로 이용함으로서 국민들에게 벼를\n알리고 농업정서 함양을 고취할 필요가 있음\n○ 주요 도로와 철로변의 논을 활용하여 우리 쌀의 우수성과 우리 농업의 중요\n성 등과 같은 주요 정책의 핵심사항을 일반국민에게 간결하면서도 인상 깊\n게 홍보하기 위하여 개발되었음", "classSubHtml": "A01090648.html", "classSubIdx": "248", "classSubMaster": "농업연구사 정국현 055-350-1159", "classSubMovieUrl": null, "classSubPdf": "A01090648.pdf", "classSubTitle": "유색벼 이용 논모자이크 광고 홍보방법 개발", "classSubUse": "Y", "regDate": "2010-04-19 18:00:05.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('293', '전통방식에 의한 시래기 무 생산기술 체계 확립', '시래기 무는 전통식품으로서 섬유질 및 비타민 A 급원으로서 좋은 식품
이다. 시래기 무는 여러 가지 방법에 의해 생산 유통되고 있으나 전통적인
방법으로 시래기 무를 생산함으로서 식품적 가치 향상 및 새로운 신소득
창출로서 농가 부가 가치를 향상 할 수 있음', NULL, NULL, '{"classCode": "A010904", "className": "원예", "classSubCode": "A01090449", "classSubContents": "시래기 무는 전통식품으로서 섬유질 및 비타민 A 급원으로서 좋은 식품\n이다. 시래기 무는 여러 가지 방법에 의해 생산 유통되고 있으나 전통적인\n방법으로 시래기 무를 생산함으로서 식품적 가치 향상 및 새로운 신소득\n창출로서 농가 부가 가치를 향상 할 수 있음", "classSubContents2": "○ 전통 방식에 의한 시래기 무 생산기술 체계 확립\n○ 고품질 다수확 시래기 무 생산을 위한 및 건조 방법 기술 개발 필요", "classSubHtml": "A01090449.html", "classSubIdx": "293", "classSubMaster": "농업연구사 권영석 033-330-1640", "classSubMovieUrl": null, "classSubPdf": "A01090449.pdf", "classSubTitle": "전통방식에 의한 시래기 무 생산기술 체계 확립", "classSubUse": "Y", "regDate": "2010-04-21 13:51:31.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('249', '벼멸구의 벼 수액 섭식특성을 이용한 저항성 품종 판별', '본 기술은 감수성 벼품종에서는 벼멸구가 벼의 체관부 수액을 쉽게 빨아먹
을 수 있지만 저항성 벼품종에서는 거의 빨아먹지 못하는 섭식행동 특성을
이용하여 저항성 벼품종을 판별하는 방법임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090649", "classSubContents": "본 기술은 감수성 벼품종에서는 벼멸구가 벼의 체관부 수액을 쉽게 빨아먹\n을 수 있지만 저항성 벼품종에서는 거의 빨아먹지 못하는 섭식행동 특성을\n이용하여 저항성 벼품종을 판별하는 방법임", "classSubContents2": "○ 화학농약 사용량을 줄이면서 친환경적으로 벼멸구를 방제할 수 있는 경\n제적인 방법인 저항성 벼품종 개발이 필요함\n○ 벼멸구의 섭식과정에서 나타나는 섭식행동은 먹이식물인 벼에 대한 직\n접적인 반응으로 보다 정확한 저항성 벼품종 판별을 위한 기초자료로\n벼멸구의 섭식행동을 수치화할 수 있는 기술이 요구됨", "classSubHtml": "A01090649.html", "classSubIdx": "249", "classSubMaster": "농업연구사 서보윤 031-290-6792", "classSubMovieUrl": null, "classSubPdf": "A01090649.pdf", "classSubTitle": "벼멸구의 벼 수액 섭식특성을 이용한 저항성 품종 판별", "classSubUse": "Y", "regDate": "2010-04-19 18:00:59.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('250', '퉁퉁마디(함초)의 신문제 해충 퉁퉁마디뿔나방의 발생 및 피해 구명', '퉁퉁마디(함초) 재배지에 새로운 해충으로 퉁퉁마디뿔나방이 다발생하여
피해를 주기 때문에 이 해충의 형태, 발생 및 피해에 대한 정보 제공', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090650", "classSubContents": "퉁퉁마디(함초) 재배지에 새로운 해충으로 퉁퉁마디뿔나방이 다발생하여\n피해를 주기 때문에 이 해충의 형태, 발생 및 피해에 대한 정보 제공", "classSubContents2": "1) 목적\n○ 퉁퉁마디(함초) 재배지의 새로운 해충인 퉁퉁마디뿔나방의 형태, 발생 및\n피해에 대한 정보를 제공코자 함\n2) 필요성\n○ 최근 간척지에서 재배되는 퉁퉁마디(함초)가 신소득작물로 이용되고 있음\n○ 퉁퉁마디(함초) 재배지에서 발생되고 있는 신문제 해충인 퉁퉁마디뿔나방에\n대한 기본적인 형태, 발생 및 피해정보가 국내에는 없음", "classSubHtml": "A01090650.html", "classSubIdx": "250", "classSubMaster": "농업연구사 백채훈 063-840-2293", "classSubMovieUrl": null, "classSubPdf": "A01090650.pdf", "classSubTitle": "퉁퉁마디(함초)의 신문제 해충 퉁퉁마디뿔나방의 발생 및 피해 구명", "classSubUse": "Y", "regDate": "2010-04-19 18:02:14.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('251', '벼 줄무늬잎마름병(RSV) 보독충률 진단을 위한 다중유전자(duplex RT-PCR) 진단방법', '애멸구 보독충률 진단 시 사용되는 VC/RT-PCR이나 RT-PCR 반응에, 벼
줄무늬잎마름병 검출 특이 프라이머와 애멸구 양성 반응 대조용 프라이
머 (internal positive control primer)를 함께 사용하여 PCR 반응의 정확
성을 높여, 보다 정밀한 보독충률을 검정할 수 있음', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090651", "classSubContents": "애멸구 보독충률 진단 시 사용되는 VC/RT-PCR이나 RT-PCR 반응에, 벼\n줄무늬잎마름병 검출 특이 프라이머와 애멸구 양성 반응 대조용 프라이\n머 (internal positive control primer)를 함께 사용하여 PCR 반응의 정확\n성을 높여, 보다 정밀한 보독충률을 검정할 수 있음", "classSubContents2": "1) 목적\n○ 벼 줄무늬잎마름병을 매개하는 애멸구에서 벼 줄무늬잎마름병 보독충률\n을 정밀하게 확인하기 위함\n2) 필요성\n○ 벼 줄무늬잎마름병은 애멸구가 매개하는 벼 바이러스 병으로 애멸구에서\n바이러스 보독충률을 조사하여 병 방제의 기본 자료로 이용\n○ 애멸구의 보독충률은 주로 RT-PCR 이나 VC/RT-PCR방법으로 조사하게 되며,\nVC/RT-PCR법이 간편하여 이용하기 용이하나, 애멸구 시료의 특성상 바이\n러스 농도가 낮아 VC/RT-PCR반응에서 양성 결과가 누락되기도 함", "classSubHtml": "A01090651.html", "classSubIdx": "251", "classSubMaster": "농업연구사 강미형 063-840-2228", "classSubMovieUrl": null, "classSubPdf": "A01090651.pdf", "classSubTitle": "벼 줄무늬잎마름병(RSV) 보독충률 진단을 위한 다중유전자(duplex RT-PCR) 진단방법", "classSubUse": "Y", "regDate": "2010-04-19 18:03:44.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('254', '칩 가공용 가을감자 ‘고운’의 최적 시비기술', '칩 가공용 가을감자 ‘고운’은 잎줄기의 생리활성, 괴경품질, 칩가공성을
고려할 때 토양검정에 의한 적정시비를 하는 것이 바람직하며, 토양검정
시비는 질소, 인산, 칼륨을 복합비료나 단비의 형태로 기준시비량의 최대
50%까지 감량시비 함', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090654", "classSubContents": "칩 가공용 가을감자 ‘고운’은 잎줄기의 생리활성, 괴경품질, 칩가공성을\n고려할 때 토양검정에 의한 적정시비를 하는 것이 바람직하며, 토양검정\n시비는 질소, 인산, 칼륨을 복합비료나 단비의 형태로 기준시비량의 최대\n50%까지 감량시비 함", "classSubContents2": "○ 우리나라에서 칩 가공용 감자로는 도입 육종된 ‘대서’(Atlantic) 품종이\n이용되고 있는데, 이 품종은 괴경내부생리장해에 민감하여 주로 중남부\n평난지의 봄 재배에서 이용되고 있음\n○ 봄 재배에서 수확한 ‘대서’ 품종은 일부를 저장하여 가을까지 이용하고\n있으나 저장에 따른 품질저하, 원료감자부족에 따라 가을재배 칩가공용\n감자의 품종 개발과 재배기술이 꾸준히 요구되어 왔음\n○ 농촌진흥청 국립식량과학원(고령지농업연구센터)에서는 2006년 칩 가공용\n가을감자로서 ‘고운’ 품종을 육성하였고 칩가공회사에서도 ‘고운’ 품종\n의 산업화를 위한 재배기술의 조기 보급을 요청하고 있는 실정임", "classSubHtml": "A01090654.html", "classSubIdx": "254", "classSubMaster": "농업연구사 장동칠 033-330-1622", "classSubMovieUrl": null, "classSubPdf": "A01090654.pdf", "classSubTitle": "칩 가공용 가을감자 ‘고운’의 최적 시비기술", "classSubUse": "Y", "regDate": "2010-04-19 18:06:47.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('255', '쓴메밀 품종육성 및 식품소재 산업화', '기존 보통메밀에 비해 루틴함량이 매우 높아 약리효과가 뛰어난 쓴메밀 품
종 ‘약선(계통명 : 대관3-3호)을 육성하였음. 숙기가 짧아 대부분 지역에서 1
년에 2번 재배가 가능하고 보통메밀과 달리 자식성으로 수량이 높고 안정적
인 재배가 가능한 품종임. 또한 쓴메밀의 기능성을 활용한 다양한 식품소
재 개발을 통해 메밀의 산업화를 추진중임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090655", "classSubContents": "기존 보통메밀에 비해 루틴함량이 매우 높아 약리효과가 뛰어난 쓴메밀 품\n종 ‘약선(계통명 : 대관3-3호)을 육성하였음. 숙기가 짧아 대부분 지역에서 1\n년에 2번 재배가 가능하고 보통메밀과 달리 자식성으로 수량이 높고 안정적\n인 재배가 가능한 품종임. 또한 쓴메밀의 기능성을 활용한 다양한 식품소\n재 개발을 통해 메밀의 산업화를 추진중임", "classSubContents2": "○ 새로운 기능성 소재로 ‘쓴메밀’ 품종 국산화 필요\n○ 메밀 소비 확대를 위한 식품소재 개발 시급\n- 국내 메밀시장규모 1천억 : 95% 이상 단순가공제품(가루, 국수)", "classSubHtml": "A01090655.html", "classSubIdx": "255", "classSubMaster": "농업연구관 윤영호 033-330-1840", "classSubMovieUrl": null, "classSubPdf": "A01090655.pdf", "classSubTitle": "쓴메밀 품종육성 및 식품소재 산업화", "classSubUse": "Y", "regDate": "2010-04-19 18:07:36.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
INSERT INTO nongsaro_advanced_tech (cntnts_no, title, content, image_url, video_url, raw_data) VALUES ('294', '돈분뇨 퇴&#8228;액비 이용 벼 안정재배 기술 확립', '화학비료 가격 상승에 따른 퇴&#8228;액비 활용 농가 급증하고 새로 개발된 SCB액비와 제조과정중 생산
되는 퇴비에 대하여 논에서 활용기술이 개발되지 않아 경종농가가 벼 안정재배를 위해 필요한 기
술임', NULL, NULL, '{"classCode": "A010906", "className": "작물", "classSubCode": "A01090656", "classSubContents": "화학비료 가격 상승에 따른 퇴&#8228;액비 활용 농가 급증하고 새로 개발된 SCB액비와 제조과정중 생산\n되는 퇴비에 대하여 논에서 활용기술이 개발되지 않아 경종농가가 벼 안정재배를 위해 필요한 기\n술임", "classSubContents2": "1) 목적\n   ○  돈분퇴비와 저농도액비(SCB) 이용 자원순환형 벼 재배 안정 방법 구명\n\n2) 필요성\n   ○ SCB 공법 이용 양돈 슬러리 처리방법 확대보급 : (’07)172→(’10)210개소\n   ○ 가축분뇨 액비는 밑거름과 웃거름으로 활용하여 화학비료 전량 대체기술 개발이 필요\n   ○ 농경지 볏짚 사료화에 대비 가축분뇨 퇴&#8228;액비 이용 기술 필요", "classSubHtml": "A01090656.html", "classSubIdx": "294", "classSubMaster": "농업연구관 이상복 063-840-2268", "classSubMovieUrl": null, "classSubPdf": "A01090656.pdf", "classSubTitle": "돈분뇨 퇴&#8228;액비 이용 벼 안정재배 기술 확립", "classSubUse": "Y", "regDate": "2010-04-22 09:53:21.0"}'::jsonb) ON CONFLICT (cntnts_no) DO NOTHING;
